-- Poems batch 472
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-81','長安感興','鄭穀','唐','御定全唐诗','yuding','','[]','徒勞悲喪亂，自古戒繁華。落日狐兔徑，近年公相家。',48,'御定全唐詩/json/674.json','["徒勞悲喪亂，自古戒繁華。落日狐兔徑，近年公相家。", "可悲聞玉笛，不見走香車。寂寞牆匡裏，春陰挫杏花。"]'),
('yuding-82','聞所知游樊川有寄','鄭穀','唐','御定全唐诗','yuding','','[]','誰無泉石趣，朝下少同過。貪勝覺程近，愛閑經宿多。',48,'御定全唐詩/json/674.json','["誰無泉石趣，朝下少同過。貪勝覺程近，愛閑經宿多。", "片沙留白鳥，高木引青蘿。醉把漁竿去，殷勤藉岸莎。"]'),
('yuding-83','張谷田舍','鄭谷','唐','御定全唐诗','yuding','','[]','縣官清且儉，深谷有人家。一徑入寒竹，小橋穿野花。',48,'御定全唐詩/json/674.json','["縣官清且儉，深谷有人家。一徑入寒竹，小橋穿野花。", "碓喧春澗滿，梯倚綠桑斜。自說年來稔，前村酒可賒。"]'),
('yuding-84','深居','鄭穀','唐','御定全唐诗','yuding','','[]','吾道有誰同，深居自固窮。殷勤謝綠樹，朝夕惠清風。',48,'御定全唐詩/json/674.json','["吾道有誰同，深居自固窮。殷勤謝綠樹，朝夕惠清風。", "書滿閑窗下，琴橫野艇中。年來頭更白，雅稱釣魚翁。"]'),
('yuding-85','端居','鄭谷','唐','御定全唐诗','yuding','','[]','葉葉下高梧，端居失所圖。亂離時輩少，風月夜吟孤。',48,'御定全唐詩/json/674.json','["葉葉下高梧，端居失所圖。亂離時輩少，風月夜吟孤。", "舊疾衰還有，窮愁醉暫無。秋光如水國，不語理霜須。"]'),
('yuding-86','郊園','鄭穀','唐','御定全唐诗','yuding','','[]','相近複相尋，山僧與水禽。煙蓑春釣靜，雪屋夜棋深。',48,'御定全唐詩/json/674.json','["相近複相尋，山僧與水禽。煙蓑春釣靜，雪屋夜棋深。", "雅道誰開口，時風未醒心。溪光何以報，只有醉和吟。"]'),
('yuding-87','郊野','鄭谷','唐','御定全唐诗','yuding','','[]','蓼水菊籬邊，新晴有亂蟬。秋光終寂寞，晚醉自留連。',48,'御定全唐詩/json/674.json','["蓼水菊籬邊，新晴有亂蟬。秋光終寂寞，晚醉自留連。", "野濕禾中露，村閑社後天。題詩滿紅葉，何必浣花箋。"]'),
('yuding-88','旅寓洛南村舍','鄭谷','唐','御定全唐诗','yuding','','[]','村落清明近，秋千稚女誇。春陰妨柳絮，月黑見梨花。',48,'御定全唐詩/json/674.json','["村落清明近，秋千稚女誇。春陰妨柳絮，月黑見梨花。", "白鳥窺魚網，青簾認酒家。幽棲雖自適，交友在京華。"]'),
('yuding-89','杏花','鄭穀','唐','御定全唐诗','yuding','','[]','不學梅欺雪，輕紅照碧池。小桃新謝後，雙燕卻來時。',48,'御定全唐詩/json/674.json','["不學梅欺雪，輕紅照碧池。小桃新謝後，雙燕卻來時。", "香屬登龍客，煙籠宿蝶枝。臨軒須貌取，風雨易離披。"]'),
('yuding-90','水林檎花','鄭穀','唐','御定全唐诗','yuding','','[]','一露一朝新，簾櫳曉景分。豔和蜂蝶動，香帶管弦聞。',48,'御定全唐詩/json/674.json','["一露一朝新，簾櫳曉景分。豔和蜂蝶動，香帶管弦聞。", "笑擬春無力，妝濃酒漸醺。直疑風起夜，飛去替行雲。"]'),
('yuding-91','蓼花','鄭穀','唐','御定全唐诗','yuding','','[]','蔟蔟複悠悠，年年拂漫流。差池伴黃菊，冷淡過清秋。',48,'御定全唐詩/json/674.json','["蔟蔟複悠悠，年年拂漫流。差池伴黃菊，冷淡過清秋。", "晚帶鳴蟲急，寒藏宿鷺愁。故溪歸不得，憑仗系漁舟。"]'),
('yuding-92','江梅','鄭谷','唐','御定全唐诗','yuding','','[]','江梅且緩飛，前輩有歌詞。莫惜黃金縷，難忘白雪枝。',48,'御定全唐詩/json/674.json','["江梅且緩飛，前輩有歌詞。莫惜黃金縷，難忘白雪枝。", "吟看歸不得，醉嗅立如癡。和雨和煙折，含情寄所思。"]'),
('yuding-93','荔枝','鄭谷','唐','御定全唐诗','yuding','','[]','平昔誰相愛，驪山遇貴妃。枉教生處遠，愁見摘來稀。',48,'御定全唐詩/json/674.json','["平昔誰相愛，驪山遇貴妃。枉教生處遠，愁見摘來稀。", "晚奪紅霞色，晴欺瘴日威。南荒何所戀，為爾即忘歸。"]'),
('yuding-94','駐蹕華下同年司封員外從翁許共遊西溪久違前契戲成寄贈','鄭穀','唐','御定全唐诗','yuding','','[]','北渚牽吟興，西溪爽共遊。指期乘禁馬，無暇狎沙鷗。',48,'御定全唐詩/json/674.json','["北渚牽吟興，西溪爽共遊。指期乘禁馬，無暇狎沙鷗。", "縱目懷青島，澄心想碧流。明公非不愛，應待泛龍舟。"]'),
('yuding-95','穀自亂離之後在西蜀半紀之餘多寓止精舍…四韻以吊之','鄭穀','唐','御定全唐诗','yuding','','[]','每思聞淨話，雨夜對禪床。未得重相見，秋燈照影堂。',48,'御定全唐詩/json/674.json','["每思聞淨話，雨夜對禪床。未得重相見，秋燈照影堂。", "孤雲終負約，薄宦轉堪傷。夢繞長松塔，遙焚一炷香。"]'),
('yuding-96','投時相十韻','鄭穀','唐','御定全唐诗','yuding','','[]','何以保孤危，操修自不知。眾中常杜口，夢裏亦吟詩。',120,'御定全唐詩/json/674.json','["何以保孤危，操修自不知。眾中常杜口，夢裏亦吟詩。", "失計辭山早，非才得仕遲。薄冰安可履，暗室豈能欺。", "勤苦流螢信，籲嗟宿燕知。殘鐘殘漏曉，落葉落花時。", "故舊寒門少，文章外族衰。此生多轗軻，半世足漂離。", "省署隨清品，漁舟爽素期。戀恩休未遂，雙鬢漸成絲。"]'),
('yuding-0','喜秀上人相訪','鄭谷','唐','御定全唐诗','yuding','','[]','雪初開一徑，師忽扣雙扉。老大情相近，林泉約共歸。',48,'御定全唐詩/json/675.json','["雪初開一徑，師忽扣雙扉。老大情相近，林泉約共歸。", "憂榮棲省署，孤僻謝朝衣。他夜松堂宿，論詩更入微。"]'),
('yuding-1','夕陽','鄭穀','唐','御定全唐诗','yuding','','[]','夕陽秋更好，斂斂蕙蘭中。極浦明殘雨，長天急遠鴻。',48,'御定全唐詩/json/675.json','["夕陽秋更好，斂斂蕙蘭中。極浦明殘雨，長天急遠鴻。", "僧窗留半榻，漁舸透疏篷。莫恨清光盡，寒蟾即照空。"]'),
('yuding-2','搖落','鄭穀','唐','御定全唐诗','yuding','','[]','夜來搖落悲，桑棗半空枝。故國無消息，流年有亂離。',48,'御定全唐詩/json/675.json','["夜來搖落悲，桑棗半空枝。故國無消息，流年有亂離。", "霜秦聞雁早，煙渭認帆遲。日暮寒鼙急，邊軍在雍岐。"]'),
('yuding-3','西蜀淨眾寺松溪八韻兼寄小筆崔處士','鄭穀','唐','御定全唐诗','yuding','','[]','松因溪得名，溪吹答松聲。繚繞能穿寺，幽奇不在城。',96,'御定全唐詩/json/675.json','["松因溪得名，溪吹答松聲。繚繞能穿寺，幽奇不在城。", "寒煙齋後散，春雨夜中平。染岸蒼苔古，翹沙白鳥明。", "澄分僧影瘦，光徹客心清。帶梵侵雲響，和鐘擊石鳴。", "淡烹新茗爽，暖泛落花輕。此景吟難盡，憑君畫入京。"]'),
('yuding-4','遷客','鄭穀','唐','御定全唐诗','yuding','','[]','離夜聞橫笛，可堪吹鷓鴣。雪冤知早晚，雨泣渡江湖。',48,'御定全唐詩/json/675.json','["離夜聞橫笛，可堪吹鷓鴣。雪冤知早晚，雨泣渡江湖。", "秋樹吹黃葉，臘煙垂綠蕪。虞翻歸有日，莫便哭窮途。"]'),
('yuding-5','蔡處士','鄭穀','唐','御定全唐诗','yuding','','[]','無著複無求，平生不解愁。鬻蔬貧潔淨，中酒病風流。',48,'御定全唐詩/json/675.json','["無著複無求，平生不解愁。鬻蔬貧潔淨，中酒病風流。", "旨趣陶山相，詩篇沈隱侯。小齋江色裏，籬柱系漁舟。"]'),
('yuding-6','予嘗有雪景一絕為人所諷吟段贊善小筆精微…詩謝之','鄭穀','唐','御定全唐诗','yuding','','[]','贊善賢相後，家藏名畫多。留心於繪素，得事在煙波。',48,'御定全唐詩/json/675.json','["贊善賢相後，家藏名畫多。留心於繪素，得事在煙波。", "屬興同吟詠，成功更琢磨。愛予風雪句，幽絕寫漁蓑。"]'),
('yuding-7','京兆府試殘月如新月','鄭谷','唐','御定全唐诗','yuding','','[]','榮落何相似，初終卻一般。猶疑和夕照，誰信墮朝寒。',72,'御定全唐詩/json/675.json','["榮落何相似，初終卻一般。猶疑和夕照，誰信墮朝寒。", "水木輝華別，詩家比象難。佳人應誤拜，棲鳥反求安。", "屈指期輪滿，何心謂影殘。庾樓清賞處，吟徹曙鐘看。"]'),
('yuding-8','咸通十四年府試木向榮','鄭谷','唐','御定全唐诗','yuding','','[]','園林青氣動，眾木散寒聲。敗葉牆陰在，滋條雪後榮。',72,'御定全唐詩/json/675.json','["園林青氣動，眾木散寒聲。敗葉牆陰在，滋條雪後榮。", "欣欣春令早，藹藹日華輕。庾嶺梅先覺，隋堤柳暗驚。", "山川應物候，皋壤起農情。只待花開日，連棲出穀鶯。"]'),
('yuding-9','丞相孟夏祗薦南郊紀獻十韻','鄭谷','唐','御定全唐诗','yuding','','[]','節應清和候，郊宮事潔羞。至誠聞上帝，明德祀圓丘。',120,'御定全唐詩/json/675.json','["節應清和候，郊宮事潔羞。至誠聞上帝，明德祀圓丘。", "雅用陶匏器，馨非黍稷流。就陽陳盛禮，匡國禱鴻休。", "漸曉蘭迎露，微涼麥弄秋。壽山橫紫閣，瑞靄抱皇州。", "外肅通班序，中嚴錫慶優。奏歌三酒備，表敬百神柔。", "池碧將還鳳，原清再問牛。萬方瞻輔翼，共賀贊皇猷。"]'),
('yuding-10','敘事感恩上狄右丞','鄭穀','唐','御定全唐诗','yuding','','[]','昔歲曾投贄，關河在左馮。庾公垂顧遇，王粲許從容。',168,'御定全唐詩/json/675.json','["昔歲曾投贄，關河在左馮。庾公垂顧遇，王粲許從容。", "首薦叨殊禮，全家寓近封。白樓陪寫望，青眼感遭逢。", "顧念梁間燕，深憐澗底松。嵐光蓮嶽逼，酒味菊花濃。", "寇難旋移國，漂離幾聽蛩。半生悲逆旅，二紀間門墉。", "蜀雪隨僧蹋，荊煙逐雁沖。凋零歸兩鬢，舉止失前蹤。", "得事雖甘晚，陳詩未肯慵。邇來趨九仞，又伴賞三峰。", "棲托情何限，吹噓意數重。自茲儔侶內，無複歎龍鍾。"]'),
('yuding-11','詠懷','鄭穀','唐','御定全唐诗','yuding','','[]','迂疏雖可欺，心路甚男兒。薄宦渾無味，平生粗有詩。',120,'御定全唐詩/json/675.json','["迂疏雖可欺，心路甚男兒。薄宦渾無味，平生粗有詩。", "淡交終不破，孤達晚相宜。直夜花前喚，朝寒雪裏追。", "竹聲輸我聽，茶格共僧知。景物還多感，情懷偶不卑。", "溪鶯喧午寢，山蕨止春饑。險事銷腸酒，清歡敵手棋。", "香鋤拋藥圃，煙艇憶莎陂。自許亨途在，儒綱複振時。"]'),
('yuding-12','幹符丙申歲奉試春漲曲江池','鄭谷','唐','御定全唐诗','yuding','','[]','王澤尚通津，恩波此日新。深疑一夜雨，宛似五湖春。',72,'御定全唐詩/json/675.json','["王澤尚通津，恩波此日新。深疑一夜雨，宛似五湖春。", "泛灩翹振鷺，澄清躍紫鱗。翠低孤嶼柳，香失半汀蘋。", "鳳輦尋佳境，龍舟命近臣。桂花如入手，願作從遊人。"]'),
('yuding-13','華山','鄭穀','唐','御定全唐诗','yuding','','[]','峭仞聳巍巍，晴嵐染近畿。孤高不可狀，圖寫盡應非。',144,'御定全唐詩/json/675.json','["峭仞聳巍巍，晴嵐染近畿。孤高不可狀，圖寫盡應非。", "絕頂神仙會，半空鸞鶴歸。雲台分遠靄，樹穀隱斜暉。", "墜石連村響，狂雷發廟威。氣中寒渭闊，影外白樓微。", "雲對蓮花落，泉橫露掌飛。乳懸危磴滑，樵徹上方稀。", "淡泊生真趣，逍遙息世機。野花明澗路，春蘚澀松圍。", "遠洞時聞磬，群僧晝掩扉。他年洗塵骨，香火願相依。"]'),
('yuding-14','入閣','鄭谷','唐','御定全唐诗','yuding','','[]','秘殿臨軒日，和鑾返正年。兩班文武盛，百辟羽儀全。',120,'御定全唐詩/json/675.json','["秘殿臨軒日，和鑾返正年。兩班文武盛，百辟羽儀全。", "霜漏清中禁，風旗拂曙天。門嚴新勘契，仗入乍承宣。", "玉幾當紅旭，金爐縱碧煙。對揚稱法吏，贊引出宮鈿。", "言動揮毫疾，雍容執簿專。壽山晴靉靆，顥氣暖連延。", "禮有鴛鸞集，恩無雨露偏。小臣叨備位，歌詠泰階前。"]'),
('yuding-15','故少師從翁隱岩別墅亂後榛蕪感舊愴懷遂有追紀','鄭穀','唐','御定全唐诗','yuding','','[]','風騷為主人，凡俗仰清塵。密行稱閨閫，明誠動搢紳。',240,'御定全唐詩/json/675.json','["風騷為主人，凡俗仰清塵。密行稱閨閫，明誠動搢紳。", "周旋居顯重，內外掌絲綸。妙主蓬壺籍，忠為社稷臣。", "大儀牆仞峻，東轄紀綱新。聞善常開口，推公豈為身。", "立朝鳴佩重，歸宅典衣貧。半醉看花晚，中餐煮菜春。", "晴台隨鹿上，幽墅結僧鄰。理論知清越，生徒得李頻。", "藥香沾筆硯，竹色染衣巾。寄鶴眠雲叟，騎驢入室賓。", "近將姚監比，僻與段卿親。葉積池邊路，茶遲雪後薪。", "所難留著述，誰不秉陶鈞。喪亂時多變，追思事已陳。", "浮華重發作，雅正甚湮淪。宗從今何在，依棲素有因。", "七松無影響，雙淚益悲辛。猶喜於門秀，年來屈複伸。"]'),
('yuding-16','送吏部曹郎中免官南歸','鄭谷','唐','御定全唐诗','yuding','','[]','高名向己求，古韻古無儔。風月拋蘭省，江山複桂州。',240,'御定全唐詩/json/675.json','["高名向己求，古韻古無儔。風月拋蘭省，江山複桂州。", "賢人知止足，中歲便歸休。雲鶴深相待，公卿不易留。", "滿朝張祖席，半路上仙舟。篋重藏吳畫，茶新換越甌。", "郡迎紅燭宴，寺宿翠嵐樓。觸目成幽興，全家是勝遊。", "篷聲漁叟雨，葦色鷺鷥秋。久別郊園改，將歸裏巷修。", "桑麻勝祿食，節序免鄉愁。陽朔花迎棹，崇賢葉滿溝。", "席春歡促膝，簷日暖梳頭。道暢應為蝶，時來必問牛。", "終須康庶品，未爽漱寒流。議在歸群望，情難戀自由。", "小生誠淺拙，早歲便依投。夏課每垂獎，雪天常見憂。", "遠招陪宿直，首薦向公侯。攀送偏揮灑，龍鍾志未酬。"]'),
('yuding-17','回鑾','鄭穀','唐','御定全唐诗','yuding','','[]','妖星沈雨露，和氣滿京關。上將忠勳立，明君法駕還。',96,'御定全唐詩/json/675.json','["妖星沈雨露，和氣滿京關。上將忠勳立，明君法駕還。", "順風調雅樂，夾道序群班。香泛傳宣裏，塵清指顧間。", "樓臺新紫氣，雲物舊黃山。曉渭行朝肅，秋郊曠望閑。", "廟靈安國步，日角動天顏。浩浩升平曲，流歌徹百蠻。"]'),
('yuding-18','峽中','鄭谷','唐','御定全唐诗','yuding','','[]','萬重煙靄裏，隱隱見夔州。夜靜明月峽，春寒堆雪樓。',48,'御定全唐詩/json/675.json','["萬重煙靄裏，隱隱見夔州。夜靜明月峽，春寒堆雪樓。", "獨吟誰會解，多病自淹留。往事如今日，聊同子美愁。"]'),
('yuding-19','蜀中寓止夏日自貽','鄭穀','唐','御定全唐诗','yuding','','[]','輾轉欹孤枕，風幃信寂寥。漲江垂螮蝀，驟雨鬧芭蕉。',48,'御定全唐詩/json/675.json','["輾轉欹孤枕，風幃信寂寥。漲江垂螮蝀，驟雨鬧芭蕉。", "道阻歸期晚，年加記性銷。故人衰颯盡，相望在行朝。"]'),
('yuding-20','試筆偶書','鄭谷','唐','御定全唐诗','yuding','','[]','沙鳥與山麋，由來性不羈。可憑唯在道，難解莫過詩。',96,'御定全唐詩/json/675.json','["沙鳥與山麋，由來性不羈。可憑唯在道，難解莫過詩。", "任笑孤吟僻，終嫌巧宦卑。乖慵恩地恕，冷淡好僧知。", "華省慚公器，滄江負釣師。露花春直夜，煙鼓早朝時。", "世路多艱梗，家風免墜遺。殷勤一蓑雨，只得夢中披。"]'),
('yuding-21','奔避','鄭穀','唐','御定全唐诗','yuding','','[]','奔避投人遠，漂離易感恩。愁髯霜颯颯，病眼淚昏昏。',48,'御定全唐詩/json/675.json','["奔避投人遠，漂離易感恩。愁髯霜颯颯，病眼淚昏昏。", "孤館秋聲樹，寒江落照村。更聞歸路絕，新寨截荊門。"]'),
('yuding-22','吊水部賈員外嵩','鄭穀','唐','御定全唐诗','yuding','','[]','八韻與五字，俱為時所先。幽魂應自慰，李白墓相連。',24,'御定全唐詩/json/675.json','["八韻與五字，俱為時所先。幽魂應自慰，李白墓相連。"]'),
('yuding-23','貧女吟','鄭穀','唐','御定全唐诗','yuding','','[]','塵壓鴛鴦廢錦機，滿頭空插麗春枝。',32,'御定全唐詩/json/675.json','["塵壓鴛鴦廢錦機，滿頭空插麗春枝。", "東鄰舞妓多金翠，笑剪燈花學畫眉。"]'),
('yuding-24','席上貽歌者','鄭穀','唐','御定全唐诗','yuding','','[]','花月樓臺近九衢，清歌一曲倒金壺。',32,'御定全唐詩/json/675.json','["花月樓臺近九衢，清歌一曲倒金壺。", "座中亦有江南客，莫向春風唱鷓鴣。"]'),
('yuding-25','菊','鄭谷','唐','御定全唐诗','yuding','','[]','王孫莫把比荊蒿，九日枝枝近鬢毛。',32,'御定全唐詩/json/675.json','["王孫莫把比荊蒿，九日枝枝近鬢毛。", "露濕秋香滿池岸，由來不羨瓦松高。"]'),
('yuding-26','下峽','鄭穀','唐','御定全唐诗','yuding','','[]','憶子啼猿繞樹哀，雨隨孤棹過陽臺。',32,'御定全唐詩/json/675.json','["憶子啼猿繞樹哀，雨隨孤棹過陽臺。", "波頭未白人頭白，瞥見春風灩澦堆。"]'),
('yuding-27','文昌寓直','鄭谷','唐','御定全唐诗','yuding','','[]','何遜空階夜雨平，朝來交直雨新晴。',32,'御定全唐詩/json/675.json','["何遜空階夜雨平，朝來交直雨新晴。", "落花亂上花磚上，不忍和苔蹋紫英。"]'),
('yuding-28','街西晚歸','鄭穀','唐','御定全唐诗','yuding','','[]','禦溝春水繞閑坊，信馬歸來傍短牆。',32,'御定全唐詩/json/675.json','["禦溝春水繞閑坊，信馬歸來傍短牆。", "幽榭名園臨紫陌，晚風時帶牡丹香。"]'),
('yuding-29','十日菊','鄭穀','唐','御定全唐诗','yuding','','[]','節去蜂愁蝶不知，曉庭還繞折殘枝。',32,'御定全唐詩/json/675.json','["節去蜂愁蝶不知，曉庭還繞折殘枝。", "自緣今日人心別，未必秋香一夜衰。"]'),
('yuding-30','鷺鷥','鄭谷','唐','御定全唐诗','yuding','','[]','閑立春塘煙淡淡，靜眠寒葦雨颼颼。',32,'御定全唐詩/json/675.json','["閑立春塘煙淡淡，靜眠寒葦雨颼颼。", "漁翁歸後汀沙晚，飛下灘頭更自由。"]'),
('yuding-31','柳','鄭穀','唐','御定全唐诗','yuding','','[]','半煙半雨江橋畔，映杏映桃山路中。',32,'御定全唐詩/json/675.json','["半煙半雨江橋畔，映杏映桃山路中。", "會得離人無限意，千絲萬絮惹春風。"]'),
('yuding-32','下第退居二首','鄭穀','唐','御定全唐诗','yuding','','[]','年來還未上丹梯，且著漁蓑謝故溪。',64,'御定全唐詩/json/675.json','["年來還未上丹梯，且著漁蓑謝故溪。", "落盡梨花春又了，破籬殘雨晚鶯啼。", "未嘗青杏出長安，豪士應疑怕牡丹。", "只有退耕耕不得，茫然村落水吹殘。"]'),
('yuding-33','江宿聞蘆管','鄭谷','唐','御定全唐诗','yuding','','[]','塞曲淒清楚水濱，聲聲吹出落梅春。',32,'御定全唐詩/json/675.json','["塞曲淒清楚水濱，聲聲吹出落梅春。", "須知風月千檣下，亦有葫蘆河畔人。"]'),
('yuding-34','閑題','鄭谷','唐','御定全唐诗','yuding','','[]','舉世何人肯自知，須逢精鑒定妍媸。',32,'御定全唐詩/json/675.json','["舉世何人肯自知，須逢精鑒定妍媸。", "若教嫫母臨明鏡，也道不勞紅粉施。"]'),
('yuding-35','曲江春草','鄭穀','唐','御定全唐诗','yuding','','[]','花落江堤蔟暖煙，雨餘草色遠相連。',32,'御定全唐詩/json/675.json','["花落江堤蔟暖煙，雨餘草色遠相連。", "香輪莫輾青青破，留與愁人一醉眠。"]'),
('yuding-36','雪中偶題','鄭穀','唐','御定全唐诗','yuding','','[]','亂飄僧舍茶煙濕，密灑歌樓酒力微。',32,'御定全唐詩/json/675.json','["亂飄僧舍茶煙濕，密灑歌樓酒力微。", "江上晚來堪畫處，漁人披得一蓑歸。"]'),
('yuding-37','題慈恩寺默公院','鄭穀','唐','御定全唐诗','yuding','','[]','雖近曲江居古寺，舊山終憶九華峰。',32,'御定全唐詩/json/675.json','["雖近曲江居古寺，舊山終憶九華峰。", "春來老病厭迎送，剪卻牡丹栽野松。"]'),
('yuding-38','江上阻風','鄭谷','唐','御定全唐诗','yuding','','[]','水天春暗暮寒濃，船閉篷窗細雨中。',32,'御定全唐詩/json/675.json','["水天春暗暮寒濃，船閉篷窗細雨中。", "聞道漁家酒初熟，晚來翻喜打頭風。"]'),
('yuding-39','淮上與友人別','鄭穀','唐','御定全唐诗','yuding','','[]','揚子江頭楊柳春，楊花愁殺渡江人。',32,'御定全唐詩/json/675.json','["揚子江頭楊柳春，楊花愁殺渡江人。", "數聲風笛離亭晚，君向瀟湘我向秦。"]'),
('yuding-40','忍公小軒二首','鄭谷','唐','御定全唐诗','yuding','','[]','松溪水色綠於松，每到松溪到暮鐘。',64,'御定全唐詩/json/675.json','["松溪水色綠於松，每到松溪到暮鐘。", "閑得心源只如此，問禪何必向雙峰。", "舊遊前事半埃塵，多向林中結淨因。", "一念一爐香火裏，後身唯願似師身。"]'),
('yuding-41','淮上漁者','鄭穀','唐','御定全唐诗','yuding','','[]','白頭波上白頭翁，家逐船移浦浦風。',32,'御定全唐詩/json/675.json','["白頭波上白頭翁，家逐船移浦浦風。", "一尺鱸魚新釣得，兒孫吹火荻花中。"]'),
('yuding-42','興州江館','鄭谷','唐','御定全唐诗','yuding','','[]','向蜀還秦計未成，寒蛩一夜繞床鳴。',32,'御定全唐詩/json/675.json','["向蜀還秦計未成，寒蛩一夜繞床鳴。", "愁眠不穩孤燈盡，坐聽嘉陵江水聲。"]'),
('yuding-43','題無本上人小齋','鄭穀','唐','御定全唐诗','yuding','','[]','寒寺唯應我訪師，人稀境靜雪銷遲。',32,'御定全唐詩/json/675.json','["寒寺唯應我訪師，人稀境靜雪銷遲。", "竹西落照侵窗好，堪惜歸時落照時。"]'),
('yuding-44','七祖院小山','鄭穀','唐','御定全唐诗','yuding','','[]','小巧功成雨蘚斑，軒車日日扣松關。',32,'御定全唐詩/json/675.json','["小巧功成雨蘚斑，軒車日日扣松關。", "峨嵋咫尺無人去，卻向僧窗看假山。"]'),
('yuding-45','定水寺行香','鄭穀','唐','御定全唐诗','yuding','','[]','聽經看畫繞虛廊，風拂金爐待賜香。',32,'御定全唐詩/json/675.json','["聽經看畫繞虛廊，風拂金爐待賜香。", "丞相未來春雪密，暫偷閒臥老僧床。"]'),
('yuding-46','浯溪','鄭穀','唐','御定全唐诗','yuding','','[]','湛湛清江疊疊山，白雲白鳥在其間。',32,'御定全唐詩/json/675.json','["湛湛清江疊疊山，白雲白鳥在其間。", "漁翁醉睡又醒睡，誰道皇天最惜閑。"]'),
('yuding-47','悶題','鄭谷','唐','御定全唐诗','yuding','','[]','莫厭九衢塵土間，秋晴滿眼是南山。',32,'御定全唐詩/json/675.json','["莫厭九衢塵土間，秋晴滿眼是南山。", "僧家未必全無事，道著訪僧心且閑。"]'),
('yuding-48','重訪黃神穀策禪者','鄭谷','唐','御定全唐诗','yuding','','[]','初塵芸閣辭禪閣，卻訪支郎是老郎。',32,'御定全唐詩/json/675.json','["初塵芸閣辭禪閣，卻訪支郎是老郎。", "我趣轉卑師趣靜，數峰秋雪一爐香。"]'),
('yuding-49','別修覺寺無本上人','鄭穀','唐','御定全唐诗','yuding','','[]','松上閑雲石上苔，自嫌歸去夕陽催。',32,'御定全唐詩/json/675.json','["松上閑雲石上苔，自嫌歸去夕陽催。", "山門握手無他語，只約今冬看雪來。"]'),
('yuding-50','贈日東鑒禪師','鄭谷','唐','御定全唐诗','yuding','','[]','故國無心渡海潮，老禪方丈倚中條。',32,'御定全唐詩/json/675.json','["故國無心渡海潮，老禪方丈倚中條。", "夜深雨絕松堂靜，一點山螢照寂寥。"]'),
('yuding-51','傳經院壁畫松','鄭谷','唐','御定全唐诗','yuding','','[]','危根瘦盡聳孤峰，珍重江僧好筆蹤。',32,'御定全唐詩/json/675.json','["危根瘦盡聳孤峰，珍重江僧好筆蹤。", "得向遊人多處畫，卻勝澗底作真松。"]'),
('yuding-52','高蟾先輩以詩筆相示抒成寄酬','鄭谷','唐','御定全唐诗','yuding','','[]','張生故國三千里，知者唯應杜紫微。',32,'御定全唐詩/json/675.json','["張生故國三千里，知者唯應杜紫微。", "君有君恩秋後葉，可能更羨謝玄暉。"]'),
('yuding-53','為人題','鄭穀','唐','御定全唐诗','yuding','','[]','淚濕孤鸞曉鏡昏，近來方解惜青春。',32,'御定全唐詩/json/675.json','["淚濕孤鸞曉鏡昏，近來方解惜青春。", "杏花楊柳年年好，不忍回看舊寫真。"]'),
('yuding-54','越鳥','鄭穀','唐','御定全唐诗','yuding','','[]','背霜南雁不到處，倚棹北人初聽時。',32,'御定全唐詩/json/675.json','["背霜南雁不到處，倚棹北人初聽時。", "梅雨滿江春草歇，一聲聲在荔枝枝。"]'),
('yuding-55','黃鶯','鄭穀','唐','御定全唐诗','yuding','','[]','春雲薄薄日輝輝，宮樹煙深隔水飛。',32,'御定全唐詩/json/675.json','["春雲薄薄日輝輝，宮樹煙深隔水飛。", "應為能歌系仙籍，麻姑乞與女真衣。"]'),
('yuding-56','失鷺鷥','鄭穀','唐','御定全唐诗','yuding','','[]','野格由來倦小池，驚飛卻下碧江涯。',32,'御定全唐詩/json/675.json','["野格由來倦小池，驚飛卻下碧江涯。", "月昏風急何處宿，秋岸蕭蕭黃葦枝。"]'),
('yuding-57','苔錢','鄭穀','唐','御定全唐诗','yuding','','[]','春紅秋紫繞池台，個個圓如濟世財。',32,'御定全唐詩/json/675.json','["春紅秋紫繞池台，個個圓如濟世財。", "雨後無端滿窮巷，買花不得買愁來。"]'),
('yuding-58','蓮葉','鄭穀','唐','御定全唐诗','yuding','','[]','移舟水濺差差綠，倚檻風搖柄柄香。',32,'御定全唐詩/json/675.json','["移舟水濺差差綠，倚檻風搖柄柄香。", "多謝浣溪人不折，雨中留得蓋鴛鴦。"]'),
('yuding-59','蜀中賞海棠','鄭穀','唐','御定全唐诗','yuding','','[]','濃淡芳春滿蜀鄉，半隨風雨斷鶯腸。',32,'御定全唐詩/json/675.json','["濃淡芳春滿蜀鄉，半隨風雨斷鶯腸。", "浣花溪上堪惆悵，子美無心為發揚。"]'),
('yuding-60','投所知','鄭穀','唐','御定全唐诗','yuding','','[]','砌下芝蘭新滿徑，門前桃李舊垂陰。',32,'御定全唐詩/json/675.json','["砌下芝蘭新滿徑，門前桃李舊垂陰。", "卻應回念江邊草，放出春煙一寸心。"]'),
('yuding-61','早入諫院二首','鄭穀','唐','御定全唐诗','yuding','','[]','玉階春冷未催班，暫拂塵衣就笏眠。',64,'御定全唐詩/json/675.json','["玉階春冷未催班，暫拂塵衣就笏眠。", "孤立小心還自笑，夢魂潛繞禦爐煙。", "紫雲重疊抱春城，廊下人稀唱漏聲。", "偷得微吟斜倚柱，滿衣花露聽宮鶯。"]'),
('yuding-62','忝官諫垣明日轉對','鄭穀','唐','御定全唐诗','yuding','','[]','吾君英睿相君賢，其那寰區未晏然。',32,'御定全唐詩/json/675.json','["吾君英睿相君賢，其那寰區未晏然。", "明日翠華春殿下，不知何語可聞天。"]'),
('yuding-63','再經南陽','鄭谷','唐','御定全唐诗','yuding','','[]','平蕪漠漠失樓臺，昔日遊人亂後來。',32,'御定全唐詩/json/675.json','["平蕪漠漠失樓臺，昔日遊人亂後來。", "寥落牆匡春欲暮，燒殘官樹有花開。"]'),
('yuding-64','贈下第舉公','鄭穀','唐','御定全唐诗','yuding','','[]','見君失意我惆悵，記得當年落第情。',32,'御定全唐詩/json/675.json','["見君失意我惆悵，記得當年落第情。", "出去無憀歸又悶，花南慢打講鐘聲。"]'),
('yuding-65','春陰','鄭穀','唐','御定全唐诗','yuding','','[]','推琴當酒度春陰，不解謀生只解吟。',32,'御定全唐詩/json/675.json','["推琴當酒度春陰，不解謀生只解吟。", "舞蝶歌鶯莫相試，老郎心是老僧心。"]'),
('yuding-66','送張逸人','鄭穀','唐','御定全唐诗','yuding','','[]','人間疏散更無人，浪兀孤舟酒兀身。',32,'御定全唐詩/json/675.json','["人間疏散更無人，浪兀孤舟酒兀身。", "蘆筍鱸魚拋不得，五陵珍重五湖春。"]'),
('yuding-67','初還京師寓止府署偶題屋壁','鄭穀','唐','御定全唐诗','yuding','','[]','秋光不見舊亭台，四顧荒涼瓦礫堆。',32,'御定全唐詩/json/675.json','["秋光不見舊亭台，四顧荒涼瓦礫堆。", "火力不能銷地力，亂前黃菊眼前開。"]'),
('yuding-68','擢第後入蜀經羅村，路見海棠盛開偶有題詠','鄭谷','唐','御定全唐诗','yuding','','[]','上國休誇紅杏豔，深溪自照綠苔磯。一枝低帶流鶯睡，',40,'御定全唐詩/json/675.json','["上國休誇紅杏豔，深溪自照綠苔磯。一枝低帶流鶯睡，", "手中已有新春桂，多謝煙香更入衣。"]'),
('yuding-69','次韻和禮部盧侍郎江上秋夕寓懷','鄭谷','唐','御定全唐诗','yuding','','[]','盧郎到處覺風生，蜀郡留連亞相情。亂後江山悲庾信，',40,'御定全唐詩/json/675.json','["盧郎到處覺風生，蜀郡留連亞相情。亂後江山悲庾信，", "未脫白衣頭半白，叨陪屬和倍為榮。"]'),
('yuding-70','宜春再訪芳公言公幽齋寫懷敘事，因賦長言','鄭穀','唐','御定全唐诗','yuding','','[]','入門長恐先師在，香印紗燈似昔年，澗路縈回齋處遠，',40,'御定全唐詩/json/675.json','["入門長恐先師在，香印紗燈似昔年，澗路縈回齋處遠，", "顧渚一甌春有味，中林話舊亦潸然。"]'),
('yuding-71','讀李白集','鄭谷','唐','御定全唐诗','yuding','','[]','何事文星與酒星，一時鐘在李先生。',32,'御定全唐詩/json/675.json','["何事文星與酒星，一時鐘在李先生。", "高吟大醉三千首，留著人間伴月明。"]'),
('yuding-72','卷末偶題三首','鄭穀','唐','御定全唐诗','yuding','','[]','一卷疏蕪一百篇，名成未敢暫忘筌。',96,'御定全唐詩/json/675.json','["一卷疏蕪一百篇，名成未敢暫忘筌。", "何如海日生殘夜，一句能令萬古傳。", "七歲侍行湖外去，岳陽樓上敢題詩。", "如今寒晚無功業，何以勝任國士知。", "一第由來是出身，垂名俱為國風陳。", "此生若不知騷雅，孤宦如何作近臣。"]'),
('yuding-73','讀前集二首','鄭谷','唐','御定全唐诗','yuding','','[]','殷璠裁鑒英靈集，頗覺同才得旨深。',64,'御定全唐詩/json/675.json','["殷璠裁鑒英靈集，頗覺同才得旨深。", "何事後來高仲武，品題間氣未公心。", "風騷如線不勝悲，國步多艱即此時。", "愛日滿階看古集，只應陶集是吾師。"]'),
('yuding-74','渚宮亂後作','鄭穀','唐','御定全唐诗','yuding','','[]','鄉人來話亂離情，淚滴殘陽問楚荊。白社已應無故老，',40,'御定全唐詩/json/675.json','["鄉人來話亂離情，淚滴殘陽問楚荊。白社已應無故老，", "牢落故居灰燼後，黃花紫蔓上牆生。"]'),
('yuding-75','鷓鴣','鄭穀','唐','御定全唐诗','yuding','','[]','暖戲煙蕪錦翼齊，品流應得近山雞。雨昏青草湖邊過，',40,'御定全唐詩/json/675.json','["暖戲煙蕪錦翼齊，品流應得近山雞。雨昏青草湖邊過，", "相呼相應湘江闊，苦竹叢深春日西。"]'),
('yuding-76','燕','鄭穀','唐','御定全唐诗','yuding','','[]','年去年來來去忙，春寒煙暝渡瀟湘。低飛綠岸和梅雨，',40,'御定全唐詩/json/675.json','["年去年來來去忙，春寒煙暝渡瀟湘。低飛綠岸和梅雨，", "千言萬語無人會，又逐流鶯過短牆。"]'),
('yuding-77','侯家鷓鴣','鄭谷','唐','御定全唐诗','yuding','','[]','江天梅雨濕江蘺，到處煙香是此時。苦竹嶺無歸去日，',40,'御定全唐詩/json/675.json','["江天梅雨濕江蘺，到處煙香是此時。苦竹嶺無歸去日，", "唯有佳人憶南國，殷勤為爾唱愁詞。"]'),
('yuding-78','雁','鄭穀','唐','御定全唐诗','yuding','','[]','八月悲風九月霜，蓼花紅淡葦條黃。石頭城下波搖影，',40,'御定全唐詩/json/675.json','["八月悲風九月霜，蓼花紅淡葦條黃。石頭城下波搖影，", "故鄉聞爾亦惆悵，何況扁舟非故鄉。"]'),
('yuding-79','水','鄭穀','唐','御定全唐诗','yuding','','[]','竹院松廊分數派，不空清泚亦逶迤。落花相逐去何處，',40,'御定全唐詩/json/675.json','["竹院松廊分數派，不空清泚亦逶迤。落花相逐去何處，", "晚晴一片連莎綠，悔與滄浪有舊期。"]'),
('yuding-80','海棠','鄭谷','唐','御定全唐诗','yuding','','[]','春風用意勻顏色，銷得攜觴與賦詩。穠麗最宜新著雨，',40,'御定全唐詩/json/675.json','["春風用意勻顏色，銷得攜觴與賦詩。穠麗最宜新著雨，", "朝醉暮吟看不足，羨他蝴蝶宿深枝。"]'),
('yuding-81','竹','鄭穀','唐','御定全唐诗','yuding','','[]','宜煙宜雨又宜風，拂水藏村複間松。移得蕭騷從遠寺，',40,'御定全唐詩/json/675.json','["宜煙宜雨又宜風，拂水藏村複間松。移得蕭騷從遠寺，", "無賴杏花多意緒，數枝穿翠好相容。"]'),
('yuding-82','荔枝樹','鄭穀','唐','御定全唐诗','yuding','','[]','二京曾見畫圖中，數本芳菲色不同。孤棹今來巴徼外，',40,'御定全唐詩/json/675.json','["二京曾見畫圖中，數本芳菲色不同。孤棹今來巴徼外，", "腸斷渝瀘霜霰薄，不教葉似灞陵紅。"]'),
('yuding-83','錦二首','鄭穀','唐','御定全唐诗','yuding','','[]','布素豪家定不看，若無文彩入時難。紅迷天子帆邊日，',80,'御定全唐詩/json/675.json','["布素豪家定不看，若無文彩入時難。紅迷天子帆邊日，", "舞衣轉轉求新樣，不問流離桑柘殘。", "文君手裏曙霞生，美號仍聞借蜀城。奪得始知袍更貴，", "禮部郎官人所重，省中別占好窠名。"]'),
('yuding-84','蠟燭','鄭穀','唐','御定全唐诗','yuding','','[]','仙漏遲遲出建章，宮簾不動透清光。金闈露白新裁詔，',40,'御定全唐詩/json/675.json','["仙漏遲遲出建章，宮簾不動透清光。金闈露白新裁詔，", "多情更有分明處，照得歌塵下燕梁。"]'),
('yuding-85','燈','鄭谷','唐','御定全唐诗','yuding','','[]','雨向莎階滴未休，冷光孤恨兩悠悠。船中聞雁洞庭宿，',40,'御定全唐詩/json/675.json','["雨向莎階滴未休，冷光孤恨兩悠悠。船中聞雁洞庭宿，", "蕭騷寒竹南窗靜，一局閑棋為爾留。"]'),
('yuding-86','宗人作尉唐昌官署幽勝而又博學精富得以言談…留書屋壁','鄭穀','唐','御定全唐诗','yuding','','[]','公堂瀟灑有林泉，只隔苔牆是渚田。宗黨相親離亂世，',40,'御定全唐詩/json/675.json','["公堂瀟灑有林泉，只隔苔牆是渚田。宗黨相親離亂世，", "風雨夜長同一宿，舊遊多共憶樊川。"]'),
('yuding-87','為戶部李郎中與令季端公寓止渠州江寺偶作寄獻','鄭谷','唐','御定全唐诗','yuding','','[]','退居瀟灑寄禪關，高掛朝簪淨室間。孤島雖留雙鶴歇，',40,'御定全唐詩/json/675.json','["退居瀟灑寄禪關，高掛朝簪淨室間。孤島雖留雙鶴歇，", "仙署金閨虛位久，夜清應夢近天顏。"]'),
('yuding-88','重陽日訪元秀上人','鄭谷','唐','御定全唐诗','yuding','','[]','紅葉黃花秋景寬，醉吟朝夕在樊川。卻嫌今日登山俗，',40,'御定全唐詩/json/675.json','["紅葉黃花秋景寬，醉吟朝夕在樊川。卻嫌今日登山俗，", "歸來童稚爭相笑，何事無人與酒船。"]'),
('yuding-0','闕下春日','鄭谷','唐','御定全唐诗','yuding','','[]','建章宮殿紫雲飄，春漏遲遲下絳霄。綺陌暖風嘶去馬，',40,'御定全唐詩/json/676.json','["建章宮殿紫雲飄，春漏遲遲下絳霄。綺陌暖風嘶去馬，", "秦楚年年有離別，揚鞭揮袖灞陵橋。"]'),
('yuding-1','贈劉神童','鄭谷','唐','御定全唐诗','yuding','','[]','習讀在前生，僧談足可明。還家雖解喜，登第未知榮。',48,'御定全唐詩/json/676.json','["習讀在前生，僧談足可明。還家雖解喜，登第未知榮。", "時果曾沾賜，春闈不掛情。燈前猶惡睡，寤語讀書聲。"]'),
('yuding-2','遠遊','鄭穀','唐','御定全唐诗','yuding','','[]','江湖猶足事，食宿戍鼙喧。久客秋風起，孤舟夜浪翻。',72,'御定全唐詩/json/676.json','["江湖猶足事，食宿戍鼙喧。久客秋風起，孤舟夜浪翻。", "鄉音離楚水，廟貌入湘源。岸闊鳧鷖小，林垂橘柚繁。", "津官來有意，漁者笑無言。早晚酬僧約，中條有藥園。"]'),
('yuding-3','光化戊午年舉公見示省試春草碧色詩偶賦是題','鄭穀','唐','御定全唐诗','yuding','','[]','萇弘血染新，含露滿江濱。想得尋花徑，應迷拾翠人。',72,'御定全唐詩/json/676.json','["萇弘血染新，含露滿江濱。想得尋花徑，應迷拾翠人。", "窗紗迎擁砌，簪玉姑成茵。天借新晴色，雲饒落日春。", "嵐光垂處合，眉黛看時嚬。願與仙桃比，無令惹路塵。"]'),
('yuding-4','江際','鄭穀','唐','御定全唐诗','yuding','','[]','杳杳漁舟破暝煙，疏疏蘆葦舊江天。那堪流落逢搖落，',40,'御定全唐詩/json/676.json','["杳杳漁舟破暝煙，疏疏蘆葦舊江天。那堪流落逢搖落，", "兵車未息年華促，早晚閑吟向滻川。"]'),
('yuding-5','將之瀘郡旅次遂州遇裴晤員外謫居於此話舊淒涼因寄二首','鄭谷','唐','御定全唐诗','yuding','','[]','誰解登高問上玄，謫仙何事謫詩仙，雲遮列宿離華省，',80,'御定全唐詩/json/676.json','["誰解登高問上玄，謫仙何事謫詩仙，雲遮列宿離華省，", "不知幾首南行曲，留與巴兒萬古傳。", "昔年共照松溪影，松折溪荒僧已無。今日重思錦城事，", "我拜師門更南去，荔枝春熟向渝瀘。"]'),
('yuding-6','次韻和秀上人長安寺居言懷寄渚宮禪者','鄭穀','唐','御定全唐诗','yuding','','[]','舊齋松老別多年，香社人稀喪亂間。出寺只知趨內殿，',40,'御定全唐詩/json/676.json','["舊齋松老別多年，香社人稀喪亂間。出寺只知趨內殿，", "唯恐興來飛錫去，老郎無路更追攀。"]'),
('yuding-7','蜀中春日','鄭谷','唐','御定全唐诗','yuding','','[]','海棠風外獨沾巾，襟袖無端惹蜀塵。和暖又逢挑菜日，',40,'御定全唐詩/json/676.json','["海棠風外獨沾巾，襟袖無端惹蜀塵。和暖又逢挑菜日，", "何事晚來微雨後，錦江春學曲江春。"]'),
('yuding-8','遊蜀','鄭谷','唐','御定全唐诗','yuding','','[]','所向明知是暗投，兩行清淚語前流。雲橫新塞遮秦甸，',40,'御定全唐詩/json/676.json','["所向明知是暗投，兩行清淚語前流。雲橫新塞遮秦甸，", "梅黃麥綠無歸處，可得漂漂愛浪遊。"]'),
('yuding-9','峽中嘗茶','鄭穀','唐','御定全唐诗','yuding','','[]','蔟蔟新英摘露光，小江園裏火煎嘗。吳僧漫說鴉山好，',40,'御定全唐詩/json/676.json','["蔟蔟新英摘露光，小江園裏火煎嘗。吳僧漫說鴉山好，", "鹿門病客不歸去，酒渴更知春味長。"]'),
('yuding-10','輦下冬暮詠懷','鄭穀','唐','御定全唐诗','yuding','','[]','永巷閑吟一徑蒿，輕肥大笑事風騷。煙含紫禁花期近，',40,'御定全唐詩/json/676.json','["永巷閑吟一徑蒿，輕肥大笑事風騷。煙含紫禁花期近，", "十年春淚催衰颯，羞向清流照鬢毛。"]'),
('yuding-11','石城','鄭穀','唐','御定全唐诗','yuding','','[]','石城昔為莫愁鄉，莫愁魂散石城荒。江人依舊棹舴艋，',40,'御定全唐詩/json/676.json','["石城昔為莫愁鄉，莫愁魂散石城荒。江人依舊棹舴艋，", "煙濃草遠望不盡，千古漢陽閑夕陽。"]'),
('yuding-12','蜀中三首','鄭穀','唐','御定全唐诗','yuding','','[]','馬頭春向鹿頭關，遠樹平蕪一望閑。雪下文君沾酒市，',120,'御定全唐詩/json/676.json','["馬頭春向鹿頭關，遠樹平蕪一望閑。雪下文君沾酒市，", "堤月橋燈好時景，漢庭無事不征蠻。", "夜無多雨曉生塵，草色嵐光日日新。蒙頂茶畦千點露，", "卻共海棠花有約，數年留滯不歸人。", "渚遠江清碧簟紋，小桃花繞薛濤墳。朱橋直指金門路，", "子規夜夜啼巴樹，不並吳鄉楚國聞。"]'),
('yuding-13','少華甘露寺','鄭谷','唐','御定全唐诗','yuding','','[]','石門蘿徑與天鄰，雨檜風篁遠近聞。飲澗鹿喧雙派水，',40,'御定全唐詩/json/676.json','["石門蘿徑與天鄰，雨檜風篁遠近聞。飲澗鹿喧雙派水，", "長欲然香來此宿，北林猿鶴舊同群。"]'),
('yuding-14','慈恩寺偶題','鄭穀','唐','御定全唐诗','yuding','','[]','往事悠悠添浩歎，勞生擾擾竟何能。故山歲晚不歸去，',40,'御定全唐詩/json/676.json','["往事悠悠添浩歎，勞生擾擾竟何能。故山歲晚不歸去，", "吟餘卻起雙峰念，曾看庵西瀑布冰。"]'),
('yuding-15','石門山泉','鄭穀','唐','御定全唐诗','yuding','','[]','一脈清冷何所之，縈莎漱蘚入僧池。雲邊野客窮來處，',40,'御定全唐詩/json/676.json','["一脈清冷何所之，縈莎漱蘚入僧池。雲邊野客窮來處，", "煙春雨晚閑吟去，不復遠尋皇子陂。"]'),
('yuding-16','渭陽樓閑望','鄭穀','唐','御定全唐诗','yuding','','[]','千重二華見皇州，望盡凝嵐即此樓。細雨不藏秦樹色，',40,'御定全唐詩/json/676.json','["千重二華見皇州，望盡凝嵐即此樓。細雨不藏秦樹色，", "擾擾塵中猶未已，可能疏傅獨能休。"]'),
('yuding-17','送田光','鄭穀','唐','御定全唐诗','yuding','','[]','九陌低迷誰問我，五湖流浪可悲君。著書笑破蘇司業，',40,'御定全唐詩/json/676.json','["九陌低迷誰問我，五湖流浪可悲君。著書笑破蘇司業，", "耒陽江口春山綠，慟哭應尋杜甫墳。"]'),
('yuding-18','送進士吳延保及第後南游','鄭谷','唐','御定全唐诗','yuding','','[]','得意卻思尋舊跡，新銜未切向蘭台。吟看秋草出關去，',40,'御定全唐詩/json/676.json','["得意卻思尋舊跡，新銜未切向蘭台。吟看秋草出關去，", "江湖易有淹留興，莫待春風落庾梅。"]'),
('yuding-19','送進士王駕下第歸蒲中','鄭穀','唐','御定全唐诗','yuding','','[]','失意離愁春不知，到家時是落花時。孤單取事休言命，',40,'御定全唐詩/json/676.json','["失意離愁春不知，到家時是落花時。孤單取事休言命，", "應嗟我又巴江去，遊子悠悠聽子規。"]'),
('yuding-20','作尉鄠郊送進士潘為下第南歸','鄭穀','唐','御定全唐诗','yuding','','[]','歸去宜春春水深，麥秋梅雨過湘陰。鄉園幾度經狂寇，',40,'御定全唐詩/json/676.json','["歸去宜春春水深，麥秋梅雨過湘陰。鄉園幾度經狂寇，", "灞陵橋上楊花裏，酒滿芳樽淚滿襟。"]'),
('yuding-21','送進士韋序赴舉','鄭穀','唐','御定全唐诗','yuding','','[]','丹霞照上三清路，瑞錦裁成五色毫。波浪不能隨世態，',40,'御定全唐詩/json/676.json','["丹霞照上三清路，瑞錦裁成五色毫。波浪不能隨世態，", "預想明年騰躍處，龍津春碧浸仙桃。"]'),
('yuding-22','寄獻狄右丞','鄭穀','唐','御定全唐诗','yuding','','[]','逐勝偷閒向杜陵，愛僧不愛紫衣僧。身為醉客思吟客，',40,'御定全唐詩/json/676.json','["逐勝偷閒向杜陵，愛僧不愛紫衣僧。身為醉客思吟客，", "孤單小諫漁舟在，心戀清潭去未能。"]'),
('yuding-23','轉正郎後寄獻集賢相公','鄭谷','唐','御定全唐诗','yuding','','[]','予名初在德門前，屈指年來三十年。自賀孤危終際會，',40,'御定全唐詩/json/676.json','["予名初在德門前，屈指年來三十年。自賀孤危終際會，", "平昔苦心何所恨，受恩多是舊詩篇。"]'),
('yuding-24','所知從事近藩偶有懷寄','鄭穀','唐','御定全唐诗','yuding','','[]','官舍種莎僧對榻，生涯如在舊山貧。酒醒草檄聞殘漏，',40,'御定全唐詩/json/676.json','["官舍種莎僧對榻，生涯如在舊山貧。酒醒草檄聞殘漏，", "霜台伏首思歸切，莫把漁竿逐逸人。"]'),
('yuding-25','獻大京兆薛常侍能','鄭谷','唐','御定全唐诗','yuding','','[]','恥將官業競前途，自愛篇章古不如。一炷香新開道院，',40,'御定全唐詩/json/676.json','["恥將官業競前途，自愛篇章古不如。一炷香新開道院，", "唯有明公賞新句，秋風不敢憶鱸魚。"]'),
('yuding-26','寄贈孫路處士','鄭谷','唐','御定全唐诗','yuding','','[]','平生詩譽更誰過，歸老東吳命若何。知己凋零垂白髮，',40,'御定全唐詩/json/676.json','["平生詩譽更誰過，歸老東吳命若何。知己凋零垂白髮，", "深入富春人不見，閑門空掩半庭莎。"]'),
('yuding-27','獻制誥楊舍人','鄭穀','唐','御定全唐诗','yuding','','[]','為郡東吳只飲冰，瑣闈頻降鳳書征。隨行已有朱衣吏，',40,'御定全唐詩/json/676.json','["為郡東吳只飲冰，瑣闈頻降鳳書征。隨行已有朱衣吏，", "葦陂竹塢情無限，閒話毗陵問杜陵。"]'),
('yuding-28','次韻酬張補闕因寒食見寄之什','鄭谷','唐','御定全唐诗','yuding','','[]','柳近清明翠縷長，多情右袞不相忘。開緘雖睹新篇麗，',40,'御定全唐詩/json/676.json','["柳近清明翠縷長，多情右袞不相忘。開緘雖睹新篇麗，", "朝稀且莫輕春賞，勝事由來在帝鄉。"]'),
('yuding-29','贈宗人前公安宰君','鄭穀','唐','御定全唐诗','yuding','','[]','喧卑從宦出喧卑，別畫能琴又解棋。海上春耕因亂廢，',40,'御定全唐詩/json/676.json','["喧卑從宦出喧卑，別畫能琴又解棋。海上春耕因亂廢，", "孤散恨無推唱路，耿懷吟得贈君詩。"]'),
('yuding-30','寄贈楊夔處士','鄭谷','唐','御定全唐诗','yuding','','[]','結茅只約釣魚臺，濺水鸕鷀去又回。春臥甕邊聽酒熟，',40,'御定全唐詩/json/676.json','["結茅只約釣魚臺，濺水鸕鷀去又回。春臥甕邊聽酒熟，", "國步未安風雅薄，可能高尚掞天才。"]'),
('yuding-31','寄同年禮部趙郎中','鄭谷','唐','御定全唐诗','yuding','','[]','仙步徐徐整羽衣，小儀澄澹轉中儀。樺飄紅燼趨朝路，',40,'御定全唐詩/json/676.json','["仙步徐徐整羽衣，小儀澄澹轉中儀。樺飄紅燼趨朝路，", "自憐孤宦誰相念，禱祝空吟一首詩。"]'),
('yuding-32','春暮詠懷寄集賢韋起居袞','鄭穀','唐','御定全唐诗','yuding','','[]','寂寂風簾信自垂，楊花筍籜正離披。長安一夜殘春雨，',40,'御定全唐詩/json/676.json','["寂寂風簾信自垂，楊花筍籜正離披。長安一夜殘春雨，", "五湖煙網非無意，未去難忘國士知。"]'),
('yuding-33','多情','鄭穀','唐','御定全唐诗','yuding','','[]','賦分多情卻自嗟，蕭衰未必為年華。睡輕可忍風敲竹，',40,'御定全唐詩/json/676.json','["賦分多情卻自嗟，蕭衰未必為年華。睡輕可忍風敲竹，", "鶯春雁夜長如此，賴是幽居近酒家。"]'),
('yuding-34','感懷投時相','鄭穀','唐','御定全唐诗','yuding','','[]','非才偶忝直文昌，兩鬢年深一鏡霜。待漏敢辭稱小吏，',40,'御定全唐詩/json/676.json','["非才偶忝直文昌，兩鬢年深一鏡霜。待漏敢辭稱小吏，", "丞相舊知為學苦，更教何處貢篇章。"]'),
('yuding-35','自貽','鄭穀','唐','御定全唐诗','yuding','','[]','飲筵博席與心違，野眺春吟更是誰。琴有澗風聲轉淡，',40,'御定全唐詩/json/676.json','["飲筵博席與心違，野眺春吟更是誰。琴有澗風聲轉淡，", "頭角俊髦應指笑，權門蹤跡獨差池。"]'),
('yuding-36','自遣','鄭谷','唐','御定全唐诗','yuding','','[]','強健宦途何足謂，入微章句更難論。誰知野性真天性，',40,'御定全唐詩/json/676.json','["強健宦途何足謂，入微章句更難論。誰知野性真天性，", "朝回何處消長日，紫閣峰南有舊村。"]'),
('yuding-37','中年','鄭谷','唐','御定全唐诗','yuding','','[]','漠漠秦雲淡淡天，新年景象入中年。情多最恨花無語，',40,'御定全唐詩/json/676.json','["漠漠秦雲淡淡天，新年景象入中年。情多最恨花無語，", "衰遲自喜添詩學，更把前題改數聯。"]'),
('yuding-38','自適','鄭穀','唐','御定全唐诗','yuding','','[]','紫陌賓士不暫停，送迎終日在郊坰。年來鬢畔未垂白，',40,'御定全唐詩/json/676.json','["紫陌賓士不暫停，送迎終日在郊坰。年來鬢畔未垂白，", "春風只有九十日，可合花前半日醒。"]'),
('yuding-39','結綬鄠郊縻攝府署偶有自詠','鄭穀','唐','御定全唐诗','yuding','','[]','鶯離寒穀士逢春，釋褐來年暫種芸。自笑老為梅少府，',40,'御定全唐詩/json/676.json','["鶯離寒穀士逢春，釋褐來年暫種芸。自笑老為梅少府，", "推卻簿書搔短髮，落花飛絮正紛紛。"]'),
('yuding-40','漂泊','鄭穀','唐','御定全唐诗','yuding','','[]','槿墜蓬疏池館清，日光風緒淡無情。鱸魚斫鱠輸張翰，',40,'御定全唐詩/json/676.json','["槿墜蓬疏池館清，日光風緒淡無情。鱸魚斫鱠輸張翰，", "黃花催促重陽近，何處登高望二京。"]'),
('yuding-41','吊故禮部韋員外序','鄭穀','唐','御定全唐诗','yuding','','[]','臘雪初晴花舉杯，便期攜手上春台。高情唯怕酒不滿，',40,'御定全唐詩/json/676.json','["臘雪初晴花舉杯，便期攜手上春台。高情唯怕酒不滿，", "杜陵芳草年年綠，醉魄吟魂無複回。"]'),
('yuding-42','渼陂','鄭穀','唐','御定全唐诗','yuding','','[]','昔事東流共不回，春深獨向渼陂來。亂前別業依稀在，',40,'御定全唐詩/json/676.json','["昔事東流共不回，春深獨向渼陂來。亂前別業依稀在，", "潸然四顧難消遣，只有佯狂泥酒杯。"]'),
('yuding-43','代秋扇詞','鄭穀','唐','御定全唐诗','yuding','','[]','露入庭蕪恨已深，熱時天下是知音。汗流浹背曾施力，',40,'御定全唐詩/json/676.json','["露入庭蕪恨已深，熱時天下是知音。汗流浹背曾施力，", "綠槐陰合清和後，不會何顏又見尋。"]'),
('yuding-44','宣義裏舍冬暮自貽','鄭穀','唐','御定全唐诗','yuding','','[]','幽居不稱在長安，溝淺浮春岸雪殘。板屋漸移方帶野，',40,'御定全唐詩/json/676.json','["幽居不稱在長安，溝淺浮春岸雪殘。板屋漸移方帶野，", "滿眼塵埃馳騖去，獨尋煙竹剪漁竿。"]'),
('yuding-45','省中偶作','鄭穀','唐','御定全唐诗','yuding','','[]','三轉郎曹自勉旃，莎階吟步想前賢。未如何遜無佳句，',40,'御定全唐詩/json/676.json','["三轉郎曹自勉旃，莎階吟步想前賢。未如何遜無佳句，", "乳毛松雪春來好，直夜清閒且學禪。"]'),
('yuding-46','同志顧雲下第出京偶有寄勉','鄭穀','唐','御定全唐诗','yuding','','[]','鳳策聯華是國華，春來偶未上仙槎。鄉連南渡思菰米，',40,'御定全唐詩/json/676.json','["鳳策聯華是國華，春來偶未上仙槎。鄉連南渡思菰米，", "一般情緒應相信，門靜莎深樹影斜。"]'),
('yuding-47','敷溪高士','鄭穀','唐','御定全唐诗','yuding','','[]','敷溪南岸掩柴荊，掛卻朝衣愛淨名。閑得林園栽樹法，',40,'御定全唐詩/json/676.json','["敷溪南岸掩柴荊，掛卻朝衣愛淨名。閑得林園栽樹法，", "謫去征還何擾擾，片雲相伴看衰榮。"]'),
('yuding-48','九日偶懷寄左省張起居','鄭穀','唐','御定全唐诗','yuding','','[]','令節爭歡我獨閑，荒台盡日向晴山。渾無酒泛金英菊，',40,'御定全唐詩/json/676.json','["令節爭歡我獨閑，荒台盡日向晴山。渾無酒泛金英菊，", "羨君官重多吟興，醉帶南陂落照還。"]'),
('yuding-49','春夕伴同年禮部趙員外省直','鄭穀','唐','御定全唐诗','yuding','','[]','錦帳名郎重錦科，清宵寓直縱吟哦。冰含玉鏡春寒在，',40,'御定全唐詩/json/676.json','["錦帳名郎重錦科，清宵寓直縱吟哦。冰含玉鏡春寒在，", "流鶯百囀和殘漏，猶把芳樽藉露莎。"]'),
('yuding-50','倦客','鄭穀','唐','御定全唐诗','yuding','','[]','十年五年岐路中，千里萬里西複東。匹馬愁沖晚村雪，',40,'御定全唐詩/json/676.json','["十年五年岐路中，千里萬里西複東。匹馬愁沖晚村雪，", "閑烹蘆筍炊菰米，會向源鄉作醉翁。"]'),
('yuding-51','溫處士能畫鷺鶿以四韻換之','鄭穀','唐','御定全唐诗','yuding','','[]','昔年吟醉繞江蘺，愛把漁竿伴鷺鶿。聞說小毫能縱逸，',40,'御定全唐詩/json/676.json','["昔年吟醉繞江蘺，愛把漁竿伴鷺鶿。聞說小毫能縱逸，", "得向曉窗閑掛玩，雪蓑煙艇恨無遺。"]'),
('yuding-52','駕部鄭郎中三十八丈尹貳東周榮加金紫穀以末派…因賀送','鄭穀','唐','御定全唐诗','yuding','','[]','香浮玉陛曉辭天，袍拂蒲茸稱少年。郎署轉曹雖久次，',40,'御定全唐詩/json/676.json','["香浮玉陛曉辭天，袍拂蒲茸稱少年。郎署轉曹雖久次，", "今日龍門看松雪，探春明日向平泉。"]'),
('yuding-53','欹枕','鄭穀','唐','御定全唐诗','yuding','','[]','欹枕高眠日午春，酒酣睡足最閑身。',32,'御定全唐詩/json/676.json','["欹枕高眠日午春，酒酣睡足最閑身。", "明朝會得窮通理，未必輸他馬上人。"]'),
('yuding-54','野步','鄭穀','唐','御定全唐诗','yuding','','[]','翠嵐迎步興何長，笑領漁翁入醉鄉。',32,'御定全唐詩/json/676.json','["翠嵐迎步興何長，笑領漁翁入醉鄉。", "日暮渚田微雨後，鷺鶿閒暇稻花香。"]'),
('yuding-55','偶書','鄭谷','唐','御定全唐诗','yuding','','[]','承時偷喜負明神，務實那能得庇身。',32,'御定全唐詩/json/676.json','["承時偷喜負明神，務實那能得庇身。", "不會蒼蒼主何事，忍饑多是力耕人。"]'),
('yuding-56','靜吟','鄭穀','唐','御定全唐诗','yuding','','[]','騷雅荒涼我未安，月和餘雪夜吟寒。',32,'御定全唐詩/json/676.json','["騷雅荒涼我未安，月和餘雪夜吟寒。", "相門相客應相笑，得句勝於得好官。"]'),
('yuding-57','和知己秋日傷懷','鄭穀','唐','御定全唐诗','yuding','','[]','流水歌聲共不回，去年天氣舊亭台。',32,'御定全唐詩/json/676.json','["流水歌聲共不回，去年天氣舊亭台。", "梁塵寂寞燕歸去，黃蜀葵花一朵開。"]'),
('yuding-58','穀比歲受同年丈人故川守李侍郎教諭衰晏龍鍾益用…自貽','鄭穀','唐','御定全唐诗','yuding','','[]','多感京河李丈人，童蒙受教便書紳。文章至竟無功業，',40,'御定全唐詩/json/676.json','["多感京河李丈人，童蒙受教便書紳。文章至竟無功業，", "孤單所得皆逾分，歸種敷溪一畝春。"]'),
('yuding-59','郊墅','鄭谷','唐','御定全唐诗','yuding','','[]','韋曲樊川雨半晴，竹莊花院遍題名。畫成煙景垂楊色，',40,'御定全唐詩/json/676.json','["韋曲樊川雨半晴，竹莊花院遍題名。畫成煙景垂楊色，", "渼陂水色澄於鏡，何必滄浪始濯纓。"]'),
('yuding-60','舟行','鄭穀','唐','御定全唐诗','yuding','','[]','九派迢迢九月殘，舟人相語且相寬。村逢好處嫌風便，',40,'御定全唐詩/json/676.json','["九派迢迢九月殘，舟人相語且相寬。村逢好處嫌風便，", "季鷹可是思鱸鱠，引退知時自古難。"]'),
('yuding-61','奔問三峰寓止近墅','鄭穀','唐','御定全唐诗','yuding','','[]','半年奔走頗驚魂，來謁行宮淚眼昏。鴛鷺入朝同待漏，',40,'御定全唐詩/json/676.json','["半年奔走頗驚魂，來謁行宮淚眼昏。鴛鷺入朝同待漏，", "兵革未休無異術，不知何以受君恩。"]'),
('yuding-62','朝直','鄭穀','唐','御定全唐诗','yuding','','[]','朝直叨居省閣間，由來疏退校安閒。落花夜靜宮中漏，',40,'御定全唐詩/json/676.json','["朝直叨居省閣間，由來疏退校安閒。落花夜靜宮中漏，", "孤峰未得深歸去，名畫偏求水墨山。"]'),
('yuding-63','巴江','鄭穀','唐','御定全唐诗','yuding','','[]','亂來奔走巴江濱，愁客多於江徼人。朝醉暮醉雪開霽，',40,'御定全唐詩/json/676.json','["亂來奔走巴江濱，愁客多於江徼人。朝醉暮醉雪開霽，", "鬢禿又驚逢獻歲，眼前渾不見交親。"]'),
('yuding-64','故許昌薛尚書能嘗為都官郎中後數歲故建州…遂賦自賀','鄭穀','唐','御定全唐诗','yuding','','[]','都官雖未是名郎，踐曆曾聞薛許昌。複有李公陪雅躅，',40,'御定全唐詩/json/676.json','["都官雖未是名郎，踐曆曾聞薛許昌。複有李公陪雅躅，", "他日節旄如可繼，不嫌曹冷在中行。"]'),
('yuding-65','訪題表兄王藻渭上別業','鄭谷','唐','御定全唐诗','yuding','','[]','桑林搖落渭川西，蓼水彌彌接稻泥。幽檻靜來漁唱遠，',40,'御定全唐詩/json/676.json','["桑林搖落渭川西，蓼水彌彌接稻泥。幽檻靜來漁唱遠，", "中表人稀離亂後，花時莫惜重相攜。"]'),
('yuding-66','題汝州從事廳','鄭谷','唐','御定全唐诗','yuding','','[]','詩人公署如山舍，只向階前便采薇。驚燕拂簾閑睡覺，',40,'御定全唐詩/json/676.json','["詩人公署如山舍，只向階前便采薇。驚燕拂簾閑睡覺，", "自說小池栽葦後，雨涼頻見鷺鶿飛。"]'),
('yuding-67','谷初忝諫垣今憲長薛公方在西閣知獎隆異以四韻代述榮感','鄭谷','唐','御定全唐诗','yuding','','[]','舊詩常得在高吟，不奈公心愛苦心。道自瑣闈言下振，',40,'御定全唐詩/json/676.json','["舊詩常得在高吟，不奈公心愛苦心。道自瑣闈言下振，", "自拂青萍知有地，齋誠旦夕望為霖。"]'),
('yuding-68','兵部盧郎中光濟借示詩集，以四韻謝之','鄭穀','唐','御定全唐诗','yuding','','[]','七子風騷尋失主，五君歌誦久無聲。調和雅樂歸時正，',40,'御定全唐詩/json/676.json','["七子風騷尋失主，五君歌誦久無聲。調和雅樂歸時正，", "葉公好尚渾疏闊，忽見真龍幾喪明。"]'),
('yuding-69','賀左省新除韋拾遺','鄭谷','唐','御定全唐诗','yuding','','[]','初升諫署是真仙，浪透桃花恰五年。垂白郎官居座末，',40,'御定全唐詩/json/676.json','["初升諫署是真仙，浪透桃花恰五年。垂白郎官居座末，", "從此追飛何處去，金鸞殿與玉堂連。"]'),
('yuding-70','右省張補闕茂樞同在諫垣連居光德新春賦詠聊以寄懷','鄭谷','唐','御定全唐诗','yuding','','[]','小梅零落雪欺殘，浩蕩窮愁豈易寬。唯有朗吟償晚景，',40,'御定全唐詩/json/676.json','["小梅零落雪欺殘，浩蕩窮愁豈易寬。唯有朗吟償晚景，", "十五年前諳苦節，知心不獨為同官。"]'),
('yuding-71','右省補闕張茂樞同在諫垣鄰居光德迭和篇什…因抒酬寄','鄭谷','唐','御定全唐诗','yuding','','[]','何宋清名動粉闈，不才今日偶陳詩。考功豈敢聞題品，',40,'御定全唐詩/json/676.json','["何宋清名動粉闈，不才今日偶陳詩。考功豈敢聞題品，", "紫垣名士推揚切，為話心孤倍感知。"]'),
('yuding-72','寄職方李員外','鄭谷','唐','御定全唐诗','yuding','','[]','曾袖篇章謁長卿，今來附鳳事何榮。星臨南省陪仙步，',40,'御定全唐詩/json/676.json','["曾袖篇章謁長卿，今來附鳳事何榮。星臨南省陪仙步，", "龍墀仗下天街暖，共看圭峰並馬行。"]'),
('yuding-73','寄題詩僧秀公','鄭谷','唐','御定全唐诗','yuding','','[]','靈一心傳清塞心，可公吟後楚公吟。近來雅道相親少，',40,'御定全唐詩/json/676.json','["靈一心傳清塞心，可公吟後楚公吟。近來雅道相親少，", "冷曹孤宦甘寥落，多謝攜筇數訪尋。"]'),
('yuding-74','東蜀春晚','鄭穀','唐','御定全唐诗','yuding','','[]','如此浮生更別離，可堪長慟送春歸。',32,'御定全唐詩/json/676.json','["如此浮生更別離，可堪長慟送春歸。", "潼江水上楊花雪，剛逐孤舟繚繞飛。"]'),
('yuding-75','永日有懷','鄭穀','唐','御定全唐诗','yuding','','[]','能消永日是摴蒱，坑塹由來似宦途。',32,'御定全唐詩/json/676.json','["能消永日是摴蒱，坑塹由來似宦途。", "兩擲未終楗橛內，座中何惜為呼盧。"]'),
('yuding-76','槐花','鄭穀','唐','御定全唐诗','yuding','','[]','毿毿金蕊撲晴空，舉子魂驚落照中。',32,'御定全唐詩/json/676.json','["毿毿金蕊撲晴空，舉子魂驚落照中。", "今日老郎猶有恨，昔年相虐十秋風。"]'),
('yuding-77','小桃','鄭穀','唐','御定全唐诗','yuding','','[]','和煙和雨遮敷水，映竹映村連灞橋。',32,'御定全唐詩/json/676.json','["和煙和雨遮敷水，映竹映村連灞橋。", "撩亂春風耐寒令，到頭贏得杏花嬌。"]'),
('yuding-78','長江縣經賈島墓','鄭谷','唐','御定全唐诗','yuding','','[]','水繞荒墳縣路斜，耕人訝我久咨嗟。',32,'御定全唐詩/json/676.json','["水繞荒墳縣路斜，耕人訝我久咨嗟。", "重來兼恐無尋處，落日風吹鼓子花。"]'),
('yuding-79','嘉陵','鄭谷','唐','御定全唐诗','yuding','','[]','細雨濕萋萋，人稀江日西。春愁腸已斷，不在子規啼。',24,'御定全唐詩/json/676.json','["細雨濕萋萋，人稀江日西。春愁腸已斷，不在子規啼。"]'),
('yuding-80','中秋','鄭谷','唐','御定全唐诗','yuding','','[]','清香聞曉蓮，水國雨餘天。天氣正得所，客心剛悄然。',48,'御定全唐詩/json/676.json','["清香聞曉蓮，水國雨餘天。天氣正得所，客心剛悄然。", "亂兵何日息，故老幾人全。此際難消遣，從來未學禪。"]'),
('yuding-81','朝謁','鄭穀','唐','御定全唐诗','yuding','','[]','捧日整朝簪，千官一片心。班趨黃道急，殿接紫宸深。',48,'御定全唐詩/json/676.json','["捧日整朝簪，千官一片心。班趨黃道急，殿接紫宸深。", "威鳳回香扆，新鶯囀上林。小松含瑞露，春翠易成陰。"]'),
('yuding-82','錦浦','鄭穀','唐','御定全唐诗','yuding','','[]','流落夜淒淒，春寒錦浦西。不甘花逐水，可惜雪成泥。',48,'御定全唐詩/json/676.json','["流落夜淒淒，春寒錦浦西。不甘花逐水，可惜雪成泥。", "病眼嫌燈近，離腸賴酒迷。憑君囑鵯鵊，莫向五更啼。"]'),
('yuding-83','峨嵋山','鄭谷','唐','御定全唐诗','yuding','','[]','萬仞白雲端，經春雪未殘。夏消江峽滿，晴照蜀樓寒。',48,'御定全唐詩/json/676.json','["萬仞白雲端，經春雪未殘。夏消江峽滿，晴照蜀樓寒。", "造境知僧熟，歸林認鶴難。會須朝闕去，只有畫圖看。"]'),
('yuding-84','蜀江有吊','鄭穀','唐','御定全唐诗','yuding','','[]','孟子有良策，惜哉今已而。徒將心體國，不識道消時。',48,'御定全唐詩/json/676.json','["孟子有良策，惜哉今已而。徒將心體國，不識道消時。", "折檻未為切，沈湘何足悲。蒼蒼無問處，煙雨遍江蘺。"]'),
('yuding-85','書村叟壁','鄭穀','唐','御定全唐诗','yuding','','[]','草肥朝牧牛，桑綠晚鳴鳩。列岫簷前見，清泉碓下流。',48,'御定全唐詩/json/676.json','["草肥朝牧牛，桑綠晚鳴鳩。列岫簷前見，清泉碓下流。", "春蔬和雨割，社酒向花篘。引我南陂去，籬邊有小舟。"]'),
('yuding-86','題進士王駕郊居','鄭穀','唐','御定全唐诗','yuding','','[]','前山微有雨，永巷淨無塵。牛臥籬陰晚，鳩鳴村意春。',48,'御定全唐詩/json/676.json','["前山微有雨，永巷淨無塵。牛臥籬陰晚，鳩鳴村意春。", "時浮應寡合，道在不嫌貧。後徑臨陂水，菰蒲是切鄰。"]'),
('yuding-87','題莊嚴寺休公院','鄭穀','唐','御定全唐诗','yuding','','[]','秋深庭色好，紅葉間青松。病客殘無著，吾師甚見容。',48,'御定全唐詩/json/676.json','["秋深庭色好，紅葉間青松。病客殘無著，吾師甚見容。", "疏鐘和細溜，高塔等遙峰。未省求名侶，頻於此地逢。"]'),
('yuding-88','題興善寺','鄭穀','唐','御定全唐诗','yuding','','[]','寺在帝城陰，清虛勝二林。蘚侵隋畫暗，茶助越甌深。',48,'御定全唐詩/json/676.json','["寺在帝城陰，清虛勝二林。蘚侵隋畫暗，茶助越甌深。", "巢鶴和鐘唳，詩僧倚錫吟。煙莎後池水，前跡杳難尋。"]'),
('yuding-89','宿澄泉蘭若','鄭穀','唐','御定全唐诗','yuding','','[]','山半古招提，空林雪月迷。亂流分石上，斜漢在松西。',48,'御定全唐詩/json/676.json','["山半古招提，空林雪月迷。亂流分石上，斜漢在松西。", "雲集寒庵宿，猿先曉磬啼。此心如了了，即此是曹溪。"]'),
('yuding-90','送舉子下第東歸','鄭谷','唐','御定全唐诗','yuding','','[]','夫子道何孤，青雲未得途。詩書難舍魯，山水暫游吳。',48,'御定全唐詩/json/676.json','["夫子道何孤，青雲未得途。詩書難舍魯，山水暫游吳。", "野綠梅陰重，江春浪勢粗。秣陵兵役後，舊業半成蕪。"]'),
('yuding-91','寄察院李侍禦文炬','鄭谷','唐','御定全唐诗','yuding','','[]','古柏間疏篁，清陰在印床。宿郊虔點饌，秋寺靜監香。',48,'御定全唐詩/json/676.json','["古柏間疏篁，清陰在印床。宿郊虔點饌，秋寺靜監香。", "參集行多揖，風儀見即莊。佇聞橫擘去，帷集諫書囊。"]'),
('yuding-92','偶懷寄台院孫端公棨','鄭穀','唐','御定全唐诗','yuding','','[]','才拙道仍孤，無何舍釣徒。班雖沾玉筍，香不近金爐。',48,'御定全唐詩/json/676.json','["才拙道仍孤，無何舍釣徒。班雖沾玉筍，香不近金爐。", "雨露瞻雙闕，煙波隔五湖。唯君應見念，曾共伏青蒲。"]'),
('yuding-93','次韻和秀上人游南五台','鄭穀','唐','御定全唐诗','yuding','','[]','中峰曾到處，題記沒蒼苔。振錫傳深谷，翻經想舊台。',48,'御定全唐詩/json/676.json','["中峰曾到處，題記沒蒼苔。振錫傳深谷，翻經想舊台。", "蒼松臨砌偃，驚鹿驀溪來。內殿評詩切，身回心未回。"]'),
('yuding-94','乖慵','鄭穀','唐','御定全唐诗','yuding','','[]','乖慵居竹裏，涼冷臥池東。一霎芰荷雨，幾回簾幕風。',72,'御定全唐詩/json/676.json','["乖慵居竹裏，涼冷臥池東。一霎芰荷雨，幾回簾幕風。", "遠僧來扣寂，小吏笑書空。衰鬢霜供白，愁顏酒借紅。", "扇輕搖鷺羽，屏古畫漁翁。自得無端趣，琴棋舫子中。"]'),
('yuding-95','南宮寓直','鄭穀','唐','御定全唐诗','yuding','','[]','寓直事非輕，宦孤憂且榮。制承黃紙重，詞見紫垣清。',96,'御定全唐詩/json/676.json','["寓直事非輕，宦孤憂且榮。制承黃紙重，詞見紫垣清。", "曉霽庭松色，風和禁漏聲。僧攜新茗伴，吏掃落花迎。", "鎖印詩心動，垂簾睡思生。粉廊曾試處，石柱昔賢名。", "來誤宮窗燕，啼疑苑樹鶯。殘陽應更好，歸促恨嚴城。"]'),
('yuding-96','恩門小諫雨中乞菊栽','鄭谷','唐','御定全唐诗','yuding','','[]','握蘭將滿歲，栽菊伴吟詩。老去慵趨世，朝回獨繞籬。',72,'御定全唐詩/json/676.json','["握蘭將滿歲，栽菊伴吟詩。老去慵趨世，朝回獨繞籬。", "遞香風細細，澆綠水彌彌。只共山僧賞，何當國士移。", "孤根深有托，微雨正相宜。更待金英發，憑君插一枝。"]'),
('yuding-97','荊渚八月十五夜值雨寄同年李嶼','鄭穀','唐','御定全唐诗','yuding','','[]','共待輝光夜，翻成黯澹秋。正宜清路望，潛起滴階愁。',72,'御定全唐詩/json/676.json','["共待輝光夜，翻成黯澹秋。正宜清路望，潛起滴階愁。", "棹倚袁宏渚，簾垂庾亮樓。桂無香實落，蘭有露花休。", "玉漏添蕭索，金尊阻獻酬。明年佳景在，相約向神州。"]'),
('yuding-98','寄左省張起居','鄭穀','唐','御定全唐诗','yuding','','[]','含香複記言，清秩稱當年。點筆非常筆，朝天最近天。',120,'御定全唐詩/json/676.json','["含香複記言，清秩稱當年。點筆非常筆，朝天最近天。", "家聲三相後，公事一人前。詩句江郎伏，書蹤寧氏傳。", "風標欺鷺鶴，才力湧沙泉。居僻貧無慮，名高退更堅。", "漁舟思靜泛，僧榻寄閑眠。消息當彌入，絲綸的粲然。", "依棲常接跡，屬和舊盈編。開口人皆信，淒涼是謝氈。"]'),
('yuding-99','前寄左省張起居一百言尋蒙唱酬見譽過實卻用舊韻重答','鄭穀','唐','御定全唐诗','yuding','','[]','減瘦經多難，憂傷集晚年。吟高風過樹，坐久夜涼天。',120,'御定全唐詩/json/676.json','["減瘦經多難，憂傷集晚年。吟高風過樹，坐久夜涼天。", "旅退慚隨眾，孤飛怯向前。釣朋蓑叟在，藥術衲僧傳。", "鬢禿趨榮路，腸焦鄙盜泉。品徒誠有隔，推唱意何堅。", "寒地殊知感，秋燈耿不眠。從來甘默爾，自此倍怡然。", "蘭為官須握，蒲因學更編。預愁搖落後，子美笑無氈。"]'),
('yuding-100','讀故許昌薛尚書詩集','鄭穀','唐','御定全唐诗','yuding','','[]','篇篇高且真，真為國風陳。澹薄雖師古，縱橫得意新。',120,'御定全唐詩/json/676.json','["篇篇高且真，真為國風陳。澹薄雖師古，縱橫得意新。", "翦裁成幾篋，唱和是誰人。華岳題無敵，黃河句絕倫。", "吟殘荔枝雨，詠徹海棠春。李白欺前輩，陶潛仰後塵。", "難忘嵩室下，不負蜀江濱。屬思看山眼，冥搜倚樹身。", "楷模勞夢想，諷誦爽精神。落筆空追愴，曾蒙借斧斤。"]'),
('yuding-0','送水部張郎中彥回宰洛陽','鄭谷','唐','御定全唐诗','yuding','','[]','何遜蘭休握，陶潛柳正垂。官清真塞詔，事簡好吟詩。',48,'御定全唐詩/json/677.json','["何遜蘭休握，陶潛柳正垂。官清真塞詔，事簡好吟詩。", "春漏懷丹闕，涼船泛碧伊。已虛西閣位，朝夕鳳書追。"]'),
('yuding-1','贈咸陽王主簿','鄭穀','唐','御定全唐诗','yuding','','[]','可愛咸陽王主簿，窮經盡到昔賢心。登科未足酬多學，',40,'御定全唐詩/json/677.json','["可愛咸陽王主簿，窮經盡到昔賢心。登科未足酬多學，", "我來賒酒相留宿，聽我披衣看雪吟。"]'),
('yuding-2','松','鄭穀','唐','御定全唐诗','yuding','','[]','下視垂楊拂路塵，雙峰石上覆苔文。濃霜滿徑無紅葉，',40,'御定全唐詩/json/677.json','["下視垂楊拂路塵，雙峰石上覆苔文。濃霜滿徑無紅葉，", "那堪寂寞悲風起，千樹深藏李白墳。"]'),
('yuding-3','梅','鄭谷','唐','御定全唐诗','yuding','','[]','江國正寒春信穩，嶺頭枝上雪飄飄。何言落處堪惆悵，',40,'御定全唐詩/json/677.json','["江國正寒春信穩，嶺頭枝上雪飄飄。何言落處堪惆悵，", "離人南去腸應斷，片片隨鞭過楚橋。"]'),
('yuding-4','鶴','鄭穀','唐','御定全唐诗','yuding','','[]','一自王喬放自由，俗人行處懶回頭。睡輕旋覺松花墮，',40,'御定全唐詩/json/677.json','["一自王喬放自由，俗人行處懶回頭。睡輕旋覺松花墮，", "應嫌白鷺無仙骨，長伴漁翁宿葦洲。"]'),
('yuding-5','重陽夜旅懷','鄭谷','唐','御定全唐诗','yuding','','[]','強插黃花三兩枝，還圖一醉浸愁眉。',32,'御定全唐詩/json/677.json','["強插黃花三兩枝，還圖一醉浸愁眉。", "半床斜月醉醒後，惆悵多於未醉時。"]'),
('yuding-6','壬戌西幸後','鄭谷','唐','御定全唐诗','yuding','','[]','武德門前顥氣新，雪融鴛瓦土膏春。',32,'御定全唐詩/json/677.json','["武德門前顥氣新，雪融鴛瓦土膏春。", "夜來夢到宣麻處，草沒龍墀不見人。"]'),
('yuding-7','多虞','鄭谷','唐','御定全唐诗','yuding','','[]','多虞難住人稀處，近耗渾無戰罷棋。',32,'御定全唐詩/json/677.json','["多虞難住人稀處，近耗渾無戰罷棋。", "向闕歸山俱未得，且沽春酒且吟詩。"]'),
('yuding-8','短褐','鄭穀','唐','御定全唐诗','yuding','','[]','閑披短褐杖山藤，頭不是僧心是僧。',32,'御定全唐詩/json/677.json','["閑披短褐杖山藤，頭不是僧心是僧。", "坐睡覺來清夜半，芭蕉影動道場燈。"]'),
('yuding-9','曲江紅杏','鄭谷','唐','御定全唐诗','yuding','','[]','遮莫江頭柳色遮，日濃鶯睡一枝斜。',32,'御定全唐詩/json/677.json','["遮莫江頭柳色遮，日濃鶯睡一枝斜。", "女郎折得殷勤看，道是春風及第花。"]'),
('yuding-10','折得梅','鄭谷','唐','御定全唐诗','yuding','','[]','寒步江村折得梅，孤香不肯待春催。',32,'御定全唐詩/json/677.json','["寒步江村折得梅，孤香不肯待春催。", "滿枝儘是愁人淚，莫殢朝來露濕來。"]'),
('yuding-11','牡丹','鄭穀','唐','御定全唐诗','yuding','','[]','畫堂簾卷張清宴，含香帶霧情無限。',32,'御定全唐詩/json/677.json','["畫堂簾卷張清宴，含香帶霧情無限。", "春風愛惜未放開，柘枝鼓振紅英綻。"]'),
('yuding-12','寂寞','鄭谷','唐','御定全唐诗','yuding','','[]','江郡人稀便是村，踏青天氣欲黃昏。',32,'御定全唐詩/json/677.json','["江郡人稀便是村，踏青天氣欲黃昏。", "春愁不破還成醉，衣上淚痕和酒痕。"]'),
('yuding-13','亂後灞上','鄭谷','唐','御定全唐诗','yuding','','[]','柳絲牽水杏房紅，煙岸人稀草色中。',32,'御定全唐詩/json/677.json','["柳絲牽水杏房紅，煙岸人稀草色中。", "日暮一行高鳥處，依稀合是望春宮。"]'),
('yuding-14','長門怨二首','鄭穀','唐','御定全唐诗','yuding','','[]','閑把羅衣泣鳳凰，先朝曾教舞霓裳。',64,'御定全唐詩/json/677.json','["閑把羅衣泣鳳凰，先朝曾教舞霓裳。", "春來卻羨庭花落，得逐晴風出禁牆。", "流水君恩共不回，杏花爭忍掃成堆。", "殘春未必多煙雨，淚滴閑階長綠苔。"]'),
('yuding-15','郊野戲題','鄭穀','唐','御定全唐诗','yuding','','[]','竹巷溪橋天氣涼，荷開稻熟村酒香。',32,'御定全唐詩/json/677.json','["竹巷溪橋天氣涼，荷開稻熟村酒香。", "唯憂野叟相回避，莫道儂家是漢郎。"]'),
('yuding-16','宗人惠四藥','鄭谷','唐','御定全唐诗','yuding','','[]','宗人忽惠西山藥，四味清新香助茶。',32,'御定全唐詩/json/677.json','["宗人忽惠西山藥，四味清新香助茶。", "爽得心神便騎鶴，何須燒得白朱砂。"]'),
('yuding-17','題張衡廟','鄭穀','唐','御定全唐诗','yuding','','[]','遠俗只憑淫祀切，多年平子固悠悠。',32,'御定全唐詩/json/677.json','["遠俗只憑淫祀切，多年平子固悠悠。", "江煙日午無簫鼓，直到如今詠四愁。"]'),
('yuding-18','山鳥','鄭穀','唐','御定全唐诗','yuding','','[]','驚飛失勢粉牆高，好個聲音好羽毛。',32,'御定全唐詩/json/677.json','["驚飛失勢粉牆高，好個聲音好羽毛。", "小婢不須催柘彈，且從枝上吃櫻桃。"]'),
('yuding-19','黯然','鄭穀','唐','御定全唐诗','yuding','','[]','搢紳奔避複淪亡，消息春來到水鄉。',32,'御定全唐詩/json/677.json','["搢紳奔避複淪亡，消息春來到水鄉。", "屈指故人能幾許，月明花好更悲涼。"]'),
('yuding-20','借薛尚書集','鄭穀','唐','御定全唐诗','yuding','','[]','江天冬暖似花時，上國音塵杳未知。',32,'御定全唐詩/json/677.json','["江天冬暖似花時，上國音塵杳未知。", "正被蟲聲喧老耳，今君又借薛能詩。"]'),
('yuding-21','小北廳閑題','鄭谷','唐','御定全唐诗','yuding','','[]','冷曹孤宦本相宜，山在牆南落照時。',32,'御定全唐詩/json/677.json','["冷曹孤宦本相宜，山在牆南落照時。", "洗竹澆莎足公事，一來贏寫一聯詩。"]'),
('yuding-22','菊','鄭穀','唐','御定全唐诗','yuding','','[]','日日池邊載酒行，黃昏猶自繞黃英。',32,'御定全唐詩/json/677.json','["日日池邊載酒行，黃昏猶自繞黃英。", "重陽過後頻來此，甚覺多情勝薄情。"]'),
('yuding-23','贈楊夔二首','鄭穀','唐','御定全唐诗','yuding','','[]','散賦冗書高且奇，百篇仍有百篇詩。',64,'御定全唐詩/json/677.json','["散賦冗書高且奇，百篇仍有百篇詩。", "江湖休灑春風淚，十軸香于一桂枝。", "時無韓柳道難窮，也覺天公不至公。", "看取年年金榜上，幾人才氣似揚雄。"]'),
('yuding-0','中秋夜有懷','許彬','唐','御定全唐诗','yuding','','[]','趨馳早晚休，一歲又殘秋。若只如今日，何難致白頭。',48,'御定全唐詩/json/678.json','["趨馳早晚休，一歲又殘秋。若只如今日，何難致白頭。", "滄波歸處遠，旅舍向邊愁。賴見前賢說，窮通不自由。"]'),
('yuding-1','尋白石山人澗','許彬','唐','御定全唐诗','yuding','','[]','路窮川島上，果值古仙家。陰洞長鳴磬，石泉寒泛花。',48,'御定全唐詩/json/678.json','["路窮川島上，果值古仙家。陰洞長鳴磬，石泉寒泛花。", "莓苔深峭壁，煙靄積層崖。難見囊中術，人間有歲華。"]'),
('yuding-2','遊頭陀寺上方','許彬','唐','御定全唐诗','yuding','','[]','高步陟崔嵬，吟閑路惜回。寺從何代有，僧是梵宮來。',48,'御定全唐詩/json/678.json','["高步陟崔嵬，吟閑路惜回。寺從何代有，僧是梵宮來。", "暮靄連沙積，餘霞逼檻開。更期招靜者，長嘯上方台。"]'),
('yuding-3','歸山夜發湖中','許彬','唐','御定全唐诗','yuding','','[]','廣澤去無邊，夜程風信偏。疏星遙抵浪，遠燒似迎船。',48,'御定全唐詩/json/678.json','["廣澤去無邊，夜程風信偏。疏星遙抵浪，遠燒似迎船。", "響嶽猿相次，翻空雁接連。北歸家業就，深處更逾年。"]'),
('yuding-4','同友人會裴明府縣樓','許彬','唐','御定全唐诗','yuding','','[]','開閣雨吹塵，陶家揖上賓。湖山萬疊翠，汀樹一行春。',48,'御定全唐詩/json/678.json','["開閣雨吹塵，陶家揖上賓。湖山萬疊翠，汀樹一行春。", "景逼歸簷燕，歌喧已醉身。登臨興未足，喜有數年因。"]'),
('yuding-5','荊山夜泊與親友遇','許彬','唐','御定全唐诗','yuding','','[]','山海兩分歧，停舟偶此期。別來何限意，相見卻無詞。',48,'御定全唐詩/json/678.json','["山海兩分歧，停舟偶此期。別來何限意，相見卻無詞。", "坐永神疑夢，愁多鬢欲絲。趨名易遲晚，此去莫經時。"]'),
('yuding-6','北遊夜懷','許彬','唐','御定全唐诗','yuding','','[]','苦心終是否，舍此複無營。已致歸成晚，非緣去有程。',48,'御定全唐詩/json/678.json','["苦心終是否，舍此複無營。已致歸成晚，非緣去有程。", "館空吟向月，霜曙坐聞更。住久誰相問，馳羸又獨行。"]'),
('yuding-7','重經漢南','許彬','唐','御定全唐诗','yuding','','[]','分散多如此，人情豈自由。重來看月夕，不似去年秋。',48,'御定全唐詩/json/678.json','["分散多如此，人情豈自由。重來看月夕，不似去年秋。", "息慮雖孤寢，論空未識愁。須同醉鄉者，萬事付江流。"]'),
('yuding-8','湘江','許彬','唐','御定全唐诗','yuding','','[]','孤舟方此去，嘉景稱于聞。煙盡九峰雪，雨生諸派雲。',48,'御定全唐詩/json/678.json','["孤舟方此去，嘉景稱于聞。煙盡九峰雪，雨生諸派雲。", "沙寒鴻鵠聚，底極龜魚分。異日誰為侶，逍遙耕釣群。"]'),
('yuding-9','黔中書事','許彬','唐','御定全唐诗','yuding','','[]','巴蜀水南偏，山窮塞壘寬。歲時將近臘，草樹未知寒。',48,'御定全唐詩/json/678.json','["巴蜀水南偏，山窮塞壘寬。歲時將近臘，草樹未知寒。", "獨狖啼朝雨，群牛向暮灘。更聞蠻俗近，烽火不艱難。"]'),
('yuding-10','經李翰林廬山屏風疊所居','許彬','唐','御定全唐诗','yuding','','[]','放逐非多罪，江湖偶不回。深居應有謂，濟代豈無才。',48,'御定全唐詩/json/678.json','["放逐非多罪，江湖偶不回。深居應有謂，濟代豈無才。", "疊巘晴舒障，寒川暗動雷。誰能續高興，醉死一千杯。"]'),
('yuding-11','酬簡寂熊尊師以趙員外廬山草堂見借','許彬','唐','御定全唐诗','yuding','','[]','豈易投居止，廬山得此峰。主人曾已許，仙客偶相逢。',48,'御定全唐詩/json/678.json','["豈易投居止，廬山得此峰。主人曾已許，仙客偶相逢。", "顧己恩難答，窮經業未慵。還能勵僮僕，稍更補杉松。"]'),
('yuding-12','寄懷孫處士','許彬','唐','御定全唐诗','yuding','','[]','生平酌與吟，誰是見君心。上國一歸去，滄波閑至今。',48,'御定全唐詩/json/678.json','["生平酌與吟，誰是見君心。上國一歸去，滄波閑至今。", "鐘繁秋寺遠，岸闊晚濤深。疏放長如此，何人更得尋。"]'),
('yuding-13','漢南懷友人','許彬','唐','御定全唐诗','yuding','','[]','此身西複東，何計此相逢。夢盡吳越水，恨深湘漢鐘。',48,'御定全唐詩/json/678.json','["此身西複東，何計此相逢。夢盡吳越水，恨深湘漢鐘。", "積雲開去路，曙雪疊前峰。誰即知非舊，憐君忽見容。"]'),
('yuding-14','送人下第歸江州','許彬','唐','御定全唐诗','yuding','','[]','名高不俟召，操賦獻君門。偶屈應緣數，他人盡為冤。',48,'御定全唐詩/json/678.json','["名高不俟召，操賦獻君門。偶屈應緣數，他人盡為冤。", "新春城外路，舊隱水邊村。歸去無勞久，知音待更論。"]'),
('yuding-15','送蘇處士歸西山','許彬','唐','御定全唐诗','yuding','','[]','南游何所為，一篋又空歸。守道安清世，無心換白衣。',48,'御定全唐詩/json/678.json','["南游何所為，一篋又空歸。守道安清世，無心換白衣。", "深溪猿共暮，絕頂客來稀。早晚還相見，論詩更及微。"]'),
('yuding-16','送李處士歸山','許彬','唐','御定全唐诗','yuding','','[]','舊山來複去，不與世人論。得道書留篋，忘機酒滿尊。',48,'御定全唐詩/json/678.json','["舊山來複去，不與世人論。得道書留篋，忘機酒滿尊。", "溪軒松偃坐，石室水臨門。應有頻相訪，相看坐到昏。"]'),
('yuding-17','送新羅客歸','許彬','唐','御定全唐诗','yuding','','[]','君家滄海外，一別見何因。風土難知教，程途自致貧。',48,'御定全唐詩/json/678.json','["君家滄海外，一別見何因。風土難知教，程途自致貧。", "浸天波色晚，橫吹鳥行春。明發千檣下，應為更遠人。"]'),
('yuding-18','府試萊城晴日望三山','許彬','唐','御定全唐诗','yuding','','[]','不易識蓬瀛，憑高望有程。盤根出巨浸，遠色到孤城。',72,'御定全唐詩/json/678.json','["不易識蓬瀛，憑高望有程。盤根出巨浸，遠色到孤城。", "隱隱排雲峻，層層就日明。淨收殘靄盡，浮動嫩嵐輕。", "縱目徒多暇，馳心累發誠。從容更何往，此路徹三清。"]'),
('yuding-19','題故李賓客廬山草堂','許彬','唐','御定全唐诗','yuding','','[]','難窮林下趣，坐使致君恩。術業行當代，封章動諫垣。',72,'御定全唐詩/json/678.json','["難窮林下趣，坐使致君恩。術業行當代，封章動諫垣。", "已明邪佞跡，幾雪薜蘿冤。報主深知此，憂民詎可論。", "名將山共古，跡與道俱存。為謝重來者，何人更及門。"]'),
('yuding-0','秋夕送友人歸吳','崔塗','唐','御定全唐诗','yuding','','[]','離心醉豈歡，把酒強相寬。世路須求達，還家亦未安。',48,'御定全唐詩/json/679.json','["離心醉豈歡，把酒強相寬。世路須求達，還家亦未安。", "旅程愁算遠，江月坐吟殘。莫羨扁舟興，功成去不難。"]'),
('yuding-1','長安逢江南僧','崔塗','唐','御定全唐诗','yuding','','[]','孤雲無定蹤，忽到又相逢。說盡天涯事，聽殘上國鐘。',48,'御定全唐詩/json/679.json','["孤雲無定蹤，忽到又相逢。說盡天涯事，聽殘上國鐘。", "問人尋寺僻，乞食過街慵。憶到曾棲處，開門對數峰。"]'),
('yuding-2','晚次修路僧','崔塗','唐','御定全唐诗','yuding','','[]','平盡不平處，尚嫌功未深。應難將世路，便得稱師心。',48,'御定全唐詩/json/679.json','["平盡不平處，尚嫌功未深。應難將世路，便得稱師心。", "高鳥下殘照，白煙生遠林。更聞清磬發，聊喜緩塵襟。"]'),
('yuding-3','湖外送友人游邊','崔塗','唐','御定全唐诗','yuding','','[]','我泛瀟湘浦，君行指塞雲。兩鄉天外隔，一徑渡頭分。',48,'御定全唐詩/json/679.json','["我泛瀟湘浦，君行指塞雲。兩鄉天外隔，一徑渡頭分。", "雨暗江花老，笳愁隴月曛。不堪來去雁，迢遞思離群。"]'),
('yuding-4','讀段太尉碑','崔塗','唐','御定全唐诗','yuding','','[]','憤激計潛成，臨危豈顧生。只空持一笏，便欲碎長鯨。',48,'御定全唐詩/json/679.json','["憤激計潛成，臨危豈顧生。只空持一笏，便欲碎長鯨。", "國已酬徽烈，家猶聳義聲。不知青史上，誰可計功名。"]'),
('yuding-5','夕次洛陽道中','崔塗','唐','御定全唐诗','yuding','','[]','秋風吹故城，城下獨吟行。高樹鳥已息，古原人尚耕。',48,'御定全唐詩/json/679.json','["秋風吹故城，城下獨吟行。高樹鳥已息，古原人尚耕。", "流年川暗度，往事月空明。不復歎岐路，馬前塵夜生。"]'),
('yuding-6','讀方幹詩因懷別業','崔塗','唐','御定全唐诗','yuding','','[]','把君詩一吟，萬里見君心。華髮新知少，滄洲舊隱深。',48,'御定全唐詩/json/679.json','["把君詩一吟，萬里見君心。華髮新知少，滄洲舊隱深。", "潮沖虛閣上，山入暮窗沈。憶宿高齋夜，庭枝識海禽。"]'),
('yuding-7','題嵩陽隱者','崔塗','唐','御定全唐诗','yuding','','[]','四十年高夢，生涯指一丘。無人同久住，有鶴對冥修。',48,'御定全唐詩/json/679.json','["四十年高夢，生涯指一丘。無人同久住，有鶴對冥修。", "草雜芝田出，泉和石髓流。更嫌庭樹老，疑是世間秋。"]'),
('yuding-8','友人問卜見招','崔塗','唐','御定全唐诗','yuding','','[]','何必問蓍龜，行藏自可期。但逢公道日，即是命通時。',48,'御定全唐詩/json/679.json','["何必問蓍龜，行藏自可期。但逢公道日，即是命通時。", "樂善知無厭，操心幸不欺。豈能花下淚，長似去年垂。"]'),
('yuding-9','江行晚望','崔塗','唐','御定全唐诗','yuding','','[]','木落曙江晴，寒郊極望平。孤舟三楚去，萬里獨吟行。',48,'御定全唐詩/json/679.json','["木落曙江晴，寒郊極望平。孤舟三楚去，萬里獨吟行。", "鳥占橫查立，人當故里耕。十年來複去，不覺二毛生。"]'),
('yuding-10','巫山廟','崔塗','唐','御定全唐诗','yuding','','[]','雙黛儼如嚬，應傷故國春。江山非舊主，雲雨是前身。',48,'御定全唐詩/json/679.json','["雙黛儼如嚬，應傷故國春。江山非舊主，雲雨是前身。", "夢覺傳詞客，靈猶福楚人。不知千載後，何處又為神。"]'),
('yuding-11','秋夕與友人話別','崔塗','唐','御定全唐诗','yuding','','[]','懷君非一夕，此夕倍堪悲。華髮猶漂泊，滄洲又別離。',48,'御定全唐詩/json/679.json','["懷君非一夕，此夕倍堪悲。華髮猶漂泊，滄洲又別離。", "冷禽棲不定，衰葉墮無時。況值干戈隔，相逢未可期。"]'),
('yuding-12','與友人同懷江南別業','崔塗','唐','御定全唐诗','yuding','','[]','因君話故國，此夕倍依依。舊業臨秋水，何人在釣磯。',48,'御定全唐詩/json/679.json','["因君話故國，此夕倍依依。舊業臨秋水，何人在釣磯。", "浮名如縱得，滄海亦終歸。卻是風塵裏，如何便息機。"]'),
('yuding-13','苦吟','崔塗','唐','御定全唐诗','yuding','','[]','朝吟複暮吟，只此望知音。舉世輕孤立，何人念苦心。',48,'御定全唐詩/json/679.json','["朝吟複暮吟，只此望知音。舉世輕孤立，何人念苦心。", "他鄉無舊識，落日羨歸禽。況住寒江上，漁家似故林。"]'),
('yuding-14','春日郊居酬友人見貽','崔塗','唐','御定全唐诗','yuding','','[]','荒齋原上掩，不出動經旬。忽覺草木變，始知天地春。',48,'御定全唐詩/json/679.json','["荒齋原上掩，不出動經旬。忽覺草木變，始知天地春。", "方期五字達，未厭一簞貧。麗句勞相勉，余非樂釣綸。"]'),
('yuding-15','問卜','崔塗','唐','御定全唐诗','yuding','','[]','承家望一名，幾欲問君平。自小非無志，何年即有成。',48,'御定全唐詩/json/679.json','["承家望一名，幾欲問君平。自小非無志，何年即有成。", "豈能長失路，爭忍學歸耕。不擬逢昭代，悠悠過此生。"]'),
('yuding-16','蜀城春','崔塗','唐','御定全唐诗','yuding','','[]','天涯憔悴身，一望一沾巾。在處有芳草，滿城無故人。',48,'御定全唐詩/json/679.json','["天涯憔悴身，一望一沾巾。在處有芳草，滿城無故人。", "懷才皆得路，失計自傷春。清鏡不能照，鬢毛愁更新。"]'),
('yuding-17','送道士于千齡游南嶽','崔塗','唐','御定全唐诗','yuding','','[]','物外與誰期，人間又別離。四方多事日，高岳獨游時。',48,'御定全唐詩/json/679.json','["物外與誰期，人間又別離。四方多事日，高岳獨游時。", "猿狖瀟湘樹，煙波屈宋祠。無因陪此去，空惜鬢將衰。"]'),
('yuding-18','入蜀赴舉秋夜與先生話別','崔塗','唐','御定全唐诗','yuding','','[]','欲愴峨嵋別，中宵寢不能。聽殘池上雨，吟盡枕前燈。',48,'御定全唐詩/json/679.json','["欲愴峨嵋別，中宵寢不能。聽殘池上雨，吟盡枕前燈。", "失計方期隱，修心未到僧。雲門一萬里，應笑又擔簦。"]'),
('yuding-19','春晚懷進士韋澹','崔塗','唐','御定全唐诗','yuding','','[]','故里花應盡，江樓夢尚殘。半生吟欲過，一命達何難。',48,'御定全唐詩/json/679.json','["故里花應盡，江樓夢尚殘。半生吟欲過，一命達何難。", "特立珪無玷，相思草有蘭。二年春悵望，不似在長安。"]'),
('yuding-20','言懷','崔塗','唐','御定全唐诗','yuding','','[]','幹時雖苦節，趨世且無機。及覺知音少，翻疑所業非。',48,'御定全唐詩/json/679.json','["幹時雖苦節，趨世且無機。及覺知音少，翻疑所業非。", "青雲如不到，白首亦難歸。所以滄江上，年年別釣磯。"]'),
('yuding-21','秋夜興上人別','崔塗','唐','御定全唐诗','yuding','','[]','常時豈不別，此別異常情。南國初聞雁，中原未息兵。',48,'御定全唐詩/json/679.json','["常時豈不別，此別異常情。南國初聞雁，中原未息兵。", "暗蛩侵語歇，疏磬入吟清。曾聽無生說，辭師話此行。"]'),
('yuding-22','感花','崔塗','唐','御定全唐诗','yuding','','[]','繡軛香韉夜不歸，少年爭惜最紅枝。',32,'御定全唐詩/json/679.json','["繡軛香韉夜不歸，少年爭惜最紅枝。", "東風一陣黃昏雨，又到繁華夢覺時。"]'),
('yuding-23','秋宿天彭僧舍','崔塗','唐','御定全唐诗','yuding','','[]','身世兩相惜，秋雲每獨興。難將塵界事，話向雪山僧。',48,'御定全唐詩/json/679.json','["身世兩相惜，秋雲每獨興。難將塵界事，話向雪山僧。", "力善知誰許，歸耕又未能。此懷平不得，挑盡草堂燈。"]'),
('yuding-24','秋夜僧舍聞猿','崔塗','唐','御定全唐诗','yuding','','[]','哀猿聽未休，禪景夜方幽。暫得同僧靜，那能免客愁。',48,'御定全唐詩/json/679.json','["哀猿聽未休，禪景夜方幽。暫得同僧靜，那能免客愁。", "影搖雲外樹，聲褭月中秋。曾向巴江宿，當時淚亦流。"]'),
('yuding-25','過昭君故宅','崔塗','唐','御定全唐诗','yuding','','[]','以色靜胡塵，名還異眾嬪。免勞征戰力，無愧綺羅身。',48,'御定全唐詩/json/679.json','["以色靜胡塵，名還異眾嬪。免勞征戰力，無愧綺羅身。", "骨竟埋青塚，魂應怨畫人。不堪逢舊宅，寥落對江濱。"]'),
('yuding-26','過洛陽故城','崔塗','唐','御定全唐诗','yuding','','[]','三十世皇都，蕭條是霸圖。片牆看破盡，遺跡漸應無。',48,'御定全唐詩/json/679.json','["三十世皇都，蕭條是霸圖。片牆看破盡，遺跡漸應無。", "野徑通荒苑，高槐映遠衢。獨吟人不問，清冷自嗚嗚。"]'),
('yuding-27','秋夕與友人同會','崔塗','唐','御定全唐诗','yuding','','[]','章句積微功，星霜二十空。僻應如我少，吟喜得君同。',48,'御定全唐詩/json/679.json','["章句積微功，星霜二十空。僻應如我少，吟喜得君同。", "月上僧歸後，詩成客夢中。更聞棲鶴警，清露滴青松。"]'),
('yuding-28','春日登吳門','崔塗','唐','御定全唐诗','yuding','','[]','故國望不見，愁襟難暫開。春潮映楊柳，細雨入樓臺。',48,'御定全唐詩/json/679.json','["故國望不見，愁襟難暫開。春潮映楊柳，細雨入樓臺。", "靜少人同到，晴逢雁正來。長安遠於日，搔首獨徘徊。"]'),
('yuding-29','湘中秋懷遷客','崔塗','唐','御定全唐诗','yuding','','[]','蘭杜曉香薄，汀洲夕露繁。並聞燕塞雁，獨立楚人村。',48,'御定全唐詩/json/679.json','["蘭杜曉香薄，汀洲夕露繁。並聞燕塞雁，獨立楚人村。", "霧散孤城上，灘回曙枕喧。不堪逢賈傅，還欲吊湘沅。"]'),
('yuding-30','南山旅舍與故人別','崔塗','唐','御定全唐诗','yuding','','[]','一日又將暮，一年看即殘。病知新事少，老別舊交難。',48,'御定全唐詩/json/679.json','["一日又將暮，一年看即殘。病知新事少，老別舊交難。", "山盡路猶險，雨餘春卻寒。那堪試回首，烽火是長安。"]'),
('yuding-31','東林願禪師院','崔塗','唐','御定全唐诗','yuding','','[]','與世漸無緣，身心獨了然。講銷林下日，臘長定中年。',48,'御定全唐詩/json/679.json','["與世漸無緣，身心獨了然。講銷林下日，臘長定中年。", "磬絕朝齋後，香焚古寺前。非因送小朗，不到虎溪邊。"]'),
('yuding-32','孤雁','崔塗','唐','御定全唐诗','yuding','','[]','湘浦離應晚，邊城去已孤。如何萬里計，只在一枝蘆。',96,'御定全唐詩/json/679.json','["湘浦離應晚，邊城去已孤。如何萬里計，只在一枝蘆。", "迥起波搖楚，寒棲月映蒲。不知天畔侶，何處下平蕪。", "幾行歸去盡，片影獨何之。暮雨相呼失，寒塘獨下遲。", "渚雲低暗度，關月冷遙隨。未必逢矰繳，孤飛自可疑。"]'),
('yuding-33','寄青城山顥禪師','崔塗','唐','御定全唐诗','yuding','','[]','懷師不可攀，師往杳冥間。林下誰聞法，塵中只見山。',48,'御定全唐詩/json/679.json','["懷師不可攀，師往杳冥間。林下誰聞法，塵中只見山。", "終年人不到，盡日鳥空還。曾聽無生說，應憐獨未還。"]'),
('yuding-34','秋夕與王處士話別','崔塗','唐','御定全唐诗','yuding','','[]','微燈照寂寥，此夕正迢迢。丹桂得已晚，故山歸尚遙。',48,'御定全唐詩/json/679.json','["微燈照寂寥，此夕正迢迢。丹桂得已晚，故山歸尚遙。", "蟲聲移暗壁，月色動寒條。此去如真隱，期君試一瓢。"]'),
('yuding-35','秋日犍為道中','崔塗','唐','御定全唐诗','yuding','','[]','久客厭岐路，出門吟且悲。平生未到處，落日獨行時。',48,'御定全唐詩/json/679.json','["久客厭岐路，出門吟且悲。平生未到處，落日獨行時。", "芳草不長綠，故人無重期。那堪更南渡，鄉國已天涯。"]'),
('yuding-36','送僧歸江東','崔塗','唐','御定全唐诗','yuding','','[]','坐徹秦城夏，行登越客船。去留那有著，語默不離禪。',48,'御定全唐詩/json/679.json','["坐徹秦城夏，行登越客船。去留那有著，語默不離禪。", "葉擁臨關路，霞明近海天。更尋同社侶，應得虎溪邊。"]'),
('yuding-37','喜友人及第','崔塗','唐','御定全唐诗','yuding','','[]','孤吟望至公，已老半生中。不有同人達，兼疑此道窮。',48,'御定全唐詩/json/679.json','["孤吟望至公，已老半生中。不有同人達，兼疑此道窮。", "只應才自薄，豈是命難通。尚激摶溟勢，期君借北風。"]'),
('yuding-38','上巳日永崇裏言懷','崔塗','唐','御定全唐诗','yuding','','[]','未敢分明賞物華，十年如見夢中花。',32,'御定全唐詩/json/679.json','["未敢分明賞物華，十年如見夢中花。", "遊人過盡衡門掩，獨自憑欄到日斜。"]'),
('yuding-39','送僧歸天竺','崔塗','唐','御定全唐诗','yuding','','[]','忽憶曾棲處，千峰近沃州。別來秦樹老，歸去海門秋。',48,'御定全唐詩/json/679.json','["忽憶曾棲處，千峰近沃州。別來秦樹老，歸去海門秋。", "汲帶寒汀月，禪鄰賈客舟。遙思清興愜，不厭石林幽。"]'),
('yuding-40','牛渚夜泊','崔塗','唐','御定全唐诗','yuding','','[]','煙老石磯平，袁郎夜泛情。數吟人不遇，千古月空明。',48,'御定全唐詩/json/679.json','["煙老石磯平，袁郎夜泛情。數吟人不遇，千古月空明。", "人事年年別，春潮日日生。無因逢謝尚，風物自淒清。"]'),
('yuding-41','送友人歸江南','崔塗','唐','御定全唐诗','yuding','','[]','渚田芳草遍，共憶故山春。獨往滄洲暮，相看白髮新。',48,'御定全唐詩/json/679.json','["渚田芳草遍，共憶故山春。獨往滄洲暮，相看白髮新。", "定過林下寺，應見社中人。只恐東歸後，難將鷗鳥親。"]'),
('yuding-42','過陶征君隱居','崔塗','唐','御定全唐诗','yuding','','[]','陶令昔居此，弄琴遺世榮。田園三畝綠，軒冕一銖輕。',48,'御定全唐詩/json/679.json','["陶令昔居此，弄琴遺世榮。田園三畝綠，軒冕一銖輕。", "衰柳自無主，白雲猶可耕。不隨陵谷變，應只有高名。"]'),
('yuding-43','江上旅泊','崔塗','唐','御定全唐诗','yuding','','[]','汀洲一夜泊，久客半連檣。盡說逢秋色，多同憶故鄉。',48,'御定全唐詩/json/679.json','["汀洲一夜泊，久客半連檣。盡說逢秋色，多同憶故鄉。", "孤岡生晚燒，獨樹隱回塘。欲問東歸路，遙知隔渺茫。"]'),
('yuding-44','灞上','崔塗','唐','御定全唐诗','yuding','','[]','長安名利路，役役古由今。征騎少閑日，綠楊無舊陰。',48,'御定全唐詩/json/679.json','["長安名利路，役役古由今。征騎少閑日，綠楊無舊陰。", "水侵秦甸闊，草接漢陵深。紫閣曾過處，依稀白鳥沈。"]'),
('yuding-45','寄舅','崔塗','唐','御定全唐诗','yuding','','[]','中朝軒冕內，久絕寧家親。白社同孤立，青雲獨並伸。',48,'御定全唐詩/json/679.json','["中朝軒冕內，久絕寧家親。白社同孤立，青雲獨並伸。", "致君期折檻，舉職在埋輪。須信堯庭草，猶能指佞人。"]'),
('yuding-46','贈休糧僧','崔塗','唐','御定全唐诗','yuding','','[]','聞鐘獨不齋，何事更關懷。靜少人過院，閑從草上階。',48,'御定全唐詩/json/679.json','["聞鐘獨不齋，何事更關懷。靜少人過院，閑從草上階。", "生台無鳥下，石路有雲埋。為憶禪中舊，時猶夢百崖。"]'),
('yuding-47','題絕島山寺','崔塗','唐','御定全唐诗','yuding','','[]','絕島跨危欄，登臨到此難。夕陽高鳥過，疏雨一鐘殘。',48,'御定全唐詩/json/679.json','["絕島跨危欄，登臨到此難。夕陽高鳥過，疏雨一鐘殘。", "駭浪搖空闊，靈山厭渺漫。那堪更回首，鄉樹隔雲端。"]'),
('yuding-48','讀侯道華真人傳','崔塗','唐','御定全唐诗','yuding','','[]','漢皇輕萬乘，方士說三丹。不得修心要，翻知出世難。',48,'御定全唐詩/json/679.json','["漢皇輕萬乘，方士說三丹。不得修心要，翻知出世難。", "茂陵春竟綠，金掌曙空寒。何似先生去，翩翩逐彩鸞。"]'),
('yuding-49','殘花','崔塗','唐','御定全唐诗','yuding','','[]','遲遲傍曉陰，昨夜色猶深。畢竟終須落，堪悲古與今。',48,'御定全唐詩/json/679.json','["遲遲傍曉陰，昨夜色猶深。畢竟終須落，堪悲古與今。", "明年何處見，盡日此時心。蜂蝶無情極，殘香更不尋。"]'),
('yuding-50','題興善寺隋松院與人期不至','崔塗','唐','御定全唐诗','yuding','','[]','青青伊澗松，移植在蓮宮。蘚色前朝雨，秋聲半夜風。',48,'御定全唐詩/json/679.json','["青青伊澗松，移植在蓮宮。蘚色前朝雨，秋聲半夜風。", "長閑應未得，暫賞亦難同。不及禪棲者，相看老此中。"]'),
('yuding-51','樵者','崔塗','唐','御定全唐诗','yuding','','[]','行山行采薇，閑翦蕙為衣。避世嫌山淺，逢人說姓稀。',48,'御定全唐詩/json/679.json','["行山行采薇，閑翦蕙為衣。避世嫌山淺，逢人說姓稀。", "有時還獨醉，何處掩衡扉。莫看棋終局，溪風晚待歸。"]'),
('yuding-52','南澗耕叟','崔塗','唐','御定全唐诗','yuding','','[]','年年南澗濱，力盡志猶存。雨雪朝耕苦，桑麻歲計貧。',48,'御定全唐詩/json/679.json','["年年南澗濱，力盡志猶存。雨雪朝耕苦，桑麻歲計貧。", "戰添丁壯役，老憶太平春。見說經荒後，田園半屬人。"]'),
('yuding-53','春日閒居憶江南舊業','崔塗','唐','御定全唐诗','yuding','','[]','杜門朝複夕，豈是解謀身。夢不離泉石，林唯稱隱淪。',48,'御定全唐詩/json/679.json','["杜門朝複夕，豈是解謀身。夢不離泉石，林唯稱隱淪。", "漸諳浮世事，轉憶故山春。南國水風暖，又應生白蘋。"]'),
('yuding-54','屈原廟','崔塗','唐','御定全唐诗','yuding','','[]','讒勝禍難防，沈冤信可傷。本圖安楚國，不是怨懷王。',48,'御定全唐詩/json/679.json','["讒勝禍難防，沈冤信可傷。本圖安楚國，不是怨懷王。", "廟古碑無字，洲晴蕙有香。獨醒人尚笑，誰與奠椒漿。"]'),
('yuding-55','宿廬山絕頂山舍','崔塗','唐','御定全唐诗','yuding','','[]','一磴出林端，千峰次第看。長閑如未遂，暫到亦應難。',48,'御定全唐詩/json/679.json','["一磴出林端，千峰次第看。長閑如未遂，暫到亦應難。", "穀樹雲埋老，僧窗瀑影寒。自嫌心不達，向此夢長安。"]'),
('yuding-56','王逸人隱居','崔塗','唐','御定全唐诗','yuding','','[]','一徑入千岑，幽人許重尋。不逢秦世亂，未覺武陵深。',48,'御定全唐詩/json/679.json','["一徑入千岑，幽人許重尋。不逢秦世亂，未覺武陵深。", "石轉生寒色，雲歸帶夕陰。卻愁危坐久，看盡暝棲禽。"]'),
('yuding-57','申州道中','崔塗','唐','御定全唐诗','yuding','','[]','風緊日淒淒，鄉心向此迷。水分平楚闊，山接故關低。',48,'御定全唐詩/json/679.json','["風緊日淒淒，鄉心向此迷。水分平楚闊，山接故關低。", "客路緣烽火，人家厭鼓鼙。那堪獨馳馬，江樹穆陵西。"]'),
('yuding-58','江上懷翠微寺空上人','崔塗','唐','御定全唐诗','yuding','','[]','旅泛本無定，相逢那可期。空懷白閣夜，未答碧雲詩。',48,'御定全唐詩/json/679.json','["旅泛本無定，相逢那可期。空懷白閣夜，未答碧雲詩。", "暮雨潮生早，春寒雁到遲。所思今不見，鄉國正天涯。"]'),
('yuding-59','秋宿鶴林寺','崔塗','唐','御定全唐诗','yuding','','[]','步步入林中，山窮意未窮。偏逢僧話久，轉與鶴棲同。',48,'御定全唐詩/json/679.json','["步步入林中，山窮意未窮。偏逢僧話久，轉與鶴棲同。", "燭焰風銷盡，蘭條露濕空。又須從此別，江上正秋鴻。"]'),
('yuding-60','遠望','崔塗','唐','御定全唐诗','yuding','','[]','長為鄉思侵，望極即沾襟。不是前山色，能傷愁客心。',48,'御定全唐詩/json/679.json','["長為鄉思侵，望極即沾襟。不是前山色，能傷愁客心。", "平蕪連海盡，獨樹隱雲深。況複斜陽外，分明有去禽。"]'),
('yuding-61','秋晚書懷','崔塗','唐','御定全唐诗','yuding','','[]','看看秋色晚，又是出門時。白髮生非早，青雲去自遲。',48,'御定全唐詩/json/679.json','["看看秋色晚，又是出門時。白髮生非早，青雲去自遲。", "夢唯懷上國，跡不到他岐。以此堅吾道，還無愧已知。"]'),
('yuding-62','途中秋晚送友人歸江南','崔塗','唐','御定全唐诗','yuding','','[]','又指煙波算路岐，此生多是厭羈離。正逢搖落仍須別，',40,'御定全唐詩/json/679.json','["又指煙波算路岐，此生多是厭羈離。正逢搖落仍須別，", "扁舟未得如君去，空向滄江夢所思。"]'),
('yuding-63','己亥歲感事','崔塗','唐','御定全唐诗','yuding','','[]','正聞青犢起葭萌，又報黃巾犯漢營。豈是將皆無上略，',40,'御定全唐詩/json/679.json','["正聞青犢起葭萌，又報黃巾犯漢營。豈是將皆無上略，", "見說聖君能仄席，不知誰是請長纓。"]'),
('yuding-64','金陵晚眺','崔塗','唐','御定全唐诗','yuding','','[]','葦聲騷屑水天秋，吟對金陵古渡頭。千古是非輸蝶夢，',40,'御定全唐詩/json/679.json','["葦聲騷屑水天秋，吟對金陵古渡頭。千古是非輸蝶夢，", "何必登臨更惆悵，比來身世只如浮。"]'),
('yuding-65','過長江賈島主簿舊廳','崔塗','唐','御定全唐诗','yuding','','[]','雕琢文章字字精，我經此處倍傷情。身從謫宦方沾祿，',40,'御定全唐詩/json/679.json','["雕琢文章字字精，我經此處倍傷情。身從謫宦方沾祿，", "長江一曲年年水，應為先生萬古清。"]'),
('yuding-66','途中感懷寄青城李明府','崔塗','唐','御定全唐诗','yuding','','[]','鱗鬣催殘志未休，壯心翻是此身讎。並聞寒雨多因夜，',40,'御定全唐詩/json/679.json','["鱗鬣催殘志未休，壯心翻是此身讎。並聞寒雨多因夜，", "如何只是三年別，君著朱衣我白頭。"]'),
('yuding-67','夏日書懷寄道友','崔塗','唐','御定全唐诗','yuding','','[]','達即匡邦退即耕，是非何足撓平生。終期道向希夷得，',40,'御定全唐詩/json/679.json','["達即匡邦退即耕，是非何足撓平生。終期道向希夷得，", "十年惟悟吟詩句，待得中原欲鑄兵。"]'),
('yuding-68','和進士張曙聞雁見寄','崔塗','唐','御定全唐诗','yuding','','[]','斷行哀響遞相催，爭趁高秋作恨媒。雲外關山聞獨去，',40,'御定全唐詩/json/679.json','["斷行哀響遞相催，爭趁高秋作恨媒。雲外關山聞獨去，", "試向富春江畔過，故園猶合有池台。"]'),
('yuding-69','鸚鵡洲即事','崔塗','唐','御定全唐诗','yuding','','[]','悵望春襟鬱未開，重吟鸚鵡益堪哀。曹瞞尚不能容物，',40,'御定全唐詩/json/679.json','["悵望春襟鬱未開，重吟鸚鵡益堪哀。曹瞞尚不能容物，", "何人正得風濤便，一點輕帆萬里回。"]'),
('yuding-70','讀留侯傳','崔塗','唐','御定全唐诗','yuding','','[]','覆楚讎韓勢有餘，男兒遭遇更難如。偶成漢室千年業，',40,'御定全唐詩/json/679.json','["覆楚讎韓勢有餘，男兒遭遇更難如。偶成漢室千年業，", "若能終始匡天子，何必□□□□□。"]'),
('yuding-71','赤壁懷古','崔塗','唐','御定全唐诗','yuding','','[]','漢室河山鼎勢分，勤王誰肯顧元勳。不知征伐由天子，',40,'御定全唐詩/json/679.json','["漢室河山鼎勢分，勤王誰肯顧元勳。不知征伐由天子，", "分明勝敗無尋處，空聽漁歌到夕曛。"]'),
('yuding-72','東晉','崔塗','唐','御定全唐诗','yuding','','[]','五陵豪俠笑為儒，將為儒生只讀書。',64,'御定全唐詩/json/679.json','["五陵豪俠笑為儒，將為儒生只讀書。", "看取不成投筆後，謝安功業複何如。", "秦國金陵王氣全，一龍正道始東遷。", "興亡竟不關人事，虛倚長淮五百年。"]'),
('yuding-73','春夕','崔塗','唐','御定全唐诗','yuding','','[]','水流花謝兩無情，送盡東風過楚城。蝴蝶夢中家萬里，',40,'御定全唐詩/json/679.json','["水流花謝兩無情，送盡東風過楚城。蝴蝶夢中家萬里，", "自是不歸歸便得，五湖煙景有誰爭。"]'),
('yuding-74','澗松','崔塗','唐','御定全唐诗','yuding','','[]','寸寸淩霜長勁條，路人猶笑未幹霄。',32,'御定全唐詩/json/679.json','["寸寸淩霜長勁條，路人猶笑未幹霄。", "南園桃李雖堪羨，爭奈春殘又寂寥。"]'),
('yuding-75','湘中弦','崔塗','唐','御定全唐诗','yuding','','[]','蒼山遙遙江潾潾，路傍老盡沒閒人。',64,'御定全唐詩/json/679.json','["蒼山遙遙江潾潾，路傍老盡沒閒人。", "王孫不見草空綠，惆悵渡頭春複春。", "煙愁雨細雲冥冥，杜蘭香老三湘清。", "故山望斷不知處，鶗鴂隔花時一聲。"]'),
('yuding-76','續紀漢武','崔塗','唐','御定全唐诗','yuding','','[]','分明三鳥下儲胥，一覺鈞天夢不如。',32,'御定全唐詩/json/679.json','["分明三鳥下儲胥，一覺鈞天夢不如。", "爭那白頭方士到，茂陵紅葉已蕭疏。"]'),
('yuding-77','隴上逢江南故人','崔塗','唐','御定全唐诗','yuding','','[]','三聲戍角邊城暮，萬里鄉心塞草春。',32,'御定全唐詩/json/679.json','["三聲戍角邊城暮，萬里鄉心塞草春。", "莫學少年輕遠別，隴關西少向東人。"]'),
('yuding-78','夷陵夜泊','崔塗','唐','御定全唐诗','yuding','','[]','家依楚塞窮秋別，身逐孤舟萬里行。',32,'御定全唐詩/json/679.json','["家依楚塞窮秋別，身逐孤舟萬里行。", "一曲巴歌半江月，便應消得二毛生。"]'),
('yuding-79','櫓聲','崔塗','唐','御定全唐诗','yuding','','[]','煙外橈聲遠，天涯幽夢回。爭知江上客，不是故鄉來。',24,'御定全唐詩/json/679.json','["煙外橈聲遠，天涯幽夢回。爭知江上客，不是故鄉來。"]'),
('yuding-80','海棠圖','崔塗','唐','御定全唐诗','yuding','','[]','海棠花底三年客，不見海棠花盛開。',32,'御定全唐詩/json/679.json','["海棠花底三年客，不見海棠花盛開。", "卻向江南看圖畫，始慚虛到蜀城來。"]'),
('yuding-81','雲','崔塗','唐','御定全唐诗','yuding','','[]','得路直為霖濟物，不然閑共鶴忘機。',32,'御定全唐詩/json/679.json','["得路直為霖濟物，不然閑共鶴忘機。", "無端卻向陽臺畔，長送襄王暮雨歸。"]'),
('yuding-82','過二妃廟','崔塗','唐','御定全唐诗','yuding','','[]','殘陽楚水畔，獨吊舜時人。不及廟前草，至今江上春。',24,'御定全唐詩/json/679.json','["殘陽楚水畔，獨吊舜時人。不及廟前草，至今江上春。"]'),
('yuding-83','送友人','崔塗','唐','御定全唐诗','yuding','','[]','登高迎送遠，春恨並依依。不得滄洲信，空看白鶴歸。',24,'御定全唐詩/json/679.json','["登高迎送遠，春恨並依依。不得滄洲信，空看白鶴歸。"]'),
('yuding-84','聲','崔塗','唐','御定全唐诗','yuding','','[]','歡戚猶來恨不平，此中高下本無情。',32,'御定全唐詩/json/679.json','["歡戚猶來恨不平，此中高下本無情。", "韓娥絕唱唐衢哭，儘是人間第一聲。"]'),
('yuding-85','放鷓鴣','崔塗','唐','御定全唐诗','yuding','','[]','秋入池塘風露微，曉開籠檻看初飛。',32,'御定全唐詩/json/679.json','["秋入池塘風露微，曉開籠檻看初飛。", "滿身金翠畫不得，無限煙波何處歸。"]'),
('yuding-86','泉','崔塗','唐','御定全唐诗','yuding','','[]','遠辭岩竇瀉潺潺，靜拂雲根別故山。',32,'御定全唐詩/json/679.json','["遠辭岩竇瀉潺潺，靜拂雲根別故山。", "可惜寒聲留不得，旋添波浪向人間。"]'),
('yuding-87','巫山旅別','崔塗','唐','御定全唐诗','yuding','','[]','五千裏外三年客，十二峰前一望秋。',32,'御定全唐詩/json/679.json','["五千裏外三年客，十二峰前一望秋。", "無限別魂招不得，夕陽西下水東流。"]'),
('yuding-88','幽蘭','崔塗','唐','御定全唐诗','yuding','','[]','幽植眾甯知，芬芳只暗持。自無君子佩，未是國香衰。',48,'御定全唐詩/json/679.json','["幽植眾甯知，芬芳只暗持。自無君子佩，未是國香衰。", "白露沾長早，春風到每遲。不如當路草，芬馥欲何為。"]'),
('yuding-89','讀庾信集','崔塗','唐','御定全唐诗','yuding','','[]','四朝十帝盡風流，建業長安兩醉遊。',32,'御定全唐詩/json/679.json','["四朝十帝盡風流，建業長安兩醉遊。", "唯有一篇楊柳曲，江南江北為君愁。"]'),
('yuding-90','過繡嶺宮','崔塗','唐','御定全唐诗','yuding','','[]','古殿春殘綠野陰，上皇曾此駐泥金。三城帳屬升平夢，',40,'御定全唐詩/json/679.json','["古殿春殘綠野陰，上皇曾此駐泥金。三城帳屬升平夢，", "前朝舊物東流在，猶為年年下翠岑。"]'),
('yuding-91','巴山道中除夜書懷','崔塗','唐','御定全唐诗','yuding','','[]','迢遞三巴路，羈危萬里身。亂山殘雪夜，孤燭異鄉春。',48,'御定全唐詩/json/679.json','["迢遞三巴路，羈危萬里身。亂山殘雪夜，孤燭異鄉春。", "漸與骨肉遠，轉於僮僕親。那堪正漂泊，明日歲華新。"]'),
('yuding-92','題淨眾寺古松','崔塗','唐','御定全唐诗','yuding','','[]','百尺森疏倚梵台，昔人誰見此初栽。故園未有偏堪戀，',40,'御定全唐詩/json/679.json','["百尺森疏倚梵台，昔人誰見此初栽。故園未有偏堪戀，", "清陰可惜不駐得，歸去暮城空首回。"]'),
('yuding-93','折楊柳','崔塗','唐','御定全唐诗','yuding','','[]','朝朝車馬如蓬轉，處處江山待客歸。',32,'御定全唐詩/json/679.json','["朝朝車馬如蓬轉，處處江山待客歸。", "若使人間少離別，楊花應合過春飛。"]'),
('yuding-94','七夕','崔塗','唐','御定全唐诗','yuding','','[]','年年七夕渡瑤軒，誰道秋期有淚痕。',32,'御定全唐詩/json/679.json','["年年七夕渡瑤軒，誰道秋期有淚痕。", "自是人間一周歲，何妨天上只黃昏。"]'),
('yuding-95','泛楚江','崔塗','唐','御定全唐诗','yuding','','[]','九重城外家書遠，百里洲前客棹還。',32,'御定全唐詩/json/679.json','["九重城外家書遠，百里洲前客棹還。", "金印碧幢如見問，一生安穩是長閑。"]'),
('yuding-96','初過漢江','崔塗','唐','御定全唐诗','yuding','','[]','襄陽好向峴亭看，人物蕭條值歲闌。',32,'御定全唐詩/json/679.json','["襄陽好向峴亭看，人物蕭條值歲闌。", "為報習家多置酒，夜來風雪過江寒。"]'),
('yuding-97','題授陽鎮路','崔塗','唐','御定全唐诗','yuding','','[]','越鳥巢邊溪路斷，秦人耕處洞門開。',32,'御定全唐詩/json/679.json','["越鳥巢邊溪路斷，秦人耕處洞門開。", "小桃花發春風起，千里江山一夢回。"]'),
('yuding-98','初識梅花','崔塗','唐','御定全唐诗','yuding','','[]','江北不如南地暖，江南好斷北人腸。',32,'御定全唐詩/json/679.json','["江北不如南地暖，江南好斷北人腸。", "燕脂桃頰梨花粉，共作寒梅一面妝。"]'),
('yuding-99','江雨望花','崔塗','唐','御定全唐诗','yuding','','[]','細雨滿江春水漲，好風留客野梅香。',32,'御定全唐詩/json/679.json','["細雨滿江春水漲，好風留客野梅香。", "避秦不是無歸意，一度逢花一斷腸。"]'),
('yuding-0','雨後月中玉堂閑坐','韓偓','唐','御定全唐诗','yuding','','[]','銀台直北金鑾外，暑雨初晴皓月中。唯對松篁聽刻漏，',40,'御定全唐詩/json/680.json','["銀台直北金鑾外，暑雨初晴皓月中。唯對松篁聽刻漏，", "夜久忽聞鈴索動，玉堂西畔響丁東。"]'),
('yuding-1','六月十七日召對自辰及申方歸本院','韓偓','唐','御定全唐诗','yuding','','[]','清暑簾開散異香，恩深咫尺對龍章。花應洞裏尋常發，',40,'御定全唐詩/json/680.json','["清暑簾開散異香，恩深咫尺對龍章。花應洞裏尋常發，", "如今冷笑東方朔，唯用詼諧侍漢皇。"]'),
('yuding-2','與吳子華侍郎同年玉堂同直懷恩敘懇因成…兼呈諸同年','韓偓','唐','御定全唐诗','yuding','','[]','往年鶯穀接清塵，今日鼇山作侍臣。二紀計偕勞筆研，',40,'御定全唐詩/json/680.json','["往年鶯穀接清塵，今日鼇山作侍臣。二紀計偕勞筆研，", "絳帳恩深無路報，語餘相顧卻酸辛。"]'),
('yuding-3','和吳子華侍郎令狐昭化舍人歎白菊衰謝之絕次用本韻','韓偓','唐','御定全唐诗','yuding','','[]','正憐香雪披千片，忽訝殘霞覆一叢。',32,'御定全唐詩/json/680.json','["正憐香雪披千片，忽訝殘霞覆一叢。", "還似妖姬長年後，酒酣雙臉卻微紅。"]'),
('yuding-4','中秋禁直','韓偓','唐','御定全唐诗','yuding','','[]','星斗疏明禁漏殘，紫泥封後獨憑闌。露和玉屑金盤冷，',40,'御定全唐詩/json/680.json','["星斗疏明禁漏殘，紫泥封後獨憑闌。露和玉屑金盤冷，", "長卿只為長門賦，未識君臣際會難。"]'),
('yuding-5','侍宴','韓偓','唐','御定全唐诗','yuding','','[]','蜂黃蝶粉兩依依，狎宴臨春日正遲。',32,'御定全唐詩/json/680.json','["蜂黃蝶粉兩依依，狎宴臨春日正遲。", "密旨不教江令醉，麗華微笑認皇慈。"]'),
('yuding-6','錫宴日作','韓偓','唐','御定全唐诗','yuding','','[]','玉銜花馬蹋香街，詔遣追歡綺席開。中使押從天上去，',48,'御定全唐詩/json/680.json','["玉銜花馬蹋香街，詔遣追歡綺席開。中使押從天上去，", "才有異恩頒稷契，已將優禮及鄒枚。清商適向梨園降，"]'),
('yuding-7','宮柳','韓偓','唐','御定全唐诗','yuding','','[]','莫道秋來芳意違，宮娃猶似妒蛾眉。幸當玉輦經過處，',40,'御定全唐詩/json/680.json','["莫道秋來芳意違，宮娃猶似妒蛾眉。幸當玉輦經過處，", "澗松亦有淩雲分，爭似移根太液池。"]'),
('yuding-8','苑中','韓偓','唐','御定全唐诗','yuding','','[]','上苑離宮處處迷，相風高與露盤齊。金階鑄出狻猊立，',40,'御定全唐詩/json/680.json','["上苑離宮處處迷，相風高與露盤齊。金階鑄出狻猊立，", "笙歌錦繡雲霄裏，獨許詞臣醉似泥。"]'),
('yuding-9','從獵三首','韓偓','唐','御定全唐诗','yuding','','[]','獵犬諳斜路，宮嬪識認旗。馬前雙兔起，宣爾羽林兒。',72,'御定全唐詩/json/680.json','["獵犬諳斜路，宮嬪識認旗。馬前雙兔起，宣爾羽林兒。", "小鐙狹秋鞘，鞍輕妓細腰。有時齊走馬，也學唱交交。", "蹀躞巴陵駿，毰毸碧野雞。忽聞仙樂動，賜酒玉偏提。"]'),
('yuding-10','辛酉歲冬十一月隨駕幸岐下作','韓偓','唐','御定全唐诗','yuding','','[]','曳裾談笑殿西頭，忽聽征鐃從冕旒。鳳蓋行時移紫氣，',40,'御定全唐詩/json/680.json','["曳裾談笑殿西頭，忽聽征鐃從冕旒。鳳蓋行時移紫氣，", "雨露涵濡三百載，不知誰擬殺身酬。"]'),
('yuding-11','冬至夜作','韓偓','唐','御定全唐诗','yuding','','[]','中宵忽見動葭灰，料得南枝有早梅。四野便應枯草綠，',40,'御定全唐詩/json/680.json','["中宵忽見動葭灰，料得南枝有早梅。四野便應枯草綠，", "不道慘舒無定分，卻憂蚊響又成雷。"]'),
('yuding-12','秋霖夜憶家','韓偓','唐','御定全唐诗','yuding','','[]','垂老何時見弟兄，背燈愁泣到天明。',32,'御定全唐詩/json/680.json','["垂老何時見弟兄，背燈愁泣到天明。", "不知短髮能多少，一滴秋霖白一莖。"]'),
('yuding-13','恩賜櫻桃分寄朝士','韓偓','唐','御定全唐诗','yuding','','[]','未許鶯偷出漢宮，上林初進半金籠。蔗漿自透銀盃冷，',40,'御定全唐詩/json/680.json','["未許鶯偷出漢宮，上林初進半金籠。蔗漿自透銀盃冷，", "霜威食檗應難近，宜在紗窗繡戶中。"]'),
('yuding-14','出官經硤石縣','韓偓','唐','御定全唐诗','yuding','','[]','謫宦過東畿，所抵州名濮。故里欲清明，臨風堪慟哭。',72,'御定全唐詩/json/680.json','["謫宦過東畿，所抵州名濮。故里欲清明，臨風堪慟哭。", "溪長柳似帷，山暖花如醭。逆旅訝簪裾，野老悲陵穀。", "暝鳥影連翩，驚狐尾纛簌。尚得佐方州，信是皇恩沐。"]'),
('yuding-15','訪同年虞部李郎中','韓偓','唐','御定全唐诗','yuding','','[]','策蹇相尋犯雪泥，廚煙未動日平西。門庭野水褵褷鷺，',40,'御定全唐詩/json/680.json','["策蹇相尋犯雪泥，廚煙未動日平西。門庭野水褵褷鷺，", "地爐貰酒成狂醉，更覺襟懷得喪齊。"]'),
('yuding-16','贈漁者','韓偓','唐','御定全唐诗','yuding','','[]','個儂居處近誅茅，枳棘籬兼用荻梢。盡日風扉從自掩，',40,'御定全唐詩/json/680.json','["個儂居處近誅茅，枳棘籬兼用荻梢。盡日風扉從自掩，", "我亦好閑求老伴，莫嫌遷客且論交。"]'),
('yuding-17','春陰獨酌寄同年虞部李郎中','韓偓','唐','御定全唐诗','yuding','','[]','春陰漠漠土脈潤，春寒微微風意和。閑嗤入甲奔競態，',40,'御定全唐詩/json/680.json','["春陰漠漠土脈潤，春寒微微風意和。閑嗤入甲奔競態，", "酒酣狂興依然在，其奈千莖鬢雪何。"]'),
('yuding-18','奉和峽州孫舍人肇荊南重圍中寄諸朝士二篇時李…牽課','韓偓','唐','御定全唐诗','yuding','','[]','敏手何妨誤汰金，敢懷私忿斅羊斟。直應宣室還三接，',80,'御定全唐詩/json/680.json','["敏手何妨誤汰金，敢懷私忿斅羊斟。直應宣室還三接，", "私恩尚有捐軀誓，況是君恩萬倍深。", "征途安敢更遷延，冒入重圍勢使然。眾果卻應存苦李，", "黃篾舫中梅雨裏，野人無事日高眠。"]'),
('yuding-19','雪中過重湖信筆偶題','韓偓','唐','御定全唐诗','yuding','','[]','道方時險擬如何，謫去甘心隱薜蘿。青草湖將天暗合，',40,'御定全唐詩/json/680.json','["道方時險擬如何，謫去甘心隱薜蘿。青草湖將天暗合，", "處困不忙仍不怨，醉來唯是欲傞傞。"]'),
('yuding-20','寄湖南從事','韓偓','唐','御定全唐诗','yuding','','[]','索寞襟懷酒半醒，無人一為解餘酲。岸頭柳色春將盡，',40,'御定全唐詩/json/680.json','["索寞襟懷酒半醒，無人一為解餘酲。岸頭柳色春將盡，", "蓮花幕下風流客，試與溫存譴逐情。"]'),
('yuding-21','玩水禽','韓偓','唐','御定全唐诗','yuding','','[]','兩兩珍禽渺渺溪，翠衿紅掌淨無泥。向陽眠處莎成毯，',40,'御定全唐詩/json/680.json','["兩兩珍禽渺渺溪，翠衿紅掌淨無泥。向陽眠處莎成毯，", "勸君細認漁翁意，莫遣縆羅誤穩棲。"]'),
('yuding-22','早玩雪梅有懷親屬','韓偓','唐','御定全唐诗','yuding','','[]','北陸候才變，南枝花已開。無人同悵望，把酒獨裴回。',48,'御定全唐詩/json/680.json','["北陸候才變，南枝花已開。無人同悵望，把酒獨裴回。", "凍白雪為伴，寒香風是媒。何因逢越使，腸斷謫仙才。"]'),
('yuding-23','欲明','韓偓','唐','御定全唐诗','yuding','','[]','欲明籬被風吹倒，過午門因客到開。忍苦可能遭鬼笑，',40,'御定全唐詩/json/680.json','["欲明籬被風吹倒，過午門因客到開。忍苦可能遭鬼笑，", "唯有狂吟與沈飲，時時猶自觸靈台。"]'),
('yuding-24','梅花','韓偓','唐','御定全唐诗','yuding','','[]','梅花不肯傍春光，自向深冬著豔陽。龍笛遠吹胡地月，',40,'御定全唐詩/json/680.json','["梅花不肯傍春光，自向深冬著豔陽。龍笛遠吹胡地月，", "應笑暫時桃李樹，盜天和氣作年芳。"]'),
('yuding-25','小隱','韓偓','唐','御定全唐诗','yuding','','[]','借得茅齋嶽麓西，擬將身世老鋤犁。清晨向市煙含郭，',40,'御定全唐詩/json/680.json','["借得茅齋嶽麓西，擬將身世老鋤犁。清晨向市煙含郭，", "靈椿朝菌由來事，卻笑莊生始欲齊。"]'),
('yuding-26','曛黑','韓偓','唐','御定全唐诗','yuding','','[]','古木侵天日已沈，露華涼冷潤衣襟。',32,'御定全唐詩/json/680.json','["古木侵天日已沈，露華涼冷潤衣襟。", "江城曛黑人行絕，唯有啼烏伴夜碪。"]'),
('yuding-27','曉日','韓偓','唐','御定全唐诗','yuding','','[]','天際霞光入水中，水中天際一時紅。',32,'御定全唐詩/json/680.json','["天際霞光入水中，水中天際一時紅。", "直須日觀三更後，首送金烏上碧空。"]'),
('yuding-28','醉著','韓偓','唐','御定全唐诗','yuding','','[]','萬里清江萬里天，一村桑柘一村煙。',32,'御定全唐詩/json/680.json','["萬里清江萬里天，一村桑柘一村煙。", "漁翁醉著無人喚，過午醒來雪滿船。"]'),
('yuding-29','柳','韓偓','唐','御定全唐诗','yuding','','[]','一籠金線拂彎橋，幾被兒童損細腰。',32,'御定全唐詩/json/680.json','["一籠金線拂彎橋，幾被兒童損細腰。", "無奈靈和標格在，春來依舊褭長條。"]'),
('yuding-30','病中初聞複官二首','韓偓','唐','御定全唐诗','yuding','','[]','抽毫連夜侍明光，執靮三年從省方。燒玉謾勞曾曆試，',80,'御定全唐詩/json/680.json','["抽毫連夜侍明光，執靮三年從省方。燒玉謾勞曾曆試，", "聞道複官翻涕泗，屬車何在水茫茫。", "又掛朝衣一自驚，始知天意重推誠。青雲有路通還去，", "宦途巇嶮終難測，穩泊漁舟隱姓名。"]'),
('yuding-31','早起五言三韻','韓偓','唐','御定全唐诗','yuding','','[]','萬樹綠楊垂，千般黃鳥語。庭花風雨餘，岑寂如村塢。',36,'御定全唐詩/json/680.json','["萬樹綠楊垂，千般黃鳥語。庭花風雨餘，岑寂如村塢。", "依依官渡頭，晴陽照行旅。"]'),
('yuding-32','家書後批二十八字','韓偓','唐','御定全唐诗','yuding','','[]','四序風光總是愁，鬢毛衰颯涕橫流。',32,'御定全唐詩/json/680.json','["四序風光總是愁，鬢毛衰颯涕橫流。", "此書未到心先到，想在孤城海岸頭。"]'),
('yuding-33','湖南梅花一冬再發偶題於花援','韓偓','唐','御定全唐诗','yuding','','[]','湘浦梅花兩度開，直應天意別栽培。玉為通體依稀見，',40,'御定全唐詩/json/680.json','["湘浦梅花兩度開，直應天意別栽培。玉為通體依稀見，", "夭桃莫倚東風勢，調鼎何曾用不材。"]'),
('yuding-34','即目二首','韓偓','唐','御定全唐诗','yuding','','[]','萬古離懷憎物色，幾生愁緒溺風光。廢城沃土肥春草，',80,'御定全唐詩/json/680.json','["萬古離懷憎物色，幾生愁緒溺風光。廢城沃土肥春草，", "宦途棄擲須甘分，回避紅塵是所長。", "動非求進靜非禪，咋舌吞聲過十年。溪漲浪花如積石，", "攻苦慣來無不可，寸心如水但澄鮮。"]'),
('yuding-35','淨興寺杜鵑一枝繁豔無比','韓偓','唐','御定全唐诗','yuding','','[]','一園紅豔醉坡陀，自地連梢簇蒨羅。',32,'御定全唐詩/json/680.json','["一園紅豔醉坡陀，自地連梢簇蒨羅。", "蜀魄未歸長滴血，只應偏滴此叢多。"]'),
('yuding-36','花時與錢尊師同醉因成二十字','韓偓','唐','御定全唐诗','yuding','','[]','橋下淺深水，竹間紅白花。酒仙同避世，何用厭長沙。',24,'御定全唐詩/json/680.json','["橋下淺深水，竹間紅白花。酒仙同避世，何用厭長沙。"]'),
('yuding-37','避地','韓偓','唐','御定全唐诗','yuding','','[]','西山爽氣生襟袖，南浦離愁入夢魂。人泊孤舟青草岸，',40,'御定全唐詩/json/680.json','["西山爽氣生襟袖，南浦離愁入夢魂。人泊孤舟青草岸，", "白面兒郎猶巧宦，不知誰與正乾坤。"]'),
('yuding-38','息兵','韓偓','唐','御定全唐诗','yuding','','[]','漸覺人心望息兵，老儒希覬見澄清。正當困辱殊輕死，',40,'御定全唐詩/json/680.json','["漸覺人心望息兵，老儒希覬見澄清。正當困辱殊輕死，", "暫時胯下何須恥，自有蒼蒼鑒赤誠。"]'),
('yuding-39','翠碧鳥','韓偓','唐','御定全唐诗','yuding','','[]','天長水遠網羅稀，保得重重翠碧衣。',32,'御定全唐詩/json/680.json','["天長水遠網羅稀，保得重重翠碧衣。", "挾彈小兒多害物，勸君莫近市朝飛。"]'),
('yuding-40','贈孫仁本尊師','韓偓','唐','御定全唐诗','yuding','','[]','齒如冰雪發如黳，幾百年來醉似泥。',32,'御定全唐詩/json/680.json','["齒如冰雪發如黳，幾百年來醉似泥。", "不共世人爭得失，臥床前有上天梯。"]'),
('yuding-41','乙丑歲九月在蕭灘鎮駐泊兩月忽得商馬楊迢…因書四十字','韓偓','唐','御定全唐诗','yuding','','[]','旅寓在江郊，秋風正寂寥。紫泥虛寵獎，白髮已漁樵。',48,'御定全唐詩/json/680.json','["旅寓在江郊，秋風正寂寥。紫泥虛寵獎，白髮已漁樵。", "事往淒涼在，時危志氣銷。若為將朽質，猶擬杖於朝。"]'),
('yuding-42','丙寅二月二十二日撫州如歸館雨中有懷諸朝客','韓偓','唐','御定全唐诗','yuding','','[]','淒淒惻惻又微嚬。欲話羈愁憶故人。薄酒旋醒寒徹夜，',40,'御定全唐詩/json/680.json','["淒淒惻惻又微嚬。欲話羈愁憶故人。薄酒旋醒寒徹夜，", "未必交情系貧富，柴門自古少車塵。"]'),
('yuding-43','三月二十七日自撫州往南城縣舟行見拂水薔薇因有是作','韓偓','唐','御定全唐诗','yuding','','[]','江中春雨波浪肥，石上野花枝葉瘦。枝低波高如有情，',40,'御定全唐詩/json/680.json','["江中春雨波浪肥，石上野花枝葉瘦。枝低波高如有情，", "且將濁酒伴清吟，酒逸吟狂輕宇宙。"]'),
('yuding-44','荔枝三首','韓偓','唐','御定全唐诗','yuding','','[]','遐方不許貢珍奇，密詔唯教進荔枝。',96,'御定全唐詩/json/680.json','["遐方不許貢珍奇，密詔唯教進荔枝。", "漢武碧桃爭比得，枉令方朔號偷兒。", "封開玉籠雞冠濕，葉襯金盤鶴頂鮮。", "想得佳人微啟齒，翠釵先取一雙懸。", "巧裁霞片裹神漿，崖蜜天然有異香。", "應是仙人金掌露，結成冰入蒨羅囊。"]'),
('yuding-45','寄上兄長','韓偓','唐','御定全唐诗','yuding','','[]','兩地支離路八千，襟懷悽愴鬢蒼然。',32,'御定全唐詩/json/680.json','["兩地支離路八千，襟懷悽愴鬢蒼然。", "亂來未必長團會，其奈而今更長年。"]'),
('yuding-46','寶劍','韓偓','唐','御定全唐诗','yuding','','[]','因極還應有甚通，難將糞壤掩神蹤。',32,'御定全唐詩/json/680.json','["因極還應有甚通，難將糞壤掩神蹤。", "鬥間紫氣分明後，擘地成川看化龍。"]'),
('yuding-47','登南神光寺塔院','韓偓','唐','御定全唐诗','yuding','','[]','無奈離腸日九回，強攄離抱立高臺。中華地向城邊盡，',40,'御定全唐詩/json/680.json','["無奈離腸日九回，強攄離抱立高臺。中華地向城邊盡，", "日宮紫氣生冠冕，試望扶桑病眼開。"]'),
('yuding-48','兩賢','韓偓','唐','御定全唐诗','yuding','','[]','賣卜嚴將賣餅孫，兩賢高趣恐難倫。',32,'御定全唐詩/json/680.json','["賣卜嚴將賣餅孫，兩賢高趣恐難倫。", "而今若有逃名者，應被品流呼差人。"]'),
('yuding-49','再思','韓偓','唐','御定全唐诗','yuding','','[]','暴殄猶來是片時，無人向此略遲疑。流金鑠石玉長潤，',40,'御定全唐詩/json/680.json','["暴殄猶來是片時，無人向此略遲疑。流金鑠石玉長潤，", "近來更得窮經力，好事臨行亦再思。"]'),
('yuding-50','有矚','韓偓','唐','御定全唐诗','yuding','','[]','晚涼閒步向江亭，默默看書旋旋行。風轉滯帆狂得勢，',40,'御定全唐詩/json/680.json','["晚涼閒步向江亭，默默看書旋旋行。風轉滯帆狂得勢，", "安石本懷經濟意，何妨一起為蒼生。"]'),
('yuding-51','秋深閑興','韓偓','唐','御定全唐诗','yuding','','[]','此心兼笑野雲忙，甘得貧閑味甚長。病起乍嘗新橘柚，',40,'御定全唐詩/json/680.json','["此心兼笑野雲忙，甘得貧閑味甚長。病起乍嘗新橘柚，", "把釣覆棋兼舉白，不離名教可顛狂。"]'),
('yuding-52','故都','韓偓','唐','御定全唐诗','yuding','','[]','故都遙想草萋萋，上帝深疑亦自迷。塞雁已侵池籞宿，',40,'御定全唐詩/json/680.json','["故都遙想草萋萋，上帝深疑亦自迷。塞雁已侵池籞宿，", "掩鼻計成終不覺，馮驩無路斅鳴雞。"]'),
('yuding-53','夢仙','韓偓','唐','御定全唐诗','yuding','','[]','紫霄宮闕五雲芝，九級壇前再拜時。鶴舞鹿眠春草遠，',40,'御定全唐詩/json/680.json','["紫霄宮闕五雲芝，九級壇前再拜時。鶴舞鹿眠春草遠，", "澡練純陽功力在，此心唯有玉皇知。"]'),
('yuding-54','贈吳顛尊師','韓偓','唐','御定全唐诗','yuding','','[]','飲酒經何代，休糧度此生。跡應常自浼，顛亦強為名。',168,'御定全唐詩/json/680.json','["飲酒經何代，休糧度此生。跡應常自浼，顛亦強為名。", "道若千鈞重，身如一羽輕。毫釐分象緯，袒跣揖公卿。", "狗竇號光逸，漁陽裸禰衡。笑雷冬蟄震，岩電夜珠明。", "月魄侵簪冷，江光逼屐清。半酣思救世，一手擬扶傾。", "擊地嗟衰俗，看天貯不平。自緣懷氣義，可是計烹亨。", "議論通三教，年顏稱五更。老狂人不厭，密行鬼應驚。", "未識心相許，開襟語便誠。伊余常仗義，願拜十年兄。"]'),
('yuding-55','送人棄官入道','韓偓','唐','御定全唐诗','yuding','','[]','仙李濃陰潤，皇枝密葉敷。俊才輕折桂，捷徑取紆朱。',120,'御定全唐詩/json/680.json','["仙李濃陰潤，皇枝密葉敷。俊才輕折桂，捷徑取紆朱。", "斷絏三清路，揚鞭五達衢。側身期破的，縮手待呼盧。", "社稷俄如綴，雄豪詎守株。忸怩非壯志，擺脫是良圖。", "塵土留難住，纓緌棄若無。冥心歸大道，回首笑吾徒。", "酒律應難忘，詩魔未肯徂。他年如拔宅，為我指清都。"]'),
('yuding-0','感事三十四韻','韓偓','唐','御定全唐诗','yuding','','[]','紫殿承恩歲，金鑾入直年。人歸三島路，日過八花磚。',409,'御定全唐詩/json/681.json','["紫殿承恩歲，金鑾入直年。人歸三島路，日過八花磚。", "鴛鷺皆回席，皋夔亦慕膻。慶霄舒羽翼，塵世有神仙。", "雖遇河清聖，慚非嶽降賢。皇慈容散拙，公議逼陶甄。", "江總參文會，陳暄侍狎筵。腐儒親帝座，太史認星躔。", "側弁聆神算，濡毫俟密宣。宮司持玉研，書省擘香箋。", "唯理心無黨，憐才膝屢前。焦勞皆實錄，宵旰豈虛傳。", "始議新堯曆，將期整舜弦。去梯言必盡，仄席意彌堅。", "上相思懲惡，中人詎省愆。鹿窮唯抵觸，兔急且cg猭。", "本是謀賒死，因之致劫遷。氛霾言下合，日月暗中懸。", "恭顯誠甘罪，韋平亦恃權。畏聞巢幕險，寧寤積薪然。", "諒直尋鉗口，奸纖益比肩。晉讒終不解，魯瘠竟難痊。", "只擬誅黃皓，何曾識霸先。嗾獒翻醜正，養虎欲求全。", "萬乘煙塵裏，千官劍戟邊。鬥魁當北坼，地軸向西偏。", "袁董非徒爾，師昭豈偶然。中原成劫火，東海遂桑田。", "濺血慚嵇紹，遲行笑褚淵。四夷同效順，一命敢虛捐。", "山嶽還青聳，穹蒼舊碧鮮。獨夫長啜泣，多士已忘筌。", "鬱鬱空狂叫，微微幾病癲。丹梯倚寥廓，終去問青天。"]'),
('yuding-1','向隅','韓偓','唐','御定全唐诗','yuding','','[]','守道得途遲，中兼遇亂離。剛腸成繞指，玄發轉垂絲。',48,'御定全唐詩/json/681.json','["守道得途遲，中兼遇亂離。剛腸成繞指，玄發轉垂絲。", "客路少安處，病床無穩時。弟兄消息絕，獨斂問隅眉。"]'),
('yuding-2','社後','韓偓','唐','御定全唐诗','yuding','','[]','社後重陽近，雲天澹薄間。目隨棋客靜，心共睡僧閑。',48,'御定全唐詩/json/681.json','["社後重陽近，雲天澹薄間。目隨棋客靜，心共睡僧閑。", "歸鳥城銜日，殘虹雨在山。寂寥思晤語，何夕款柴關。"]'),
('yuding-3','息慮','韓偓','唐','御定全唐诗','yuding','','[]','息慮狎群鷗，行藏合自由。春寒宜酒病，夜雨入鄉愁。',48,'御定全唐詩/json/681.json','["息慮狎群鷗，行藏合自由。春寒宜酒病，夜雨入鄉愁。", "道向危時見，官因亂世休。外人相待淺，獨說濟川舟。"]'),
('yuding-4','早起探春','韓偓','唐','御定全唐诗','yuding','','[]','句芒一夜長精神，臘後風頭已見春。煙柳半眠藏利臉，',40,'御定全唐詩/json/681.json','["句芒一夜長精神，臘後風頭已見春。煙柳半眠藏利臉，", "若個高情能似我，且應欹枕睡清晨。"]'),
('yuding-5','味道','韓偓','唐','御定全唐诗','yuding','','[]','如含瓦礫竟何功，癡黠相兼似得中。心系是非徒悵望，',40,'御定全唐詩/json/681.json','["如含瓦礫竟何功，癡黠相兼似得中。心系是非徒悵望，", "弋者甚多應扼腕，任他閑處指冥鴻。"]'),
('yuding-6','秋郊閑望有感','韓偓','唐','御定全唐诗','yuding','','[]','楓葉微紅近有霜，碧雲秋色滿吳鄉。魚沖駭浪雪鱗健，',40,'御定全唐詩/json/681.json','["楓葉微紅近有霜，碧雲秋色滿吳鄉。魚沖駭浪雪鱗健，", "可憐廣武山前語，楚漢寧教作戰場。"]'),
('yuding-7','李太舍池上玩紅薇醉題','韓偓','唐','御定全唐诗','yuding','','[]','花低池小水泙泙，花落池心片片輕。酩酊不能羞白鬢，',40,'御定全唐詩/json/681.json','["花低池小水泙泙，花落池心片片輕。酩酊不能羞白鬢，", "京洛園林歸未得，天涯相顧一含情。"]'),
('yuding-8','餘寓汀州沙縣，病中聞前鄭左丞璘隨外鎮舉薦…感悟也','韓偓','唐','御定全唐诗','yuding','','[]','莫恨當年入用遲，通材何處不逢知。桑田變後新舟楫，',40,'御定全唐詩/json/681.json','["莫恨當年入用遲，通材何處不逢知。桑田變後新舟楫，", "移都已改侯王第，惆悵沙堤別築基。"]'),
('yuding-9','又一絕請為申達京洛親交知餘病廢','韓偓','唐','御定全唐诗','yuding','','[]','鬢惹新霜耳舊聾，眼昏腰曲四肢風。',32,'御定全唐詩/json/681.json','["鬢惹新霜耳舊聾，眼昏腰曲四肢風。", "交親若要知形候，嵐嶂煙中折臂翁。"]'),
('yuding-10','夢中作','韓偓','唐','御定全唐诗','yuding','','[]','紫宸初啟列鴛鸞，直向龍墀對揖班。九曜再新環北極，',40,'御定全唐詩/json/681.json','["紫宸初啟列鴛鸞，直向龍墀對揖班。九曜再新環北極，", "扇合卻循黃道退，廟堂談笑百司閑。"]'),
('yuding-11','己巳年正月十二日自沙縣抵邵武軍將謀撫…偶成一篇','韓偓','唐','御定全唐诗','yuding','','[]','訪戴船回郊外泊，故鄉何處望天涯。半明半暗山村日，',24,'御定全唐詩/json/681.json','["訪戴船回郊外泊，故鄉何處望天涯。半明半暗山村日，"]'),
('yuding-12','建溪灘波心目驚眩余平生溺奇境今則畏怯不暇因書…八字','韓偓','唐','御定全唐诗','yuding','','[]','長貪山水羨漁樵，自笑揚鞭趁早朝。',32,'御定全唐詩/json/681.json','["長貪山水羨漁樵，自笑揚鞭趁早朝。", "今日建溪驚恐後，李將軍畫也須燒。"]'),
('yuding-13','自沙縣抵龍溪縣值泉州軍過後村落皆空因有一絕','韓偓','唐','御定全唐诗','yuding','','[]','水自潺湲日自斜，盡無雞犬有鳴鴉。',32,'御定全唐詩/json/681.json','["水自潺湲日自斜，盡無雞犬有鳴鴉。", "千村萬落如寒食，不見人煙空見花。"]'),
('yuding-14','此翁','韓偓','唐','御定全唐诗','yuding','','[]','高閣群公莫忌儂，儂心不在宦名中。岩光一唾垂緌紫，',40,'御定全唐詩/json/681.json','["高閣群公莫忌儂，儂心不在宦名中。岩光一唾垂緌紫，", "唯應鬼眼兼天眼，窺見行藏信此翁。"]'),
('yuding-15','失鶴','韓偓','唐','御定全唐诗','yuding','','[]','正憐標格出華亭，況是昂藏入相經。碧落順風初得志，',40,'御定全唐詩/json/681.json','["正憐標格出華亭，況是昂藏入相經。碧落順風初得志，", "為報雞群虛嫉妒，紅塵向上有青冥。"]'),
('yuding-16','卜隱','韓偓','唐','御定全唐诗','yuding','','[]','屏跡還應減是非，卻憂藍玉又光輝。桑梢出舍蠶初老，',40,'御定全唐詩/json/681.json','["屏跡還應減是非，卻憂藍玉又光輝。桑梢出舍蠶初老，", "世間華美無心問，藜藿充腸苧作衣。"]'),
('yuding-17','晨興','韓偓','唐','御定全唐诗','yuding','','[]','曉景山河爽，閒居巷陌清。已能消滯念，兼得散餘酲。',48,'御定全唐詩/json/681.json','["曉景山河爽，閒居巷陌清。已能消滯念，兼得散餘酲。", "汲水人初起，回燈燕暫驚。放懷殊未足，圓隙已塵生。"]'),
('yuding-18','暴雨','韓偓','唐','御定全唐诗','yuding','','[]','電尾燒黑雲，雨腳飛銀線。急點濺池心，微煙昏水面。',72,'御定全唐詩/json/681.json','["電尾燒黑雲，雨腳飛銀線。急點濺池心，微煙昏水面。", "氣涼氛祲消，暑退松篁健。叢蓼亞赬茸，擎荷翻綠扇。", "風期誰與同，逸趣餘探遍。欲去更遲留，胸中久交戰。"]'),
('yuding-19','山院避暑','韓偓','唐','御定全唐诗','yuding','','[]','行樂江郊外，追涼山寺中。靜陰生晚綠，寂慮延清風。',48,'御定全唐詩/json/681.json','["行樂江郊外，追涼山寺中。靜陰生晚綠，寂慮延清風。", "運塞地維窄，氣蘇天宇空。何人識幽抱，目送冥冥鴻。"]'),
('yuding-20','閑興','韓偓','唐','御定全唐诗','yuding','','[]','景寂有玄味，韻高無俗情。他山冰雪解，此水波瀾生。',48,'御定全唐詩/json/681.json','["景寂有玄味，韻高無俗情。他山冰雪解，此水波瀾生。", "影重驗花密，滴稀知酒清。忙人常擾擾，安得心和平。"]'),
('yuding-21','漫作二首','韓偓','唐','御定全唐诗','yuding','','[]','暑雨灑和氣，香風吹日華。瞬龍驚汗漫，翥鳳綷雲霞。',96,'御定全唐詩/json/681.json','["暑雨灑和氣，香風吹日華。瞬龍驚汗漫，翥鳳綷雲霞。", "懸圃珠為樹，天池玉作砂。丹霄能幾級，何必待乘槎。", "黍谷純陽入，鸞霄瑞彩生。岳靈分正氣，仙衛借神兵。", "汙俗迎風變，虛懷遇物傾。千鈞將一羽，輕重在平衡。"]'),
('yuding-22','騰騰','韓偓','唐','御定全唐诗','yuding','','[]','八年流落醉騰騰，點檢行藏喜不勝。',32,'御定全唐詩/json/681.json','["八年流落醉騰騰，點檢行藏喜不勝。", "烏帽素餐兼施藥，前生多恐是醫僧。"]'),
('yuding-23','寄隱者','韓偓','唐','御定全唐诗','yuding','','[]','煙郭雲扃路不遙，懷賢猶恨太迢迢。長松夜落釵千股，',40,'御定全唐詩/json/681.json','["煙郭雲扃路不遙，懷賢猶恨太迢迢。長松夜落釵千股，", "渭濱晦跡南陽臥，若比吾徒更寂寥。"]'),
('yuding-24','閒居','韓偓','唐','御定全唐诗','yuding','','[]','厭聞趨競喜閒居，自種蕪菁亦自鋤。麋鹿跳樑憂觸撥，',40,'御定全唐詩/json/681.json','["厭聞趨競喜閒居，自種蕪菁亦自鋤。麋鹿跳樑憂觸撥，", "刀尺不虧繩墨在，莫疑張翰戀鱸魚。"]'),
('yuding-25','僧影','韓偓','唐','御定全唐诗','yuding','','[]','山色依然僧已亡，竹間疏磬隔殘陽。',32,'御定全唐詩/json/681.json','["山色依然僧已亡，竹間疏磬隔殘陽。", "智燈已滅餘空燼，猶自光明照十方。"]'),
('yuding-26','洞庭玩月','韓偓','唐','御定全唐诗','yuding','','[]','洞庭湖上清秋月，月皎湖寬萬頃霜。玉碗深沈潭底白，',40,'御定全唐詩/json/681.json','["洞庭湖上清秋月，月皎湖寬萬頃霜。玉碗深沈潭底白，", "更憶瑤台逢此夜，水晶宮殿挹瓊漿。"]'),
('yuding-27','贈隱逸','韓偓','唐','御定全唐诗','yuding','','[]','靜景須教靜者尋，清狂何必在山陰。蜂穿窗紙塵侵硯，',40,'御定全唐詩/json/681.json','["靜景須教靜者尋，清狂何必在山陰。蜂穿窗紙塵侵硯，", "築金總得非名士，況是無人解築金。"]'),
('yuding-28','南浦','韓偓','唐','御定全唐诗','yuding','','[]','月若半環雲若吐，高樓簾卷當南浦。應是石城艇子來，',40,'御定全唐詩/json/681.json','["月若半環雲若吐，高樓簾卷當南浦。應是石城艇子來，", "直教筆底有文星，亦應難狀分明苦。"]'),
('yuding-29','桃林場客舍之前有池半畝木槿櫛比閼水遮山…五言八韻','韓偓','唐','御定全唐诗','yuding','','[]','插槿作藩籬，叢生覆小池。為能妨遠目，因遣去閑枝。',96,'御定全唐詩/json/681.json','["插槿作藩籬，叢生覆小池。為能妨遠目，因遣去閑枝。", "鄰叟偷來賞，棲禽欲下疑。虛空無障處，蒙閉有開時。", "葦鷺憐瀟灑，泥鰍畏日曦。稍寬春水面，盡見晚山眉。", "岸穩人偷釣，階明日上基。世間多弊事，事事要良醫。"]'),
('yuding-30','中秋寄楊學士','韓偓','唐','御定全唐诗','yuding','','[]','鱗差甲子漸衰遲，依舊年年困亂離。',32,'御定全唐詩/json/681.json','["鱗差甲子漸衰遲，依舊年年困亂離。", "八月夜長鄉思切，鬢邊添得幾莖絲。"]'),
('yuding-31','寄禪師','韓偓','唐','御定全唐诗','yuding','','[]','他心明與此心同，妙用忘言理暗通。氣運陰陽成世界，',40,'御定全唐詩/json/681.json','["他心明與此心同，妙用忘言理暗通。氣運陰陽成世界，", "萬物盡遭風鼓動，唯應禪室靜無風。"]'),
('yuding-32','清興','韓偓','唐','御定全唐诗','yuding','','[]','陰沈天氣連翩醉，摘索花枝料峭寒。',32,'御定全唐詩/json/681.json','["陰沈天氣連翩醉，摘索花枝料峭寒。", "擁鼻繞廊吟看雨，不知遺卻竹皮冠。"]'),
('yuding-33','深院','韓偓','唐','御定全唐诗','yuding','','[]','鵝兒唼啑梔黃觜，鳳子輕盈膩粉腰。',32,'御定全唐詩/json/681.json','["鵝兒唼啑梔黃觜，鳳子輕盈膩粉腰。", "深院下簾人晝寢，紅薔薇架碧芭蕉。"]'),
('yuding-34','淒淒','韓偓','唐','御定全唐诗','yuding','','[]','深將寵辱齊，往往亦淒淒。白日知丹抱，青雲有舊蹊。',48,'御定全唐詩/json/681.json','["深將寵辱齊，往往亦淒淒。白日知丹抱，青雲有舊蹊。", "嗜鹹凌魯濟，惡潔助涇泥。風雨今如晦，堪憐報曉雞。"]'),
('yuding-35','火蛾','韓偓','唐','御定全唐诗','yuding','','[]','陽光不照臨，積陰生此類。非無惜死心，奈有滅明意。',48,'御定全唐詩/json/681.json','["陽光不照臨，積陰生此類。非無惜死心，奈有滅明意。", "妝穿粉焰焦，翅撲蘭膏沸。為爾一傷嗟，自棄非天棄。"]'),
('yuding-36','信筆','韓偓','唐','御定全唐诗','yuding','','[]','春風狂似虎，春浪白於鵝。柳密藏煙易，松長見日多。',48,'御定全唐詩/json/681.json','["春風狂似虎，春浪白於鵝。柳密藏煙易，松長見日多。", "石崖采芝叟，鄉俗摘茶歌。道在無伊鬱，天將奈爾何。"]'),
('yuding-37','雷公','韓偓','唐','御定全唐诗','yuding','','[]','閒人倚柱笑雷公，又向深山霹怪松。',32,'御定全唐詩/json/681.json','["閒人倚柱笑雷公，又向深山霹怪松。", "必若有蘇天下意，何如驚起武侯龍。"]'),
('yuding-38','船頭','韓偓','唐','御定全唐诗','yuding','','[]','兩岸綠蕪齊似翦，掩映雲山相向晚。',32,'御定全唐詩/json/681.json','["兩岸綠蕪齊似翦，掩映雲山相向晚。", "船頭獨立望長空，日豔波光逼人眼。"]'),
('yuding-39','喜涼','韓偓','唐','御定全唐诗','yuding','','[]','爐炭燒人百疾生，鳳狂龍躁減心情。四山毒瘴乾坤濁，',48,'御定全唐詩/json/681.json','["爐炭燒人百疾生，鳳狂龍躁減心情。四山毒瘴乾坤濁，", "豪強頓息蛙唇吻，爽利重新鶻眼睛。穩想海槎朝犯鬥，"]'),
('yuding-40','天鑒','韓偓','唐','御定全唐诗','yuding','','[]','何勞諂笑學趨時，務實清修勝用機。猛虎十年搖尾立，',40,'御定全唐詩/json/681.json','["何勞諂笑學趨時，務實清修勝用機。猛虎十年搖尾立，", "事曆艱難人始重，九層成後喜從微。"]'),
('yuding-41','江岸閒步','韓偓','唐','御定全唐诗','yuding','','[]','一手攜書一杖筇，出門何處覓情通。立談禪客傳心印，',40,'御定全唐詩/json/681.json','["一手攜書一杖筇，出門何處覓情通。立談禪客傳心印，", "淮陰市里人相見，盡道途窮未必窮。"]'),
('yuding-42','野塘','韓偓','唐','御定全唐诗','yuding','','[]','侵曉乘涼偶獨來，不因魚躍見萍開。',32,'御定全唐詩/json/681.json','["侵曉乘涼偶獨來，不因魚躍見萍開。", "卷荷忽被微風觸，瀉下清香露一杯。"]'),
('yuding-43','餘臥疾深村聞一二郎官今稱繼使閩越笑余迂古…因成此篇','韓偓','唐','御定全唐诗','yuding','','[]','枕流方采北山薇，驛騎交迎市道兒。霧豹只憂無石室，',40,'御定全唐詩/json/681.json','["枕流方采北山薇，驛騎交迎市道兒。霧豹只憂無石室，", "莫負美名書信史，清風掃地更無遺。"]'),
('yuding-44','安貧','韓偓','唐','御定全唐诗','yuding','','[]','手風慵展一行書，眼暗休尋九局圖。窗裏日光飛野馬，',40,'御定全唐詩/json/681.json','["手風慵展一行書，眼暗休尋九局圖。窗裏日光飛野馬，", "舉世可能無默識，未知誰擬試齊竽。"]'),
('yuding-45','殘春旅舍','韓偓','唐','御定全唐诗','yuding','','[]','旅舍殘春宿雨晴，恍然心地憶咸京。樹頭蜂抱花須落，',40,'御定全唐詩/json/681.json','["旅舍殘春宿雨晴，恍然心地憶咸京。樹頭蜂抱花須落，", "兩梁免被塵埃汙，拂拭朝簪待眼明。"]'),
('yuding-46','鵲','韓偓','唐','御定全唐诗','yuding','','[]','偏承雨露潤毛衣，黑白分明眾所知。高處營巢親鳳闕，',40,'御定全唐詩/json/681.json','["偏承雨露潤毛衣，黑白分明眾所知。高處營巢親鳳闕，", "莫怪天涯棲不穩，托身須是萬年枝。"]'),
('yuding-47','露','韓偓','唐','御定全唐诗','yuding','','[]','鶴非千歲飲猶難，鶯舌偷含豈自安。光濕最宜叢菊亞，',40,'御定全唐詩/json/681.json','["鶴非千歲飲猶難，鶯舌偷含豈自安。光濕最宜叢菊亞，", "五色呈祥須得處，戛雲仙掌有金盤。"]'),
('yuding-48','贈僧','韓偓','唐','御定全唐诗','yuding','','[]','盡說歸山避戰塵，幾人終肯別囂氛。瓶添澗水盛將月，',40,'御定全唐詩/json/681.json','["盡說歸山避戰塵，幾人終肯別囂氛。瓶添澗水盛將月，", "相逢莫話金鑾事，觸撥傷心不願聞。"]'),
('yuding-49','感舊','韓偓','唐','御定全唐诗','yuding','','[]','省趨弘閣侍貂璫，指座深恩刻寸腸。秦苑已荒空逝水，',40,'御定全唐詩/json/681.json','["省趨弘閣侍貂璫，指座深恩刻寸腸。秦苑已荒空逝水，", "入室故寮流落盡，路人惆悵見靈光。"]'),
('yuding-50','八月六日作四首','韓偓','唐','御定全唐诗','yuding','','[]','日離黃道十年昏，敏手重開造化門。火帝動爐銷劍戟，',160,'御定全唐詩/json/681.json','["日離黃道十年昏，敏手重開造化門。火帝動爐銷劍戟，", "丹筆不知誰定罪，莫留遺跡怨神孫。", "金虎挻災不復論，構成狂猘犯車塵。禦衣空惜侍中血，", "黃旗紫氣今仍舊，免使老臣攀畫輪。", "簪裾皆是漢公卿，盡作鋒鋩劍血醒。顯負舊恩歸亂主，", "底事亦疑懲未了，更應書罪在泉扃。", "坐看包藏負國恩，無才不得預經綸。袁安墜睫尋憂漢，", "堤防瓜李能終始，免愧於心負此身。"]'),
('yuding-51','驛步','韓偓','唐','御定全唐诗','yuding','','[]','暫息征車病眼開，況穿松竹入樓臺。江流燈影向東去，',40,'御定全唐詩/json/681.json','["暫息征車病眼開，況穿松竹入樓臺。江流燈影向東去，", "高情自古多惆悵，賴有南華養不材。"]'),
('yuding-52','訪隱者遇沈醉書其門而歸','韓偓','唐','御定全唐诗','yuding','','[]','曉入江村覓釣翁，釣翁沈醉酒缸空。',32,'御定全唐詩/json/681.json','["曉入江村覓釣翁，釣翁沈醉酒缸空。", "夜來風起閑花落，狼藉柴門鳥徑中。"]'),
('yuding-53','疏雨','韓偓','唐','御定全唐诗','yuding','','[]','疏雨從東送疾雷，小庭涼氣淨莓苔。捲簾燕子穿人去，',40,'御定全唐詩/json/681.json','["疏雨從東送疾雷，小庭涼氣淨莓苔。捲簾燕子穿人去，", "戎衣一掛清天下，傅野非無濟世才。"]'),
('yuding-54','南安寓止','韓偓','唐','御定全唐诗','yuding','','[]','此地三年偶寄家，枳籬茅廠共桑麻。蝶矜翅暖徐窺草，',40,'御定全唐詩/json/681.json','["此地三年偶寄家，枳籬茅廠共桑麻。蝶矜翅暖徐窺草，", "豈知卜肆嚴夫子，潛指星機認海槎。"]'),
('yuding-55','十月七日早起作時氣疾初愈','韓偓','唐','御定全唐诗','yuding','','[]','疾愈身輕覺數通，山無嵐瘴海無風。',32,'御定全唐詩/json/681.json','["疾愈身輕覺數通，山無嵐瘴海無風。", "陽精欲出陰精落，天地包含紫氣中。"]'),
('yuding-56','有感','韓偓','唐','御定全唐诗','yuding','','[]','堅辭羽葆與吹鐃，翻向天涯困系匏。故老未曾忘炙背，',40,'御定全唐詩/json/681.json','["堅辭羽葆與吹鐃，翻向天涯困系匏。故老未曾忘炙背，", "萬里關山如咫尺，女床唯待鳳歸巢。"]'),
('yuding-57','觀鬥雞偶作','韓偓','唐','御定全唐诗','yuding','','[]','何曾解報稻粱恩，金距花冠氣遏雲。',32,'御定全唐詩/json/681.json','["何曾解報稻粱恩，金距花冠氣遏雲。", "白日梟鳴無意問，唯將芥羽害同群。"]'),
('yuding-58','蜻蜓','韓偓','唐','御定全唐诗','yuding','','[]','碧玉眼睛雲母翅，輕于粉蝶瘦於蜂。',32,'御定全唐詩/json/681.json','["碧玉眼睛雲母翅，輕于粉蝶瘦於蜂。", "坐來迎拂波光久，豈是殷勤為蓼叢。"]'),
('yuding-59','即目','韓偓','唐','御定全唐诗','yuding','','[]','書牆暗記移花日，洗甕先知醞酒期。',32,'御定全唐詩/json/681.json','["書牆暗記移花日，洗甕先知醞酒期。", "須信閒人有忙事，早來沖雨覓漁師。"]'),
('yuding-60','寄鄰莊道侶','韓偓','唐','御定全唐诗','yuding','','[]','聞說經旬不啟關，藥窗誰伴醉開顏。',32,'御定全唐詩/json/681.json','["聞說經旬不啟關，藥窗誰伴醉開顏。", "夜來雪壓村前竹，剩見溪南幾尺山。"]'),
('yuding-61','初赴期集','韓偓','唐','御定全唐诗','yuding','','[]','輕寒著背雨淒淒，九陌無塵未有泥。',32,'御定全唐詩/json/681.json','["輕寒著背雨淒淒，九陌無塵未有泥。", "還是平時舊滋味，慢垂鞭袖過街西。"]'),
('yuding-62','惜花','韓偓','唐','御定全唐诗','yuding','','[]','皺白離情高處切，膩香愁態靜中深。眼隨片片沿流去，',40,'御定全唐詩/json/681.json','["皺白離情高處切，膩香愁態靜中深。眼隨片片沿流去，", "臨軒一醆悲春酒，明日池塘是綠陰。"]'),
('yuding-63','半醉','韓偓','唐','御定全唐诗','yuding','','[]','水向東流竟不回，紅顏白髮遞相催。壯心暗逐高歌盡，',40,'御定全唐詩/json/681.json','["水向東流竟不回，紅顏白髮遞相催。壯心暗逐高歌盡，", "西樓悵望芳菲節，處處斜陽草似苔。"]'),
('yuding-64','春盡','韓偓','唐','御定全唐诗','yuding','','[]','惜春連日醉昏昏，醒後衣裳見酒痕。細水浮花歸別澗，',40,'御定全唐詩/json/681.json','["惜春連日醉昏昏，醒後衣裳見酒痕。細水浮花歸別澗，", "慚愧流鶯相厚意，清晨猶為到西園。"]'),
('yuding-65','睡起','韓偓','唐','御定全唐诗','yuding','','[]','睡起牆陰下藥闌，瓦松花白閉柴關。斷年不出僧嫌癖，',40,'御定全唐詩/json/681.json','["睡起牆陰下藥闌，瓦松花白閉柴關。斷年不出僧嫌癖，", "終撐舴艋稱漁叟，賒買湖心一崦山。"]'),
('yuding-66','寄友人','韓偓','唐','御定全唐诗','yuding','','[]','傷時惜別心交加，支頤一向千咨嗟。曠野風吹寒食月，',40,'御定全唐詩/json/681.json','["傷時惜別心交加，支頤一向千咨嗟。曠野風吹寒食月，", "夫君亦是多情者，幾處將愁殢酒家。"]'),
('yuding-67','見別離者因贈之','韓偓','唐','御定全唐诗','yuding','','[]','征人草草盡戎裝，征馬蕭蕭立路傍。尊酒闌珊將遠別，',40,'御定全唐詩/json/681.json','["征人草草盡戎裝，征馬蕭蕭立路傍。尊酒闌珊將遠別，", "曾向天涯懷此恨，見君嗚咽更淒涼。"]'),
('yuding-68','傷亂','韓偓','唐','御定全唐诗','yuding','','[]','岸上花根總倒垂，水中花影幾千枝。一枝一影寒山裏，',40,'御定全唐詩/json/681.json','["岸上花根總倒垂，水中花影幾千枝。一枝一影寒山裏，", "交親流落身羸病，誰在誰亡兩不知。"]'),
('yuding-69','南亭','韓偓','唐','御定全唐诗','yuding','','[]','每日在南亭，南亭似僧院。人語靜先聞，鳥啼深不見。',72,'御定全唐詩/json/681.json','["每日在南亭，南亭似僧院。人語靜先聞，鳥啼深不見。", "松瘦石棱棱，山光溪澱澱。塹蔓墜長茸，島花垂小蒨。", "行簪隱士冠，臥讀先賢傳。更有興來時，取琴彈一遍。"]'),
('yuding-70','太平谷中玩水上花','韓偓','唐','御定全唐诗','yuding','','[]','山頭水從雲外落，水面花自山中來。一溪紅點我獨惜，',40,'御定全唐詩/json/681.json','["山頭水從雲外落，水面花自山中來。一溪紅點我獨惜，", "凝眸不覺斜陽盡，忘逐樵人躡石回。"]'),
('yuding-71','雨','韓偓','唐','御定全唐诗','yuding','','[]','坐來簌簌山風急，山雨隨風暗原隰。樹帶繁聲出竹聞，',40,'御定全唐詩/json/681.json','["坐來簌簌山風急，山雨隨風暗原隰。樹帶繁聲出竹聞，", "此時高味共誰論，擁鼻吟詩空佇立。"]'),
('yuding-72','幽獨','韓偓','唐','御定全唐诗','yuding','','[]','幽獨起侵晨，山鶯啼更早。門巷掩蕭條，落花滿芳草。',48,'御定全唐詩/json/681.json','["幽獨起侵晨，山鶯啼更早。門巷掩蕭條，落花滿芳草。", "煙和魂共遠，春與人同老。默默又依依，淒然此懷抱。"]'),
('yuding-73','江行','韓偓','唐','御定全唐诗','yuding','','[]','浪蹙青山江北岸，雲含黑雨日西邊。舟人偶語憂風色，',24,'御定全唐詩/json/681.json','["浪蹙青山江北岸，雲含黑雨日西邊。舟人偶語憂風色，"]'),
('yuding-74','漢江行次','韓偓','唐','御定全唐诗','yuding','','[]','村寺雖深已暗知，幡竿殘日迥依依。沙頭有廟青林合，',40,'御定全唐詩/json/681.json','["村寺雖深已暗知，幡竿殘日迥依依。沙頭有廟青林合，", "竹園相接春波暖，痛憶家鄉舊釣磯。"]'),
('yuding-75','偶題','韓偓','唐','御定全唐诗','yuding','','[]','俟時輕進固相妨，實行丹心仗彼蒼。',32,'御定全唐詩/json/681.json','["俟時輕進固相妨，實行丹心仗彼蒼。", "蕭艾轉肥蘭蕙瘦，可能天亦妒馨香。"]'),
('yuding-76','湖南絕少含桃偶有人以新摘者見惠感事傷懷因成四韻','韓偓','唐','御定全唐诗','yuding','','[]','時節雖同氣候殊，不積堪薦寢園無。合充鳳食留三島，',40,'御定全唐詩/json/681.json','["時節雖同氣候殊，不積堪薦寢園無。合充鳳食留三島，", "金鑾歲歲長宣賜，忍淚看天憶帝都。"]'),
('yuding-77','隰州新驛','韓偓','唐','御定全唐诗','yuding','','[]','盛德已圖形，胡為忽構兵。燎原雖自及，誅亂不無名。',96,'御定全唐詩/json/681.json','["盛德已圖形，胡為忽構兵。燎原雖自及，誅亂不無名。", "擲鼠須防誤，連雞莫憚驚。本期將系虜，末策但嬰城。", "肘腋人情變，朝廷物論生。果聞荒穀縊，旋睹槁街烹。", "帝怒今方息，時危喜暫清。始終俱以此，天意甚分明。"]'),
('yuding-78','亂後春日途經野塘','韓偓','唐','御定全唐诗','yuding','','[]','世亂他鄉見落梅，野塘晴暖獨裴回。船沖水鳥飛還住，',40,'御定全唐詩/json/681.json','["世亂他鄉見落梅，野塘晴暖獨裴回。船沖水鳥飛還住，", "眼看朝市成陵穀，始信昆明是劫灰。"]'),
('yuding-79','贈易卜崔江處士','韓偓','唐','御定全唐诗','yuding','','[]','白首窮經通秘義，青山養老度危時。門傳組綬身能退，',40,'御定全唐詩/json/681.json','["白首窮經通秘義，青山養老度危時。門傳組綬身能退，", "壺中日月將何用，借與閒人試一窺。"]'),
('yuding-80','過臨淮故里','韓偓','唐','御定全唐诗','yuding','','[]','交遊昔歲已凋零，第宅今來亦變更。舊廟荒涼時饗絕，',40,'御定全唐詩/json/681.json','["交遊昔歲已凋零，第宅今來亦變更。舊廟荒涼時饗絕，", "榮盛幾何流落久，遣人襟抱薄浮生。"]'),
('yuding-81','贈湖南李思齊處士','韓偓','唐','御定全唐诗','yuding','','[]','兩板船頭濁酒壺，七絲琴畔白髭須。三春日日黃梅雨，',40,'御定全唐詩/json/681.json','["兩板船頭濁酒壺，七絲琴畔白髭須。三春日日黃梅雨，", "知餘絕粒窺仙事，許到名山看藥爐。"]'),
('yuding-0','亂後卻至近甸有感','韓偓','唐','御定全唐诗','yuding','','[]','狂童容易犯金門，比屋齊人作旅魂。夜戶不扃生茂草，',40,'御定全唐詩/json/682.json','["狂童容易犯金門，比屋齊人作旅魂。夜戶不扃生茂草，", "堪恨無情清渭水，渺茫依舊繞秦原。"]'),
('yuding-1','同年前虞部李郎中自長沙赴行在余以紫石硯贈之賦詩代書','韓偓','唐','御定全唐诗','yuding','','[]','斧柯新樣勝珠璣，堪贊星郎染翰時。不向東垣修直疏，',40,'御定全唐詩/json/682.json','["斧柯新樣勝珠璣，堪贊星郎染翰時。不向東垣修直疏，", "蓬島侍臣今放逐，羨君回去逼龍墀。"]'),
('yuding-2','甲子歲夏五月自長沙抵醴陵貴就深僻以便疏慵…聊寄知心','韓偓','唐','御定全唐诗','yuding','','[]','職在內庭宮闕下，廳前皆種紫微花。眼明忽傍漁家見，',40,'御定全唐詩/json/682.json','["職在內庭宮闕下，廳前皆種紫微花。眼明忽傍漁家見，", "此行若遇支機石，又被君平驗海槎。"]'),
('yuding-3','和王舍人撫州飲席贈韋司空','韓偓','唐','御定全唐诗','yuding','','[]','樓臺掩映入春寒，絲竹錚鏦向夜闌。席上弟兄皆杞梓，',40,'御定全唐詩/json/682.json','["樓臺掩映入春寒，絲竹錚鏦向夜闌。席上弟兄皆杞梓，", "削玉風姿官水土，黑頭公自古來難。"]'),
('yuding-4','避地寒食','韓偓','唐','御定全唐诗','yuding','','[]','避地淹留已自悲，況逢寒食欲沾衣。濃春孤館人愁坐，',40,'御定全唐詩/json/682.json','["避地淹留已自悲，況逢寒食欲沾衣。濃春孤館人愁坐，", "一名所系無窮事，爭敢當年便息機。"]'),
('yuding-5','山驛','韓偓','唐','御定全唐诗','yuding','','[]','參差西北數行雁，寥落東方幾片雲。疊石小松張水部，',40,'御定全唐詩/json/682.json','["參差西北數行雁，寥落東方幾片雲。疊石小松張水部，", "瀟灑襟懷遺世慮，驛樓紅葉自紛紛。"]'),
('yuding-6','早發藍關','韓偓','唐','御定全唐诗','yuding','','[]','關門愁立候雞鳴，搜景馳魂入杳冥。雲外日隨千里雁。',64,'御定全唐詩/json/682.json','["關門愁立候雞鳴，搜景馳魂入杳冥。雲外日隨千里雁。", "山根霜共一潭星。路盤暫見樵人火，棧轉時聞驛使鈴。", "自問辛勤緣底事，半年驅馬傍長亭。"]'),
('yuding-7','深村','韓偓','唐','御定全唐诗','yuding','','[]','甘向深村固不材，猶勝摧折傍塵埃。清宵玩月唯紅葉，',40,'御定全唐詩/json/682.json','["甘向深村固不材，猶勝摧折傍塵埃。清宵玩月唯紅葉，", "隔籬農叟遙相賀，□□□□膏雨來。"]'),
('yuding-8','重游曲江','韓偓','唐','御定全唐诗','yuding','','[]','追尋前事立江汀，漁者應聞太息聲。避客野鷗如有感，',40,'御定全唐詩/json/682.json','["追尋前事立江汀，漁者應聞太息聲。避客野鷗如有感，", "惆悵引人還到夜，鞭鞘風冷柳煙輕。"]'),
('yuding-9','三月','韓偓','唐','御定全唐诗','yuding','','[]','辛夷才謝小桃發，蹋青過後寒食前。四時最好是三月，',40,'御定全唐詩/json/682.json','["辛夷才謝小桃發，蹋青過後寒食前。四時最好是三月，", "新愁舊恨真無奈，須就鄰家甕底眠。"]'),
('yuding-10','秋村','韓偓','唐','御定全唐诗','yuding','','[]','稻壟蓼紅溝水清，荻園葉白秋日明。空坡路細見騎過，',40,'御定全唐詩/json/682.json','["稻壟蓼紅溝水清，荻園葉白秋日明。空坡路細見騎過，", "絕粒看經香一炷，心知無事即長生。"]'),
('yuding-11','殘花','韓偓','唐','御定全唐诗','yuding','','[]','餘霞殘雪幾多在，蔫香冶態猶無窮。黃昏月下惆悵白，',40,'御定全唐詩/json/682.json','["餘霞殘雪幾多在，蔫香冶態猶無窮。黃昏月下惆悵白，", "西園此日傷心處，一曲高歌水向東。"]'),
('yuding-12','夜船','韓偓','唐','御定全唐诗','yuding','','[]','野雲低迷煙蒼蒼，平波揮目如凝霜。月明船上簾幕卷，',40,'御定全唐詩/json/682.json','["野雲低迷煙蒼蒼，平波揮目如凝霜。月明船上簾幕卷，", "誠知不覺天將曙，幾簇青山雁一行。"]'),
('yuding-13','傷春','韓偓','唐','御定全唐诗','yuding','','[]','三月光景不忍看，五陵春色何摧殘。窮途得志反惆悵，',40,'御定全唐詩/json/682.json','["三月光景不忍看，五陵春色何摧殘。窮途得志反惆悵，", "野棠飛盡蒲根暖，寂寞南溪倚釣竿。"]'),
('yuding-14','歸紫閣下','韓偓','唐','御定全唐诗','yuding','','[]','一笈攜歸紫閣峰，馬蹄閑慢水溶溶。黃昏後見山田火，',40,'御定全唐詩/json/682.json','["一笈攜歸紫閣峰，馬蹄閑慢水溶溶。黃昏後見山田火，", "釣磯自別經秋雨，長得莓苔更幾重。"]'),
('yuding-15','夜坐','韓偓','唐','御定全唐诗','yuding','','[]','天似空江星似波，時時珠露滴圓荷。平生蹤跡慕真隱，',40,'御定全唐詩/json/682.json','["天似空江星似波，時時珠露滴圓荷。平生蹤跡慕真隱，", "無名無位堪休去，猶擬朝衣換釣蓑。"]'),
('yuding-16','午寢夢江外兄弟','韓偓','唐','御定全唐诗','yuding','','[]','長夏居閑門不開，繞門青草絕塵埃。空庭日午獨眠覺，',40,'御定全唐詩/json/682.json','["長夏居閑門不開，繞門青草絕塵埃。空庭日午獨眠覺，", "如何水陸三千里，幾月書郵始一來。"]'),
('yuding-17','曲江夜思','韓偓','唐','御定全唐诗','yuding','','[]','鼓聲將絕月斜痕，園外閑坊半掩門。池裏紅蓮凝白露，',40,'御定全唐詩/json/682.json','["鼓聲將絕月斜痕，園外閑坊半掩門。池裏紅蓮凝白露，", "大抵世間幽獨景，最關詩思與離魂。"]'),
('yuding-18','過漢口','韓偓','唐','御定全唐诗','yuding','','[]','濁世清名一概休，古今翻覆剩堪愁。年年春浪來巫峽，',40,'御定全唐詩/json/682.json','["濁世清名一概休，古今翻覆剩堪愁。年年春浪來巫峽，", "聯翩半世騰騰過，不在漁船即酒樓。"]'),
('yuding-19','惜春','韓偓','唐','御定全唐诗','yuding','','[]','願言未偶非高臥，多病無憀選勝遊。一夜雨聲三月盡，',40,'御定全唐詩/json/682.json','["願言未偶非高臥，多病無憀選勝遊。一夜雨聲三月盡，", "應是西園花已落，滿溪紅片向東流。"]'),
('yuding-20','及第過堂日作','韓偓','唐','御定全唐诗','yuding','','[]','早隨真侶集蓬瀛，閶闔門開尚見星。龍尾樓臺迎曉日，',40,'御定全唐詩/json/682.json','["早隨真侶集蓬瀛，閶闔門開尚見星。龍尾樓臺迎曉日，", "百辟斂容開路看，片時輝赫勝圖形。"]'),
('yuding-21','夏課成感懷','韓偓','唐','御定全唐诗','yuding','','[]','別離終日心忉忉，五湖煙波歸夢勞。淒涼身事夏課畢，',40,'御定全唐詩/json/682.json','["別離終日心忉忉，五湖煙波歸夢勞。淒涼身事夏課畢，", "誰憐愁苦多衰改，未到潘年有二毛。"]'),
('yuding-22','離家第二日卻寄諸兄弟','韓偓','唐','御定全唐诗','yuding','','[]','睡起褰簾日出時，今辰初恨間容輝。千行淚激傍人感，',40,'御定全唐詩/json/682.json','["睡起褰簾日出時，今辰初恨間容輝。千行淚激傍人感，", "定知兄弟高樓上，遙指征途羨鳥飛。"]'),
('yuding-23','遊江南水陸院','韓偓','唐','御定全唐诗','yuding','','[]','早於喧雜是深讎，猶恐行藏墜俗流。高寺懶為攜酒去，',40,'御定全唐詩/json/682.json','["早於喧雜是深讎，猶恐行藏墜俗流。高寺懶為攜酒去，", "除卻祖師心法外，浮生何處不堪愁。"]'),
('yuding-24','江南送別','韓偓','唐','御定全唐诗','yuding','','[]','江南行止忽相逢，江館棠梨葉正紅。一笑共嗟成往事，',40,'御定全唐詩/json/682.json','["江南行止忽相逢，江館棠梨葉正紅。一笑共嗟成往事，", "大抵多情應易老，不堪岐路數西東。"]'),
('yuding-25','格卑','韓偓','唐','御定全唐诗','yuding','','[]','格卑嘗恨足牽仍，欲學忘情似不能。入意雲山輸畫匠，',40,'御定全唐詩/json/682.json','["格卑嘗恨足牽仍，欲學忘情似不能。入意雲山輸畫匠，", "惆悵後塵流落盡，自拋懷抱醉懵騰。"]'),
('yuding-26','冬日','韓偓','唐','御定全唐诗','yuding','','[]','蕭條古木銜斜日，戚瀝晴寒滯早梅。愁處雪煙連野起，',40,'御定全唐詩/json/682.json','["蕭條古木銜斜日，戚瀝晴寒滯早梅。愁處雪煙連野起，", "景狀入詩兼入畫，言情不盡恨無才。"]'),
('yuding-27','再止廟居','韓偓','唐','御定全唐诗','yuding','','[]','去值秋風來值春，前時今日共銷魂。頹垣古柏疑山觀，',40,'御定全唐詩/json/682.json','["去值秋風來值春，前時今日共銷魂。頹垣古柏疑山觀，", "幽深凍餒皆推分，靜者還應為討論。"]'),
('yuding-28','老將','韓偓','唐','御定全唐诗','yuding','','[]','折槍黃馬倦塵埃，掩耳凶徒怕疾雷。雪密酒酣偷號去，',40,'御定全唐詩/json/682.json','["折槍黃馬倦塵埃，掩耳凶徒怕疾雷。雪密酒酣偷號去，", "坐久不須輕矍鑠，至今雙擘硬弓開。"]'),
('yuding-29','邊上看獵贈元戎','韓偓','唐','御定全唐诗','yuding','','[]','繡簾臨曉覺新霜，便遣移廚較獵場。燕卒鐵衣圍漢相，',48,'御定全唐詩/json/682.json','["繡簾臨曉覺新霜，便遣移廚較獵場。燕卒鐵衣圍漢相，", "贊獲一聲連朔漠，賀杯環騎舞優倡。軍回野靜秋天白，"]'),
('yuding-30','余自刑部員外郎為時權所擠值磐石出鎮藩屏…長句寄所知','韓偓','唐','御定全唐诗','yuding','','[]','正叨清級忽從戎，況與燕台事不同。開口謾勞矜道在，',40,'御定全唐詩/json/682.json','["正叨清級忽從戎，況與燕台事不同。開口謾勞矜道在，", "他日陶甄尋墜履，滄洲何處覓漁翁。"]'),
('yuding-31','北齊二首','韓偓','唐','御定全唐诗','yuding','','[]','任道驕奢必敗亡，且將繁盛悅嬪嬙。幾千奩鏡成樓柱，',80,'御定全唐詩/json/682.json','["任道驕奢必敗亡，且將繁盛悅嬪嬙。幾千奩鏡成樓柱，", "綺羅堆裏春風畔，年少多情一帝王。", "神器傳時異至公，敗亡安可怨匆匆。犯寒獵士朝頻戮，", "周朝將相還無體，甯死何須入鐵籠。"]'),
('yuding-32','寄京城親友二首','韓偓','唐','御定全唐诗','yuding','','[]','苦吟看墜葉，寥落共天涯。壯歲空為客，初寒更憶家。',96,'御定全唐詩/json/682.json','["苦吟看墜葉，寥落共天涯。壯歲空為客，初寒更憶家。", "雨牆經月蘚，山菊向陽花。因味碧雲句，傷哉後會賒。", "相思凡幾日，日欲詠離衿。直得吟成病，終難狀此心。", "解衣悲緩帶，搔首悶遺簪。西嶺斜陽外，潛疑是故林。"]'),
('yuding-33','野寺','韓偓','唐','御定全唐诗','yuding','','[]','野寺看紅葉，縣城聞擣衣。自憐癡病苦，猶共賞心違。',48,'御定全唐詩/json/682.json','["野寺看紅葉，縣城聞擣衣。自憐癡病苦，猶共賞心違。", "高閣正臨夜，前山應落暉。離情在煙鳥，遙入故關飛。"]'),
('yuding-34','吳郡懷古','韓偓','唐','御定全唐诗','yuding','','[]','主暗臣忠枉就刑，遂教強國醉中傾。人亡建業空城在，',40,'御定全唐詩/json/682.json','["主暗臣忠枉就刑，遂教強國醉中傾。人亡建業空城在，", "徒勞鐵鎖長千尺，不覺樓船下晉兵。"]'),
('yuding-35','守愚','韓偓','唐','御定全唐诗','yuding','','[]','深院寥寥竹蔭廊，披衣欹枕過年芳。守愚不覺世途險，',40,'御定全唐詩/json/682.json','["深院寥寥竹蔭廊，披衣欹枕過年芳。守愚不覺世途險，", "今來自責趨時懶，翻恨松軒書滿床。"]'),
('yuding-36','村居','韓偓','唐','御定全唐诗','yuding','','[]','二月三月雨晴初，舍南舍北唯平蕪。前歡入望盈千恨，',40,'御定全唐詩/json/682.json','["二月三月雨晴初，舍南舍北唯平蕪。前歡入望盈千恨，", "行看旦夕梨霜發，猶有山寒傷酒壚。"]'),
('yuding-37','離家','韓偓','唐','御定全唐诗','yuding','','[]','八月初長夜，千山第一程。款顏唯有夢，怨泣卻無聲。',48,'御定全唐詩/json/682.json','["八月初長夜，千山第一程。款顏唯有夢，怨泣卻無聲。", "祖席諸賓散，空郊匹馬行。自憐非達識，局促為浮名。"]'),
('yuding-38','秋雨內宴','韓偓','唐','御定全唐诗','yuding','','[]','一帶清風入畫堂，撼真珠箔碎玎璫。',32,'御定全唐詩/json/682.json','["一帶清風入畫堂，撼真珠箔碎玎璫。", "更看檻外霏霏雨，似勸須教醉玉觴。"]'),
('yuding-39','寒食日沙縣雨中看薔薇','韓偓','唐','御定全唐诗','yuding','','[]','何處遇薔薇，殊鄉冷節時。雨聲籠錦帳，風勢偃羅幃。',72,'御定全唐詩/json/682.json','["何處遇薔薇，殊鄉冷節時。雨聲籠錦帳，風勢偃羅幃。", "通體全無力，酡顏不自持。綠疏微露刺，紅密欲藏枝。", "愜意憑闌久，貪吟放醆遲。旁人應見訝，自醉自題詩。"]'),
('yuding-40','地爐','韓偓','唐','御定全唐诗','yuding','','[]','兩星殘火地爐畔，夢斷背燈重擁衾。側聽空堂聞靜響，',40,'御定全唐詩/json/682.json','["兩星殘火地爐畔，夢斷背燈重擁衾。側聽空堂聞靜響，", "禪客釣翁徒自好，那知此際湛然心。"]'),
('yuding-41','隰州新驛贈刺史','韓偓','唐','御定全唐诗','yuding','','[]','賢侯新換古長亭，先定心機指顧成。高義盡招秦逐客，',40,'御定全唐詩/json/682.json','["賢侯新換古長亭，先定心機指顧成。高義盡招秦逐客，", "卻笑昔賢交易極，一開東合便垂名。"]'),
('yuding-42','草書屏風','韓偓','唐','御定全唐诗','yuding','','[]','何處一屏風，分明懷素蹤。雖多塵色染，猶見墨痕濃。',48,'御定全唐詩/json/682.json','["何處一屏風，分明懷素蹤。雖多塵色染，猶見墨痕濃。", "怪石奔秋澗，寒藤掛古松。若教臨水畔，字字恐成龍。"]'),
('yuding-43','永明禪師房','韓偓','唐','御定全唐诗','yuding','','[]','景色方妍媚，尋真出近郊。寶香爐上爇，金磬佛前敲。',48,'御定全唐詩/json/682.json','["景色方妍媚，尋真出近郊。寶香爐上爇，金磬佛前敲。", "蔓草棱山徑，晴雲拂樹梢。支公禪寂處，時有鶴來巢。"]'),
('yuding-44','登樓有題','韓偓','唐','御定全唐诗','yuding','','[]','暑氣簷前過，蟬聲樹杪交。待潮生浦口，看雨過山坳。',48,'御定全唐詩/json/682.json','["暑氣簷前過，蟬聲樹杪交。待潮生浦口，看雨過山坳。", "才見蘭舟動，仍聞桂楫敲。窣雲朱檻好，終睹鳳來巢。"]'),
('yuding-45','朝退書懷','韓偓','唐','御定全唐诗','yuding','','[]','鶴帔星冠羽客裝，寢樓西畔坐書堂。山禽養久知人喚，',40,'御定全唐詩/json/682.json','["鶴帔星冠羽客裝，寢樓西畔坐書堂。山禽養久知人喚，", "孜孜莫患勞心力，富國安民理道長。"]'),
('yuding-46','元夜即席','韓偓','唐','御定全唐诗','yuding','','[]','元宵清景亞元正，絲雨霏霏向晚傾。桂兔韜光雲葉重，',40,'御定全唐詩/json/682.json','["元宵清景亞元正，絲雨霏霏向晚傾。桂兔韜光雲葉重，", "更待今宵開霽後，九衢車馬未妨行。"]'),
('yuding-47','大慶堂賜宴元璫而有詩呈吳越王','韓偓','唐','御定全唐诗','yuding','','[]','非為親賢展綺筵，恒常甯敢恣遊盤。綠搓楊柳綿初軟，',40,'御定全唐詩/json/682.json','["非為親賢展綺筵，恒常甯敢恣遊盤。綠搓楊柳綿初軟，", "笙歌風緊人酣醉，卻繞珍叢爛熳看。"]'),
('yuding-48','又和','韓偓','唐','御定全唐诗','yuding','','[]','櫻桃花下會親賢，風遠銅烏轉露盤。蝶下粉牆梅乍坼，',40,'御定全唐詩/json/682.json','["櫻桃花下會親賢，風遠銅烏轉露盤。蝶下粉牆梅乍坼，", "狂簡斐然吟詠足，卻邀群彥重吟看。"]'),
('yuding-49','再和','韓偓','唐','御定全唐诗','yuding','','[]','我有嘉賓宴乍歡，畫簾紋細鳳雙盤。影籠沼沚修篁密，',40,'御定全唐詩/json/682.json','["我有嘉賓宴乍歡，畫簾紋細鳳雙盤。影籠沼沚修篁密，", "櫻桃零落紅桃媚，更俟旬餘共醉看。"]'),
('yuding-50','重和','韓偓','唐','御定全唐诗','yuding','','[]','冷宴殷勤展小園，舞鞇柔軟彩虯盤。篸花盡日疑頭重，',40,'御定全唐詩/json/682.json','["冷宴殷勤展小園，舞鞇柔軟彩虯盤。篸花盡日疑頭重，", "文章天子文章別，八米盧郎未可看。"]'),
('yuding-51','餘作探使以繚綾手帛子寄賀因而有詩','韓偓','唐','御定全唐诗','yuding','','[]','解寄繚綾小字封，探花筵上映春叢。黛眉印在微微綠，',40,'御定全唐詩/json/682.json','["解寄繚綾小字封，探花筵上映春叢。黛眉印在微微綠，", "帝台春盡還東去，卻系裙腰伴雪胸。"]'),
('yuding-52','別錦兒','韓偓','唐','御定全唐诗','yuding','','[]','一尺紅綃一首詩，贈君相別兩相思。畫眉今日空留語，',40,'御定全唐詩/json/682.json','["一尺紅綃一首詩，贈君相別兩相思。畫眉今日空留語，", "出門何事休惆悵，曾夢良人折桂枝。"]'),
('yuding-53','閒步','韓偓','唐','御定全唐诗','yuding','','[]','莊南縱步游荒野，獨鳥寒煙輕惹惹。傍山疏雨濕秋花，',40,'御定全唐詩/json/682.json','["莊南縱步游荒野，獨鳥寒煙輕惹惹。傍山疏雨濕秋花，", "一壺傾盡未能歸，黃昏更望諸峰火。"]'),
('yuding-54','幹寧三年丙辰在奉天重圍作','韓偓','唐','御定全唐诗','yuding','','[]','仗劍夜巡城，衣襟滿霜霰。賊火遍郊坰，飛焰侵星漢。',48,'御定全唐詩/json/682.json','["仗劍夜巡城，衣襟滿霜霰。賊火遍郊坰，飛焰侵星漢。", "積雪似空江，長林如斷岸。獨憑女牆頭，思家起長歎。"]'),
('yuding-55','雨中','韓偓','唐','御定全唐诗','yuding','','[]','青桐承雨聲，聲聲何重疊。疏滴下高枝，次打欹低葉。',48,'御定全唐詩/json/682.json','["青桐承雨聲，聲聲何重疊。疏滴下高枝，次打欹低葉。", "鳥濕更梳翎，人愁方拄頰。獨自上西樓，風襟寒帖帖。"]'),
('yuding-56','與僧','韓偓','唐','御定全唐诗','yuding','','[]','江海扁舟客，雲山一衲僧。相逢兩無語，若個是南能。',24,'御定全唐詩/json/682.json','["江海扁舟客，雲山一衲僧。相逢兩無語，若個是南能。"]'),
('yuding-57','晚岸','韓偓','唐','御定全唐诗','yuding','','[]','揭起青篷上岸頭，野花和雨冷修修。',32,'御定全唐詩/json/682.json','["揭起青篷上岸頭，野花和雨冷修修。", "春江一夜無波浪，校得行人分外愁。"]'),
('yuding-58','仙山','韓偓','唐','御定全唐诗','yuding','','[]','一炷心香洞府開，偃松皺澀半莓苔。',32,'御定全唐詩/json/682.json','["一炷心香洞府開，偃松皺澀半莓苔。", "水清無底山如削，始有仙人騎鶴來。"]'),
('yuding-59','過茂陵','韓偓','唐','御定全唐诗','yuding','','[]','不悲霜露但傷春，孝理何因感兆民。',32,'御定全唐詩/json/682.json','["不悲霜露但傷春，孝理何因感兆民。", "景帝龍髯消息斷，異香空見李夫人。"]'),
('yuding-60','曲江秋日','韓偓','唐','御定全唐诗','yuding','','[]','斜煙縷縷鷺鷥棲，藕葉枯香折野泥。',32,'御定全唐詩/json/682.json','["斜煙縷縷鷺鷥棲，藕葉枯香折野泥。", "有個高僧入圖畫，把經吟立水塘西。"]'),
('yuding-61','流年','韓偓','唐','御定全唐诗','yuding','','[]','三月傷心仍晦日，一春多病更陰天。',32,'御定全唐詩/json/682.json','["三月傷心仍晦日，一春多病更陰天。", "雄豪亦有流年恨，況是離魂易黯然。"]'),
('yuding-62','商山道中','韓偓','唐','御定全唐诗','yuding','','[]','雲橫峭壁水準鋪，渡口人家日欲晡。',32,'御定全唐詩/json/682.json','["雲橫峭壁水準鋪，渡口人家日欲晡。", "卻憶往年看粉本，始知名畫有工夫。"]'),
('yuding-63','招隱','韓偓','唐','御定全唐诗','yuding','','[]','立意忘機機已生，可能朝市汙高情。',32,'御定全唐詩/json/682.json','["立意忘機機已生，可能朝市汙高情。", "時人未會嚴陵志，不釣鱸魚只釣名。"]'),
('yuding-64','雨村','韓偓','唐','御定全唐诗','yuding','','[]','雁行斜拂雨村樓，簾下三重幕一鉤。',32,'御定全唐詩/json/682.json','["雁行斜拂雨村樓，簾下三重幕一鉤。", "倚柱不知身半濕，黃昏獨自未回頭。"]'),
('yuding-65','使風','韓偓','唐','御定全唐诗','yuding','','[]','茶煙睡覺心無事，一卷黃庭在手中。',32,'御定全唐詩/json/682.json','["茶煙睡覺心無事，一卷黃庭在手中。", "欹枕捲簾江萬里，舟人不語滿帆風。"]'),
('yuding-66','阻風','韓偓','唐','御定全唐诗','yuding','','[]','平生情趣羨漁師，此日煙江愜所思。',32,'御定全唐詩/json/682.json','["平生情趣羨漁師，此日煙江愜所思。", "肥鱖香粳小艛艓，斷腸滋味阻風時。"]'),
('yuding-67','並州','韓偓','唐','御定全唐诗','yuding','','[]','戍旗青草接榆關，雨裏並州四月寒。',32,'御定全唐詩/json/682.json','["戍旗青草接榆關，雨裏並州四月寒。", "誰會憑闌潛忍淚，不勝天際似江幹。"]'),
('yuding-68','夏夜','韓偓','唐','御定全唐诗','yuding','','[]','猛風飄電黑雲生，霎霎高林簇雨聲。',32,'御定全唐詩/json/682.json','["猛風飄電黑雲生，霎霎高林簇雨聲。", "夜久雨休風又定，斷雲流月卻斜明。"]'),
('yuding-69','闌幹','韓偓','唐','御定全唐诗','yuding','','[]','掃花雖恨夜來雨，把酒卻憐晴後寒。',32,'御定全唐詩/json/682.json','["掃花雖恨夜來雨，把酒卻憐晴後寒。", "吳質謾言愁得病，當時猶不憑闌幹。"]'),
('yuding-70','以庭前海棠梨花一枝寄李十九員外','韓偓','唐','御定全唐诗','yuding','','[]','二月春風澹蕩時，旅人虛對海棠梨。',32,'御定全唐詩/json/682.json','["二月春風澹蕩時，旅人虛對海棠梨。", "不如寄與星郎去，想得朝回正畫眉。"]'),
('yuding-71','驛樓','韓偓','唐','御定全唐诗','yuding','','[]','流雲溶溶水悠悠，故鄉千里空回頭。',32,'御定全唐詩/json/682.json','["流雲溶溶水悠悠，故鄉千里空回頭。", "三更猶憑闌幹月，淚滿關山孤驛樓。"]'),
('yuding-72','頻訪盧秀才','韓偓','唐','御定全唐诗','yuding','','[]','藥訣棋經思致論，柳腰蓮臉本忘情。',32,'御定全唐詩/json/682.json','["藥訣棋經思致論，柳腰蓮臉本忘情。", "頻頻強入風流坐，酒肆應疑阮步兵。"]'),
('yuding-73','答友人見寄酒','韓偓','唐','御定全唐诗','yuding','','[]','雖可忘憂矣，其如作病何。淋漓滿襟袖，更發楚狂歌。',24,'御定全唐詩/json/682.json','["雖可忘憂矣，其如作病何。淋漓滿襟袖，更發楚狂歌。"]'),
('yuding-74','野釣','韓偓','唐','御定全唐诗','yuding','','[]','細雨桃花水，輕鷗逆浪飛。風頭阻歸棹，坐睡倚蓑衣。',24,'御定全唐詩/json/682.json','["細雨桃花水，輕鷗逆浪飛。風頭阻歸棹，坐睡倚蓑衣。"]'),
('yuding-75','曲江晚思','韓偓','唐','御定全唐诗','yuding','','[]','雲物陰寂曆，竹木寒青蒼。水冷鷺鷥立，煙月愁昏黃。',24,'御定全唐詩/json/682.json','["雲物陰寂曆，竹木寒青蒼。水冷鷺鷥立，煙月愁昏黃。"]'),
('yuding-76','贈友人','韓偓','唐','御定全唐诗','yuding','','[]','莫嫌談笑與經過，卻恐閑多病亦多。',32,'御定全唐詩/json/682.json','["莫嫌談笑與經過，卻恐閑多病亦多。", "若遣心中無一事，不知爭奈日長何。"]'),
('yuding-77','半睡','韓偓','唐','御定全唐诗','yuding','','[]','眉山暗澹向殘燈，一半雲鬟墜枕棱。',32,'御定全唐詩/json/682.json','["眉山暗澹向殘燈，一半雲鬟墜枕棱。", "四體著人嬌欲泣，自家揉損砑繚綾。"]'),
('yuding-78','已涼','韓偓','唐','御定全唐诗','yuding','','[]','愁多卻訝天涼早，思倦翻嫌夜漏遲。',32,'御定全唐詩/json/682.json','["愁多卻訝天涼早，思倦翻嫌夜漏遲。", "何處山川孤館裏，向燈彎盡一雙眉。"]'),
('yuding-79','寄禪師','韓偓','唐','御定全唐诗','yuding','','[]','從無入有雲峰聚，已有還無電火銷。',32,'御定全唐詩/json/682.json','["從無入有雲峰聚，已有還無電火銷。", "銷聚本來皆是幻，世間閑口漫囂囂。"]'),
('yuding-80','訪明公大德','韓偓','唐','御定全唐诗','yuding','','[]','寸發如霜袒右肩，倚肩筇竹貌怡然。懸燈深屋夜分坐，',40,'御定全唐詩/json/682.json','["寸發如霜袒右肩，倚肩筇竹貌怡然。懸燈深屋夜分坐，", "清涼藥分能知味，各自胸中有醴泉。"]'),
('yuding-81','大酺樂','韓偓','唐','御定全唐诗','yuding','','[]','晚日催弦管，春風入綺羅。杏花如有意，偏落舞衫多。',24,'御定全唐詩/json/682.json','["晚日催弦管，春風入綺羅。杏花如有意，偏落舞衫多。"]'),
('yuding-82','思歸樂','韓偓','唐','御定全唐诗','yuding','','[]','淚滴珠難盡，容殊玉易銷。儻隨明月去，莫道夢魂遙。',24,'御定全唐詩/json/682.json','["淚滴珠難盡，容殊玉易銷。儻隨明月去，莫道夢魂遙。"]'),
('yuding-83','禦制春遊長句','韓偓','唐','御定全唐诗','yuding','','[]','天意分明道已光，春遊嘉景勝仙鄉。玉爐煙直風初靜，',72,'御定全唐詩/json/682.json','["天意分明道已光，春遊嘉景勝仙鄉。玉爐煙直風初靜，", "黃鶯歷歷啼紅樹，紫燕關關語畫梁。低檻晚晴籠翡翠，", "比屋管弦呈妙曲，連營羅綺鬥時妝。全吳霸越千年後，"]'),
('yuding-0','《幽窗','韓偓','唐','御定全唐诗','yuding','','[]','刺繡非無暇，幽窗自鮮歡。手香江橘嫩，齒軟越梅酸。',48,'御定全唐詩/json/683.json','["刺繡非無暇，幽窗自鮮歡。手香江橘嫩，齒軟越梅酸。", "密約臨行怯，私書欲報難。無憑諳鵲語，猶得暫心寬。"]'),
('yuding-1','江樓二首','韓偓','唐','御定全唐诗','yuding','','[]','夢啼嗚咽覺無語，杳杳微微望煙浦。',65,'御定全唐詩/json/683.json','["夢啼嗚咽覺無語，杳杳微微望煙浦。", "樓空客散燕交飛，江靜帆飛日亭午。", "ok魚苦筍香味新，楊柳酒旗三月春。", "風光百計牽人老，爭奈多情是病身。"]'),
('yuding-2','春盡日','韓偓','唐','御定全唐诗','yuding','','[]','樹頭初日照西簷，樹底蔫花夜雨沾。外院池亭聞動鎖，',40,'御定全唐詩/json/683.json','["樹頭初日照西簷，樹底蔫花夜雨沾。外院池亭聞動鎖，", "把酒送春惆悵在，年年三月病厭厭。"]'),
('yuding-3','詠燈','韓偓','唐','御定全唐诗','yuding','','[]','高在酒樓明錦幕，遠隨漁艇泊煙江。',32,'御定全唐詩/json/683.json','["高在酒樓明錦幕，遠隨漁艇泊煙江。", "古來幽怨皆銷骨，休向長門背雨窗。"]'),
('yuding-4','別緒','韓偓','唐','御定全唐诗','yuding','','[]','別緒靜愔愔，牽愁暗入心。已回花渚棹，悔聽酒壚琴。',72,'御定全唐詩/json/683.json','["別緒靜愔愔，牽愁暗入心。已回花渚棹，悔聽酒壚琴。", "菊露淒羅幕，梨霜惻錦衾。此生終獨宿，到死誓相尋。", "月好知何計，歌闌歎不禁。山巔更高處，憶上上頭吟。"]'),
('yuding-5','見花','韓偓','唐','御定全唐诗','yuding','','[]','褰裳擁鼻正吟詩，日午牆頭獨見時。血染蜀羅山躑躅，',40,'御定全唐詩/json/683.json','["褰裳擁鼻正吟詩，日午牆頭獨見時。血染蜀羅山躑躅，", "看卻東風歸去也，爭教判得最繁枝。"]'),
('yuding-6','馬上見','韓偓','唐','御定全唐诗','yuding','','[]','驕馬錦連錢，乘騎是謫仙。和裙穿玉鐙，隔袖把金鞭。',48,'御定全唐詩/json/683.json','["驕馬錦連錢，乘騎是謫仙。和裙穿玉鐙，隔袖把金鞭。", "去帶懵騰醉，歸成困頓眠。自憐輸廄吏，餘暖在香韉。"]'),
('yuding-7','繞廊','韓偓','唐','御定全唐诗','yuding','','[]','濃煙隔簾香漏泄，斜燈映竹光參差。',32,'御定全唐詩/json/683.json','["濃煙隔簾香漏泄，斜燈映竹光參差。", "繞廊倚柱堪惆悵，細雨輕寒花落時。"]'),
('yuding-8','屐子','韓偓','唐','御定全唐诗','yuding','','[]','方寸膚圓光致致，白羅繡屟紅托裏。',32,'御定全唐詩/json/683.json','["方寸膚圓光致致，白羅繡屟紅托裏。", "南朝天子欠風流，卻重金蓮輕綠齒。"]'),
('yuding-9','青春','韓偓','唐','御定全唐诗','yuding','','[]','眼意心期卒未休，暗中終擬約秦樓。光陰負我難相遇，',40,'御定全唐詩/json/683.json','["眼意心期卒未休，暗中終擬約秦樓。光陰負我難相遇，", "櫻桃花謝梨花發，腸斷青春兩處愁。"]'),
('yuding-10','聞雨','韓偓','唐','御定全唐诗','yuding','','[]','香侵蔽膝夜寒輕，聞雨傷春夢不成。',32,'御定全唐詩/json/683.json','["香侵蔽膝夜寒輕，聞雨傷春夢不成。", "羅帳四垂紅燭背，玉釵敲著枕函聲。"]'),
('yuding-11','懶起','韓偓','唐','御定全唐诗','yuding','','[]','百舌喚朝眠，春心動幾般。枕痕霞黯澹，淚粉玉闌珊。',72,'御定全唐詩/json/683.json','["百舌喚朝眠，春心動幾般。枕痕霞黯澹，淚粉玉闌珊。", "籠繡香煙歇，屏山燭焰殘。暖嫌羅襪窄，瘦覺錦衣寬。", "昨夜三更雨，今朝一陣寒。海棠花在否，側臥捲簾看。"]'),
('yuding-12','已涼','韓偓','唐','御定全唐诗','yuding','','[]','碧闌幹外繡簾垂，猩血屏風畫折枝。',32,'御定全唐詩/json/683.json','["碧闌幹外繡簾垂，猩血屏風畫折枝。", "八尺龍須方錦褥，已涼天氣未寒時。"]'),
('yuding-13','欲去','韓偓','唐','御定全唐诗','yuding','','[]','粉紜隔窗語，重約蹋青期。總得相逢處，無非欲去時。',48,'御定全唐詩/json/683.json','["粉紜隔窗語，重約蹋青期。總得相逢處，無非欲去時。", "恨深書不盡，寵極意多疑。惆悵桃源路，惟教夢寐知。"]'),
('yuding-14','橫塘','韓偓','唐','御定全唐诗','yuding','','[]','秋寒灑背入簾霜，鳳脛燈清照洞房。蜀紙麝煤沾筆興，',40,'御定全唐詩/json/683.json','["秋寒灑背入簾霜，鳳脛燈清照洞房。蜀紙麝煤沾筆興，", "散客出門斜月在，兩眉愁思問橫塘。"]'),
('yuding-15','五更','韓偓','唐','御定全唐诗','yuding','','[]','往年曾約郁金床，半夜潛身入洞房。懷裏不知金鈿落，',40,'御定全唐詩/json/683.json','["往年曾約郁金床，半夜潛身入洞房。懷裏不知金鈿落，", "光景旋消惆悵在，一生贏得是淒涼。"]'),
('yuding-16','聯綴體','韓偓','唐','御定全唐诗','yuding','','[]','院宇秋明日日長，社前一雁到遼陽。',32,'御定全唐詩/json/683.json','["院宇秋明日日長，社前一雁到遼陽。", "隴頭針線年年事，不喜寒砧搗斷腸。"]'),
('yuding-17','半睡','韓偓','唐','御定全唐诗','yuding','','[]','抬鏡仍嫌重，更衣又怕寒。宵分未歸帳，半睡待郎看。',24,'御定全唐詩/json/683.json','["抬鏡仍嫌重，更衣又怕寒。宵分未歸帳，半睡待郎看。"]'),
('yuding-18','寒食夜','韓偓','唐','御定全唐诗','yuding','','[]','清江碧草兩悠悠，各自風流一種愁。',32,'御定全唐詩/json/683.json','["清江碧草兩悠悠，各自風流一種愁。", "正是落花寒食夜，夜深無伴倚南樓。"]'),
('yuding-19','哭花','韓偓','唐','御定全唐诗','yuding','','[]','曾愁香結破顏遲，今見妖紅委地時。',32,'御定全唐詩/json/683.json','["曾愁香結破顏遲，今見妖紅委地時。", "若是有情爭不哭，夜來風雨葬西施。"]'),
('yuding-20','重游曲江','韓偓','唐','御定全唐诗','yuding','','[]','鞭梢亂拂暗傷情，蹤跡難尋露草青。',32,'御定全唐詩/json/683.json','["鞭梢亂拂暗傷情，蹤跡難尋露草青。", "猶是玉輪曾輾處，一泓秋水漲浮萍。"]'),
('yuding-21','遙見','韓偓','唐','御定全唐诗','yuding','','[]','悲歌淚濕澹胭脂，閑立風吹金縷衣。',32,'御定全唐詩/json/683.json','["悲歌淚濕澹胭脂，閑立風吹金縷衣。", "白玉堂東遙見後，令人鬥薄畫楊妃。"]'),
('yuding-22','新秋','韓偓','唐','御定全唐诗','yuding','','[]','一夜清風動扇愁，背時容色入新秋。',32,'御定全唐詩/json/683.json','["一夜清風動扇愁，背時容色入新秋。", "桃花臉裏汪汪淚，忍到更深枕上流。"]'),
('yuding-23','宮詞','韓偓','唐','御定全唐诗','yuding','','[]','繡裙斜立正銷魂，侍女移燈掩殿門。',32,'御定全唐詩/json/683.json','["繡裙斜立正銷魂，侍女移燈掩殿門。", "燕子不來花著雨，春風應自怨黃昏。"]'),
('yuding-24','蹋青','韓偓','唐','御定全唐诗','yuding','','[]','蹋青會散欲歸時，金車久立頻催上。',32,'御定全唐詩/json/683.json','["蹋青會散欲歸時，金車久立頻催上。", "收裙整髻故遲遲，兩點深心各惆悵。"]'),
('yuding-25','夜深','韓偓','唐','御定全唐诗','yuding','','[]','惻惻輕寒翦翦風，小梅飄雪杏花紅。',32,'御定全唐詩/json/683.json','["惻惻輕寒翦翦風，小梅飄雪杏花紅。", "夜深斜搭秋千索，樓閣朦朧煙雨中。"]'),
('yuding-26','夏日','韓偓','唐','御定全唐诗','yuding','','[]','庭樹新陰葉未成，玉階人靜一蟬聲。',32,'御定全唐詩/json/683.json','["庭樹新陰葉未成，玉階人靜一蟬聲。", "相風不動烏龍睡，時有嬌鶯自喚名。"]'),
('yuding-27','新上頭','韓偓','唐','御定全唐诗','yuding','','[]','學梳松鬢試新裙，消息佳期在此春。',32,'御定全唐詩/json/683.json','["學梳松鬢試新裙，消息佳期在此春。", "為要好多心轉惑，遍將宜稱問傍人。"]'),
('yuding-28','中庭','韓偓','唐','御定全唐诗','yuding','','[]','夜短睡遲慵早起，日高方始出紗窗。',32,'御定全唐詩/json/683.json','["夜短睡遲慵早起，日高方始出紗窗。", "中庭自摘青梅子，先向釵頭戴一雙。"]'),
('yuding-29','詠浴','韓偓','唐','御定全唐诗','yuding','','[]','再整魚犀攏翠簪，解衣先覺冷森森。教移蘭燭頻羞影，',40,'御定全唐詩/json/683.json','["再整魚犀攏翠簪，解衣先覺冷森森。教移蘭燭頻羞影，", "豈知侍女簾帷外，剩取君王幾餅金。"]'),
('yuding-30','席上有贈','韓偓','唐','御定全唐诗','yuding','','[]','矜嚴標格絕嫌猜，嗔怒雖逢笑靨開。小雁斜侵眉柳去，',40,'御定全唐詩/json/683.json','["矜嚴標格絕嫌猜，嗔怒雖逢笑靨開。小雁斜侵眉柳去，", "莫道風流無宋玉，好將心力事妝台。"]'),
('yuding-31','早歸','韓偓','唐','御定全唐诗','yuding','','[]','去是黃昏後，歸當朧fC時。叉衣吟宿醉，風露動相思。',25,'御定全唐詩/json/683.json','["去是黃昏後，歸當朧fC時。叉衣吟宿醉，風露動相思。"]'),
('yuding-32','玉合','韓偓','唐','御定全唐诗','yuding','','[]','羅囊繡兩鳳凰，玉合雕雙鸂鶒。中有蘭膏漬紅豆，',38,'御定全唐詩/json/683.json','["羅囊繡兩鳳凰，玉合雕雙鸂鶒。中有蘭膏漬紅豆，", "開緘不見新書跡，帶粉猶殘舊淚痕。"]'),
('yuding-33','金陵','韓偓','唐','御定全唐诗','yuding','','[]','風雨蕭蕭，石頭城下木蘭橈。煙月迢迢，金陵渡口去來潮。',50,'御定全唐詩/json/683.json','["風雨蕭蕭，石頭城下木蘭橈。煙月迢迢，金陵渡口去來潮。", "自古風流皆暗銷，才魂妖魂誰與招？彩箋麗句今已矣，"]'),
('yuding-34','懶卸頭','韓偓','唐','御定全唐诗','yuding','','[]','侍女動妝奩，故故驚人睡。那知本未眠，背面偷垂淚。',48,'御定全唐詩/json/683.json','["侍女動妝奩，故故驚人睡。那知本未眠，背面偷垂淚。", "懶卸鳳凰釵，羞入鴛鴦被。時複見殘燈，和煙墜金穗。"]'),
('yuding-35','倚醉','韓偓','唐','御定全唐诗','yuding','','[]','倚醉無端尋舊約，卻憐惆悵轉難勝。靜中樓閣深春雨。',64,'御定全唐詩/json/683.json','["倚醉無端尋舊約，卻憐惆悵轉難勝。靜中樓閣深春雨。", "遠處簾櫳半夜燈。抱柱立時風細細，繞廊行處思騰騰。", "分明窗下聞裁翦，敲遍闌幹喚不應。"]'),
('yuding-36','詠手','韓偓','唐','御定全唐诗','yuding','','[]','腕白膚紅玉筍芽，調琴抽線露尖斜。背人細撚垂胭鬢。',64,'御定全唐詩/json/683.json','["腕白膚紅玉筍芽，調琴抽線露尖斜。背人細撚垂胭鬢。", "向鏡輕勻襯臉霞。悵望昔逢褰繡幔，依稀曾見托金車。", "後園笑向同行道，摘得蘼蕪又折花。"]'),
('yuding-37','荷花','韓偓','唐','御定全唐诗','yuding','','[]','紈扇相欹綠，香囊獨立紅。浸淫因重露，狂暴是秋風。',48,'御定全唐詩/json/683.json','["紈扇相欹綠，香囊獨立紅。浸淫因重露，狂暴是秋風。", "逸調無人唱，秋塘每夜空。何繇見周昉，移入畫屏中。"]'),
('yuding-38','松髻','韓偓','唐','御定全唐诗','yuding','','[]','髻根松慢玉釵垂，指點花枝又過時。',32,'御定全唐詩/json/683.json','["髻根松慢玉釵垂，指點花枝又過時。", "坐久暗生惆悵事，背人勻卻淚胭脂。"]'),
('yuding-39','寄遠','韓偓','唐','御定全唐诗','yuding','','[]','眉如半月雲如鬟，梧桐葉落敲井闌。孤燈亭亭公署寒，',40,'御定全唐詩/json/683.json','["眉如半月雲如鬟，梧桐葉落敲井闌。孤燈亭亭公署寒，", "空房輾轉懷悲酸，銅壺漏盡聞金鸞。"]'),
('yuding-40','蹤跡','韓偓','唐','御定全唐诗','yuding','','[]','東烏西兔似車輪，劫火桑田不復論。',32,'御定全唐詩/json/683.json','["東烏西兔似車輪，劫火桑田不復論。", "唯有風光與蹤跡，思量長是暗銷魂。"]'),
('yuding-41','病憶','韓偓','唐','御定全唐诗','yuding','','[]','信知尤物必牽情，一顧難酬覺命輕。',32,'御定全唐詩/json/683.json','["信知尤物必牽情，一顧難酬覺命輕。", "曾把禪機銷此病，破除才盡又重生。"]'),
('yuding-42','妒媒','韓偓','唐','御定全唐诗','yuding','','[]','洞房深閉不曾開，橫臥烏龍作妒媒。好鳥豈勞兼比翼，',48,'御定全唐詩/json/683.json','["洞房深閉不曾開，橫臥烏龍作妒媒。好鳥豈勞兼比翼，", "多為過防成後悔，偶因翻語得深猜。已嫌刻蠟春宵短，"]'),
('yuding-43','不見','韓偓','唐','御定全唐诗','yuding','','[]','動靜防閑又怕疑，佯佯脈脈是深機。',32,'御定全唐詩/json/683.json','["動靜防閑又怕疑，佯佯脈脈是深機。", "此身願作君家燕，秋社歸時也不歸。"]'),
('yuding-44','晝寢','韓偓','唐','御定全唐诗','yuding','','[]','碧桐陰盡隔簾櫳，扇拂金鵝玉簟烘。撲粉更添香體滑，',40,'御定全唐詩/json/683.json','["碧桐陰盡隔簾櫳，扇拂金鵝玉簟烘。撲粉更添香體滑，", "何必苦勞魂與夢，王昌只在此牆東。"]'),
('yuding-45','意緒','韓偓','唐','御定全唐诗','yuding','','[]','絕代佳人何寂寞，梨花未發梅花落。東風吹雨入西園，',40,'御定全唐詩/json/683.json','["絕代佳人何寂寞，梨花未發梅花落。東風吹雨入西園，", "嬌饒意態不勝羞，願倚郎肩永相著。"]'),
('yuding-46','惆悵','韓偓','唐','御定全唐诗','yuding','','[]','身情長在暗相隨，生魄隨君君豈知。被頭不暖空沾淚，',40,'御定全唐詩/json/683.json','["身情長在暗相隨，生魄隨君君豈知。被頭不暖空沾淚，", "何如飲酒連千醉，席地幕天無所知。"]'),
('yuding-47','忍笑','韓偓','唐','御定全唐诗','yuding','','[]','宮樣衣裳淺畫眉，晚來梳洗更相宜。',32,'御定全唐詩/json/683.json','["宮樣衣裳淺畫眉，晚來梳洗更相宜。", "水精鸚鵡釵頭顫，舉袂佯羞忍笑時。"]'),
('yuding-48','詠柳','韓偓','唐','御定全唐诗','yuding','','[]','褭雨拖風不自持，全身無力向人垂。',32,'御定全唐詩/json/683.json','["褭雨拖風不自持，全身無力向人垂。", "玉纖折得遙相贈，便似觀音手裏時。"]'),
('yuding-49','密意','韓偓','唐','御定全唐诗','yuding','','[]','呵花貼鬢黏寒發，凝酥光透猩猩血。',32,'御定全唐詩/json/683.json','["呵花貼鬢黏寒發，凝酥光透猩猩血。", "經過洛水幾多人，唯有陳王見羅襪。"]'),
('yuding-50','偶見','韓偓','唐','御定全唐诗','yuding','','[]','秋千打困解羅裙，指點醍醐索一尊。',32,'御定全唐詩/json/683.json','["秋千打困解羅裙，指點醍醐索一尊。", "見客入來和笑走，手搓梅子映中門。"]'),
('yuding-51','寒食夜有寄','韓偓','唐','御定全唐诗','yuding','','[]','風流大抵是倀倀，此際相思必斷腸。',32,'御定全唐詩/json/683.json','["風流大抵是倀倀，此際相思必斷腸。", "雲薄月昏寒食夜，隔簾微雨杏花香。"]'),
('yuding-52','效崔國輔體四首','韓偓','唐','御定全唐诗','yuding','','[]','澹月照中庭，海棠花自落。獨立俯閑階，風動秋千索。',96,'御定全唐詩/json/683.json','["澹月照中庭，海棠花自落。獨立俯閑階，風動秋千索。", "雨後碧苔院，霜來紅葉樓。閑階上斜日，鸚鵡伴人愁。", "酒力滋睡眸，鹵莽聞街鼓。欲明天更寒，東風打窗雨。", "羅幕生春寒，繡窗愁未眠。南湖一夜雨，應濕採蓮船。"]'),
('yuding-53','後魏時相州人作李波小妹歌疑其未備因補之','韓偓','唐','御定全唐诗','yuding','','[]','李波小妹字雍容，窄衣短袖蠻錦紅。未解有情夢梁殿，',40,'御定全唐詩/json/683.json','["李波小妹字雍容，窄衣短袖蠻錦紅。未解有情夢梁殿，", "海棠花下秋千畔，背人撩鬢道匆匆。"]'),
('yuding-54','春晝','韓偓','唐','御定全唐诗','yuding','','[]','春融豔豔，大醉陶陶。漏添遲日，箭減良宵。',80,'御定全唐詩/json/683.json','["春融豔豔，大醉陶陶。漏添遲日，箭減良宵。", "藤垂戟戶，柳拂河橋。簾幕燕子，池塘伯勞。", "膚清臂瘦，衫薄香銷。楚殿衣窄，南朝髻高。", "河陽縣遠，清波地遙。絲纏露泣，各自無憀。"]'),
('yuding-55','三憶','韓偓','唐','御定全唐诗','yuding','','[]','憶眠時，春夢困騰騰。輾轉不能起，玉釵垂枕棱。',66,'御定全唐詩/json/683.json','["憶眠時，春夢困騰騰。輾轉不能起，玉釵垂枕棱。", "憶行時，背手挼金雀。斂笑慢回頭，步轉闌幹角。", "憶去時，向月遲遲行。強語戲同伴，圖郎聞笑聲。"]'),
('yuding-56','六言三首','韓偓','唐','御定全唐诗','yuding','','[]','春樓處子傾城，金陵狎客多情。朝雲暮雨會合，',105,'御定全唐詩/json/683.json','["春樓處子傾城，金陵狎客多情。朝雲暮雨會合，", "幽歡不盡告別，秋河悵望平明。", "一燈前雨落夜，三月盡草青時。半寒半暖正好，", "紅袖不幹誰會，揉損聯娟澹眉。", "此間青草更遠，不唯空繞汀洲。那裏朝日才出，", "桃源洞口來否，絳節霓旌久留。"]'),
('yuding-57','寒食日重游李氏園亭有懷','韓偓','唐','御定全唐诗','yuding','','[]','往年同在鸞橋上，見倚朱闌詠柳綿。今日獨來香徑裏，',40,'御定全唐詩/json/683.json','["往年同在鸞橋上，見倚朱闌詠柳綿。今日獨來香徑裏，", "料得他鄉遇佳節，亦應懷抱暗淒然。"]'),
('yuding-58','思錄舊詩於卷上，淒然有感，因成一章','韓偓','唐','御定全唐诗','yuding','','[]','緝綴小詩鈔卷裏，尋思閒事到心頭。',32,'御定全唐詩/json/683.json','["緝綴小詩鈔卷裏，尋思閒事到心頭。", "自吟自泣無人會，腸斷蓬山第一流。"]'),
('yuding-59','春閨二首','韓偓','唐','御定全唐诗','yuding','','[]','願結交加夢，因傾瀲灩尊。醒來情緒惡，簾外正黃昏。',48,'御定全唐詩/json/683.json','["願結交加夢，因傾瀲灩尊。醒來情緒惡，簾外正黃昏。", "氤氳帳裏香，薄薄睡時妝。長籲解羅帶，怯見上空床。"]'),
('yuding-60','代小玉家為蕃騎所虜後寄故集賢裴公相國','韓偓','唐','御定全唐诗','yuding','','[]','動天金鼓逼神州，惜別無心學墜樓。不得回眸辭傅粉，',40,'御定全唐詩/json/683.json','["動天金鼓逼神州，惜別無心學墜樓。不得回眸辭傅粉，", "唯有此宵魂夢裏，殷勤見覓鳳池頭。"]'),
('yuding-61','薦福寺講筵偶見又別','韓偓','唐','御定全唐诗','yuding','','[]','見時濃日午，別處暮鐘殘。景色疑春盡，襟懷似酒闌。',48,'御定全唐詩/json/683.json','["見時濃日午，別處暮鐘殘。景色疑春盡，襟懷似酒闌。", "兩情含眷戀，一餉致辛酸。夜靜長廊下，難尋屐齒看。"]'),
('yuding-62','複偶見三絕','韓偓','唐','御定全唐诗','yuding','','[]','霧為襟袖玉為冠，半似羞人半忍寒。',96,'御定全唐詩/json/683.json','["霧為襟袖玉為冠，半似羞人半忍寒。", "別易會難長自歎，轉身應把淚珠彈。", "桃花臉薄難藏淚，柳葉眉長易覺愁。", "密跡未成當面笑，幾回抬眼又低頭。", "半身映竹輕聞語，一手揭簾微轉頭。", "此意別人應未覺，不勝情緒兩風流。"]'),
('yuding-63','厭花落','韓偓','唐','御定全唐诗','yuding','','[]','厭花落，人寂寞，果樹陰成燕翅齊，西園永日閑高閣。',96,'御定全唐詩/json/683.json','["厭花落，人寂寞，果樹陰成燕翅齊，西園永日閑高閣。", "後堂夾簾愁不卷，低頭悶把衣襟撚。忽然事到心中來，", "半醉狂心忍不禁，分明一任傍人見。書中說卻平生事，", "紅紙千張言不盡，至誠無語傳心印。但得鴛鴦枕臂眠，"]'),
('yuding-64','春悶偶成十二韻','韓偓','唐','御定全唐诗','yuding','','[]','阡陌懸雲壤，闌畦隔艾芝。路遙行雨懶，河闊過橋遲。',144,'御定全唐詩/json/683.json','["阡陌懸雲壤，闌畦隔艾芝。路遙行雨懶，河闊過橋遲。", "雁足應難達，狐蹤浪得疑。謝鯤吟未廢，張碩夢堪思。", "有意通情處，無言攏鬢時。格高歸斂笑，歌怨在顰眉。", "醉後金蟬重，歡餘玉燕欹。素姿淩白柰，圓頰誚紅梨。", "粉字題花筆，香箋詠柳詩。繡窗攜手約，芳草蹋青期。", "別淚開泉脈，春愁罥藕絲。相思不相信，幽恨更誰知。"]'),
('yuding-65','想得','韓偓','唐','御定全唐诗','yuding','','[]','兩重門裏玉堂前，寒食花枝月午天。',32,'御定全唐詩/json/683.json','["兩重門裏玉堂前，寒食花枝月午天。", "想得那人垂手立，嬌羞不肯上秋千。"]'),
('yuding-66','偶見背面是夕兼夢','韓偓','唐','御定全唐诗','yuding','','[]','酥凝背胛玉搓肩，輕薄紅綃覆白蓮。此夜分明來入夢，',40,'御定全唐詩/json/683.json','["酥凝背胛玉搓肩，輕薄紅綃覆白蓮。此夜分明來入夢，", "莫道人生難際會，秦樓鸞鳳有神仙。"]'),
('yuding-67','五更','韓偓','唐','御定全唐诗','yuding','','[]','秋雨五更頭，桐竹鳴騷屑。卻似殘春間，斷送花時節。',48,'御定全唐詩/json/683.json','["秋雨五更頭，桐竹鳴騷屑。卻似殘春間，斷送花時節。", "空樓雁一聲，遠屏燈半滅。繡被擁嬌寒，眉山正愁絕。"]'),
('yuding-68','有憶','韓偓','唐','御定全唐诗','yuding','','[]','晝漏迢迢夜漏遲，傾城消息杳無期。愁腸泥酒人千里，',40,'御定全唐詩/json/683.json','["晝漏迢迢夜漏遲，傾城消息杳無期。愁腸泥酒人千里，", "何時鬥帳濃香裏，分付東風與玉兒。"]'),
('yuding-69','半夜','韓偓','唐','御定全唐诗','yuding','','[]','板合數尊後，至今猶酒悲。一宵相見事，半夜獨眠時。',36,'御定全唐詩/json/683.json','["板合數尊後，至今猶酒悲。一宵相見事，半夜獨眠時。", "明朝窗下照，應有鬢如絲。"]'),
('yuding-70','信筆','韓偓','唐','御定全唐诗','yuding','','[]','睡髻休頻攏，春眉忍更長。整釵梔子重，泛酒菊花香。',48,'御定全唐詩/json/683.json','["睡髻休頻攏，春眉忍更長。整釵梔子重，泛酒菊花香。", "繡疊昏金色，羅揉損砑光。有時閑弄筆，亦畫兩鴛鴦。"]'),
('yuding-71','寄恨','韓偓','唐','御定全唐诗','yuding','','[]','秦釵枉斷長條玉，蜀紙虛留小字紅。',32,'御定全唐詩/json/683.json','["秦釵枉斷長條玉，蜀紙虛留小字紅。", "死恨物情難會處，蓮花不肯嫁春風。"]'),
('yuding-72','兩處','韓偓','唐','御定全唐诗','yuding','','[]','樓上澹山橫，樓前溝水清。憐山又憐水，兩處總牽情。',24,'御定全唐詩/json/683.json','["樓上澹山橫，樓前溝水清。憐山又憐水，兩處總牽情。"]'),
('yuding-73','擁鼻','韓偓','唐','御定全唐诗','yuding','','[]','擁鼻悲吟一向愁，寒更轉盡未回頭。綠屏無睡秋分簟，',40,'御定全唐詩/json/683.json','["擁鼻悲吟一向愁，寒更轉盡未回頭。綠屏無睡秋分簟，", "殷勤憑仗官渠水，為到西溪動釣舟。"]'),
('yuding-74','閨怨','韓偓','唐','御定全唐诗','yuding','','[]','時光潛去暗淒涼，懶對菱花暈曉妝。',32,'御定全唐詩/json/683.json','["時光潛去暗淒涼，懶對菱花暈曉妝。", "初坼秋千人寂寞，後園青草任他長。"]'),
('yuding-75','褭娜','韓偓','唐','御定全唐诗','yuding','','[]','褭娜腰肢澹薄妝，六朝宮樣窄衣裳。著詞暫見櫻桃破，',40,'御定全唐詩/json/683.json','["褭娜腰肢澹薄妝，六朝宮樣窄衣裳。著詞暫見櫻桃破，", "此時不敢分明道，風月應知暗斷腸。"]'),
('yuding-76','多情','韓偓','唐','御定全唐诗','yuding','','[]','天遣多情不自持，多情兼與病相宜。蜂偷野蜜初嘗處，',40,'御定全唐詩/json/683.json','["天遣多情不自持，多情兼與病相宜。蜂偷野蜜初嘗處，", "水香剩置金盆裏，瓊樹長須浸一枝。"]'),
('yuding-77','偶見','韓偓','唐','御定全唐诗','yuding','','[]','千金莫惜旱蓮生，一笑從教下蔡傾。仙樹有花難問種，',40,'御定全唐詩/json/683.json','["千金莫惜旱蓮生，一笑從教下蔡傾。仙樹有花難問種，", "小疊紅箋書恨字，與奴方便寄卿卿。"]'),
('yuding-78','個儂','韓偓','唐','御定全唐诗','yuding','','[]','甚感殷勤意，其如阻礙何。隔簾窺綠齒，映柱送橫波。',48,'御定全唐詩/json/683.json','["甚感殷勤意，其如阻礙何。隔簾窺綠齒，映柱送橫波。", "老大逢知少，襟懷暗喜多。因傾一尊酒，聊以慰蹉跎。"]'),
('yuding-79','無題','韓偓','唐','御定全唐诗','yuding','','[]','小檻移燈灺，空房鎖隙塵。額波風盡日，簾影月侵晨。',372,'御定全唐詩/json/683.json','["小檻移燈灺，空房鎖隙塵。額波風盡日，簾影月侵晨。", "香辣更衣後，釵梁攏鬢新。吉音聞詭計，醉語近天真。", "妝好方長歎，歡餘卻淺顰。繡屏金作屋，絲幰玉為輪。", "致意通綿竹，精誠托錦鱗。歌凝眉際恨，酒發臉邊春。", "溪紵殊傾越，樓簫豈羨秦。柳虛禳沴氣，梅實引芳津。", "樂府降清唱，宮廚減食珍。防閑襟並斂，忍妒淚休勻。", "宿飲愁縈夢，春寒瘦著人。手持雙豆蔻，的的為東鄰。", "碧瓦偏光日，紅簾不受塵。柳昏連綠野，花爛爍清晨。", "書密偷看數，情通破體新。明言終未實，暗祝始應真。", "枉道嫌偷藥，推誠鄙效顰。合成雲五色，宜作日中輪。", "照獸金塗爪，釵魚玉鏤鱗。渺彌三島浪，平遠一樓春。", "墮髻還名壽，修蛾本姓秦。棹尋聞犬洞，槎入飲牛津。", "麟脯隨重釀，霜華間八珍。錦囊霞彩爛，羅襪砑光勻。", "羞澀佯牽伴，嬌饒欲泥人。偷兒難捉搦，慎莫共比鄰。", "紫蠟融花蒂，紅綿拭鏡塵。夢狂翻惜夜，妝懶厭淩晨。", "茜袖啼痕數，香箋墨色新。"]'),
('yuding-80','倒押前韻','韓偓','唐','御定全唐诗','yuding','','[]','白下同歸路，烏衣枉作鄰。佩聲猶隔箔，香氣已迎人。',168,'御定全唐詩/json/683.json','["白下同歸路，烏衣枉作鄰。佩聲猶隔箔，香氣已迎人。", "酒勸杯須滿，書羞字不勻。歌憐黃竹怨，味實碧桃珍。", "翦燭非良策，當關是要津。東阿初度洛，楊惲舊家秦。", "粉化橫波溢，衫輕曉霧春。鴉黃雙鳳翅，麝月半魚鱗。", "別袂翻如浪，回腸轉似輪。後期才注腳，前事又含顰。", "縱有才難詠，寧無畫逼真。天香聞更有，瓊樹見長新。", "鬥草常更僕，迷鬮誤達晨。嗅花判不得，檀注惹風塵。"]'),
('yuding-81','閨情','韓偓','唐','御定全唐诗','yuding','','[]','輕風滴礫動簾鉤，宿酒猶酣懶卸頭。但覺夜深花有露，',40,'御定全唐詩/json/683.json','["輕風滴礫動簾鉤，宿酒猶酣懶卸頭。但覺夜深花有露，", "敲折玉釵歌轉咽，一聲聲作兩眉愁。"]'),
('yuding-82','自負','韓偓','唐','御定全唐诗','yuding','','[]','人許風流自負才，偷桃三度到瑤台。',32,'御定全唐詩/json/683.json','["人許風流自負才，偷桃三度到瑤台。", "至今衣領胭脂在，曾被謫仙痛咬來。"]'),
('yuding-83','天涼','韓偓','唐','御定全唐诗','yuding','','[]','愁來卻訝天涼早，思倦翻嫌夜漏遲。',32,'御定全唐詩/json/683.json','["愁來卻訝天涼早，思倦翻嫌夜漏遲。", "何處山川孤館裏，向燈彎盡一雙眉。"]'),
('yuding-84','日高','韓偓','唐','御定全唐诗','yuding','','[]','朦朧猶記管弦聲，噤z9餘寒酒半醒。',33,'御定全唐詩/json/683.json','["朦朧猶記管弦聲，噤z9餘寒酒半醒。", "春暮日高簾半卷，落花和雨滿中庭。"]'),
('yuding-85','夕陽','韓偓','唐','御定全唐诗','yuding','','[]','花前灑淚臨寒食，醉裏回頭問夕陽。',32,'御定全唐詩/json/683.json','["花前灑淚臨寒食，醉裏回頭問夕陽。", "不管相思人老盡，朝朝容易下西牆。"]'),
('yuding-86','舊館','韓偓','唐','御定全唐诗','yuding','','[]','前歡往恨分明在，酒興詩情大半亡。',32,'御定全唐詩/json/683.json','["前歡往恨分明在，酒興詩情大半亡。", "還似牆西紫荊樹，殘花摘索映高塘。"]'),
('yuding-87','中春憶贈','韓偓','唐','御定全唐诗','yuding','','[]','年年長是阻佳期，萬種恩情只自知。',32,'御定全唐詩/json/683.json','["年年長是阻佳期，萬種恩情只自知。", "春色轉添惆悵事，似君花發兩三枝。"]'),
('yuding-88','春恨','韓偓','唐','御定全唐诗','yuding','','[]','殘夢依依酒力餘，城頭畫角伴啼烏。',32,'御定全唐詩/json/683.json','["殘夢依依酒力餘，城頭畫角伴啼烏。", "平明未卷西樓幕，院靜時聞響轆轤。"]'),
('yuding-89','秋千','韓偓','唐','御定全唐诗','yuding','','[]','池塘夜歇清明雨，繞院無塵近花塢。五絲繩系出牆遲，',40,'御定全唐詩/json/683.json','["池塘夜歇清明雨，繞院無塵近花塢。五絲繩系出牆遲，", "無語兼動所思愁，轉眼看天一長吐。"]'),
('yuding-90','長信宮二首','韓偓','唐','御定全唐诗','yuding','','[]','天上夢魂何杳杳，宮中消息太沉沉。',64,'御定全唐詩/json/683.json','["天上夢魂何杳杳，宮中消息太沉沉。", "君恩不似黃金井，一處團圓萬丈深。", "天上鳳凰休寄夢，人間鸚鵡舊堪悲。", "平生心緒無人識，一隻金梭萬丈絲。"]'),
('yuding-91','句','韓偓','唐','御定全唐诗','yuding','','[]','豈獨鴟夷解歸去，五湖漁艇且餔糟。（聞再除戎曹，',23,'御定全唐詩/json/683.json','["豈獨鴟夷解歸去，五湖漁艇且餔糟。（聞再除戎曹，"]'),
('yuding-0','奉和禦制','吳融','唐','御定全唐诗','yuding','','[]','嶽寺清秋霽，宸遊永日閑。霓旌森物外，鳳吹落人間。',48,'御定全唐詩/json/684.json','["嶽寺清秋霽，宸遊永日閑。霓旌森物外，鳳吹落人間。", "玉漱穿城水，屏開對闕山。皆知聖情悅，麗藻灑芳蘭。"]'),
('yuding-1','和集賢相公西溪侍宴觀競渡','吳融','唐','御定全唐诗','yuding','','[]','片水聳層橋，祥煙靄慶霄。晝花鋪廣宴，晴電閃飛橈。',48,'御定全唐詩/json/684.json','["片水聳層橋，祥煙靄慶霄。晝花鋪廣宴，晴電閃飛橈。", "浪疊搖仙仗，風微定彩標。都人同盛觀，不覺在行朝。"]'),
('yuding-2','山居即事四首','吳融','唐','御定全唐诗','yuding','','[]','桂樹秋來風滿枝，碧岩歸日免乖期。',128,'御定全唐詩/json/684.json','["桂樹秋來風滿枝，碧岩歸日免乖期。", "故人盡向蟾宮折，獨我攀條欲寄誰。", "不傲南窗且采樵，乾鬆每帶濕雲燒。", "庖廚卻得長兼味，三秀芝根五朮苗。", "萬事翛然只有棋，小軒高淨簟涼時。", "闌珊半局和微醉，花落中庭樹影移。", "無鄰無裏不成村，水曲雲重掩石門。", "何用深求避秦客，吾家便是武陵源。"]'),
('yuding-3','紅白牡丹','吳融','唐','御定全唐诗','yuding','','[]','不必繁弦不必歌，靜中相對更情多。殷鮮一半霞分綺，',40,'御定全唐詩/json/684.json','["不必繁弦不必歌，靜中相對更情多。殷鮮一半霞分綺，", "重來應共今來別，風墮香殘襯綠莎。"]'),
('yuding-4','中秋陪熙用學士禁中玩月','吳融','唐','御定全唐诗','yuding','','[]','月圓年十二，秋半每多陰。此夕無纖靄，同君宿禁林。',72,'御定全唐詩/json/684.json','["月圓年十二，秋半每多陰。此夕無纖靄，同君宿禁林。", "未高知海闊，當午見宮深。衣似繁霜透，身疑積水沈。", "遭逢陪侍輦，歸去憶抽簪。太液池南岸，相期到曉吟。"]'),
('yuding-5','題豪家故池','吳融','唐','御定全唐诗','yuding','','[]','歲久無泉引，春來仰雨流。萍枯黏朽檻，沙淺露沉舟。',48,'御定全唐詩/json/684.json','["歲久無泉引，春來仰雨流。萍枯黏朽檻，沙淺露沉舟。", "照影人何在，持竿客寄遊。翛然興廢外，回首謝眠鷗。"]'),
('yuding-6','偶題','吳融','唐','御定全唐诗','yuding','','[]','賤子曾塵國士知，登門倒屣憶當時。西州酌盡看花酒，',40,'御定全唐詩/json/684.json','["賤子曾塵國士知，登門倒屣憶當時。西州酌盡看花酒，", "烏衣舊宅猶能認，粉竹金松一兩枝。"]'),
('yuding-7','渚宮立春書懷','吳融','唐','御定全唐诗','yuding','','[]','春候侵殘臘，江蕪綠已齊。風高鶯囀澀，雨密雁飛低。',48,'御定全唐詩/json/684.json','["春候侵殘臘，江蕪綠已齊。風高鶯囀澀，雨密雁飛低。", "向日心須在，歸朝路欲迷。近聞驚禦火，猶及灞陵西。"]'),
('yuding-8','聞李翰林游池上有寄','吳融','唐','御定全唐诗','yuding','','[]','花飛絮落水和流，玉署詞臣奉詔遊。四面看人隨畫鷁，',40,'御定全唐詩/json/684.json','["花飛絮落水和流，玉署詞臣奉詔遊。四面看人隨畫鷁，", "不為禁鐘催入宿，前峰月上未回舟。"]'),
('yuding-9','谷口寓居偶題','吳融','唐','御定全唐诗','yuding','','[]','涔涔病骨怯朝天，穀口歸來取性眠。峭壁削成開畫障，',40,'御定全唐詩/json/684.json','["涔涔病骨怯朝天，穀口歸來取性眠。峭壁削成開畫障，", "已熟前峰采芝徑，更於何處養殘年。"]'),
('yuding-10','無題','吳融','唐','御定全唐诗','yuding','','[]','萬態千端一瞬中，沁園蕪沒佇秋風。鵁鶄夜警池塘冷，',40,'御定全唐詩/json/684.json','["萬態千端一瞬中，沁園蕪沒佇秋風。鵁鶄夜警池塘冷，", "今朝陌上相非者，曾此歌鐘幾醉同。"]'),
('yuding-11','賦雪','吳融','唐','御定全唐诗','yuding','','[]','一夜陰風度，平明顥氣交。未知融結判，唯見混茫包。',120,'御定全唐詩/json/684.json','["一夜陰風度，平明顥氣交。未知融結判，唯見混茫包。", "路莫藏行跡，林難出樹梢。氣應封獸穴，險必墮禽巢。", "影密燈回照，聲繁竹送敲。玩宜蘇讓點，餐稱蜜勻抄。", "結凍防魚躍，黏沙費馬跑。爐寒資爇荻，屋暖賴編茅。", "遠不分山疊，低宜失地坳。闌幹高百尺，新霽若為拋。"]'),
('yuding-12','寄僧','吳融','唐','御定全唐诗','yuding','','[]','柳拂池光一點清，紫方袍袖杖藜行。偶傳新句來中禁，',40,'御定全唐詩/json/684.json','["柳拂池光一點清，紫方袍袖杖藜行。偶傳新句來中禁，", "應憐正視淮王詔，不識東林物外情。"]'),
('yuding-13','酬僧','吳融','唐','御定全唐诗','yuding','','[]','吾師既續惠休才，況值高秋萬象開。吟處遠峰橫落照，',40,'御定全唐詩/json/684.json','["吾師既續惠休才，況值高秋萬象開。吟處遠峰橫落照，", "聞說近郊寒尚綠，登臨應待一追陪。"]'),
('yuding-14','題延壽坊東南角古池','吳融','唐','御定全唐诗','yuding','','[]','蔓草蕭森曲岸摧，水籠沙淺露莓苔。更無蔟蔟紅妝點，',40,'御定全唐詩/json/684.json','["蔓草蕭森曲岸摧，水籠沙淺露莓苔。更無蔟蔟紅妝點，", "繁華自古皆相似，金穀荒園土一堆。"]'),
('yuding-15','登鸛雀樓','吳融','唐','御定全唐诗','yuding','','[]','鳥在林梢腳底看，夕陽無際戍煙殘。凍開河水奔渾急，',40,'御定全唐詩/json/684.json','["鳥在林梢腳底看，夕陽無際戍煙殘。凍開河水奔渾急，", "祖鞭掉折徒為爾，贏得雲溪負釣竿。"]'),
('yuding-16','和峽州馮使君題所居','吳融','唐','御定全唐诗','yuding','','[]','三年拔薤成仁政，一日誅茅葺所居。曉岫近排吟閣冷，',40,'御定全唐詩/json/684.json','["三年拔薤成仁政，一日誅茅葺所居。曉岫近排吟閣冷，", "記得街西鄰舍否，投荒南去五千餘。"]'),
('yuding-17','秋日感事','吳融','唐','御定全唐诗','yuding','','[]','一葉飄然夕照沈，世間何事不經心。幾人欲話雲台峻，',40,'御定全唐詩/json/684.json','["一葉飄然夕照沈，世間何事不經心。幾人欲話雲台峻，", "自憐情為多憂動，不為西風白露吟。"]'),
('yuding-18','鶯','吳融','唐','御定全唐诗','yuding','','[]','日落林西鳥未知，自先飛上最高枝。千啼萬語不離恨，',40,'御定全唐詩/json/684.json','["日落林西鳥未知，自先飛上最高枝。千啼萬語不離恨，", "謝家園裏成吟久，只欠池塘一句詩。"]'),
('yuding-19','次韻和王員外雜游四韻','吳融','唐','御定全唐诗','yuding','','[]','一分難減亦難加，得似溪頭浣越紗。兩槳慣邀催去艇，',40,'御定全唐詩/json/684.json','["一分難減亦難加，得似溪頭浣越紗。兩槳慣邀催去艇，", "誰見玉郎腸斷處，露床風簟半欹斜。"]'),
('yuding-20','秋事','吳融','唐','御定全唐诗','yuding','','[]','江天暑氣自涼清，物候須知一雨成。松竹健來唯欠語，',40,'御定全唐詩/json/684.json','["江天暑氣自涼清，物候須知一雨成。松竹健來唯欠語，", "更欲輕橈放煙浪，葦花深處睡秋聲。"]'),
('yuding-21','和陸拾遺題諫院松','吳融','唐','御定全唐诗','yuding','','[]','落落孤松何處尋，月華西畔結根深。曉含仙掌三清露，',40,'御定全唐詩/json/684.json','["落落孤松何處尋，月華西畔結根深。曉含仙掌三清露，", "碧岩秋澗休相望，捧日元須在禁林。"]'),
('yuding-22','題揚子津亭','吳融','唐','御定全唐诗','yuding','','[]','揚子江津十四經，紀行文字遍長亭。驚人旅鬢斬新白，',40,'御定全唐詩/json/684.json','["揚子江津十四經，紀行文字遍長亭。驚人旅鬢斬新白，", "可憐不識生離者，數點漁帆落暮汀。"]'),
('yuding-23','閑望','吳融','唐','御定全唐诗','yuding','','[]','三點五點映山雨，一枝兩枝臨水花。蛺蝶狂飛掠芳草，',40,'御定全唐詩/json/684.json','["三點五點映山雨，一枝兩枝臨水花。蛺蝶狂飛掠芳草，", "東遷西去俱無計，卻羨暝歸林上鴉。"]'),
('yuding-24','雪後過昭應','吳融','唐','御定全唐诗','yuding','','[]','路過章台氣象寬，九重城闕在雲端。煙含上苑沉沉紫，',40,'御定全唐詩/json/684.json','["路過章台氣象寬，九重城闕在雲端。煙含上苑沉沉紫，", "灞川南北真圖畫，更待殘陽一望看。"]'),
('yuding-25','商人','吳融','唐','御定全唐诗','yuding','','[]','百尺竿頭五兩斜，此生何處不為家。北拋衡岳南過雁，',40,'御定全唐詩/json/684.json','["百尺竿頭五兩斜，此生何處不為家。北拋衡岳南過雁，", "隨風逐浪年年別，卻笑如期八月槎。"]'),
('yuding-26','岐下聞杜鵑','吳融','唐','御定全唐诗','yuding','','[]','化去蠻鄉北，飛來渭水西。為多亡國恨，不忍故山啼。',72,'御定全唐詩/json/684.json','["化去蠻鄉北，飛來渭水西。為多亡國恨，不忍故山啼。", "怨已驚秦鳳，靈應識漢雞。數聲煙漠漠，餘思草萋萋。", "樓迥波無際，林昏日又低。如何不腸斷，家近五雲溪。"]'),
('yuding-27','雨後聞思歸樂二首','吳融','唐','御定全唐诗','yuding','','[]','山禽連夜叫，兼雨未嘗休。盡道思歸樂，應多離別愁。',96,'御定全唐詩/json/684.json','["山禽連夜叫，兼雨未嘗休。盡道思歸樂，應多離別愁。", "我家方旅食，故國在滄洲。聞此不能寐，青燈茆屋幽。", "一夜鳥飛鳴，關關徹五更。似因歸路隔，長使別魂驚。", "未省愁雨暗，就中傷月明。須知越吟客，欹枕不勝情。"]'),
('yuding-28','中夜聞啼禽','吳融','唐','御定全唐诗','yuding','','[]','漠漠蒼蒼未五更，宿禽何處兩三聲。若非西澗回波觸，',40,'御定全唐詩/json/684.json','["漠漠蒼蒼未五更，宿禽何處兩三聲。若非西澗回波觸，", "此時歸夢隨腸斷，半壁殘燈閃閃明。"]'),
('yuding-29','靈池縣見早梅','吳融','唐','御定全唐诗','yuding','','[]','小園晴日見寒梅，一寸鄉心萬里回。春日暖時拋笠澤，',40,'御定全唐詩/json/684.json','["小園晴日見寒梅，一寸鄉心萬里回。春日暖時拋笠澤，", "待勒燕然歸未得，雪枝南畔少徘徊。"]'),
('yuding-30','野廟','吳融','唐','御定全唐诗','yuding','','[]','古原荒廟掩莓苔，何處喧喧鼓笛來。',32,'御定全唐詩/json/684.json','["古原荒廟掩莓苔，何處喧喧鼓笛來。", "日暮鳥歸人散盡，野風吹起紙錢灰。"]'),
('yuding-31','閒書','吳融','唐','御定全唐诗','yuding','','[]','接鷺陪鸞漫得群，未如高臥紫溪雲。晉陽起義尋常見，',40,'御定全唐詩/json/684.json','["接鷺陪鸞漫得群，未如高臥紫溪雲。晉陽起義尋常見，", "回看帶礪山河者，濟得危時沒舊勳。"]'),
('yuding-32','寄貫休上人','吳融','唐','御定全唐诗','yuding','','[]','別來如夢亦如雲，八字微言不復聞。世上浮沈應念我，',40,'御定全唐詩/json/684.json','["別來如夢亦如雲，八字微言不復聞。世上浮沈應念我，", "見擬沃州尋舊約，且教丹頂許為鄰。"]'),
('yuding-33','書懷','吳融','唐','御定全唐诗','yuding','','[]','傍岩依樹結簷楹，夏物蕭疏景更清。灘響忽高何處雨，',40,'御定全唐詩/json/684.json','["傍岩依樹結簷楹，夏物蕭疏景更清。灘響忽高何處雨，", "爭得便誇饒勝事，九衢塵裏免勞生。"]'),
('yuding-34','重陽日荊州作','吳融','唐','御定全唐诗','yuding','','[]','萬里投荒已自哀，高秋寓目更徘徊。濁醪任冷難辭醉，',40,'御定全唐詩/json/684.json','["萬里投荒已自哀，高秋寓目更徘徊。濁醪任冷難辭醉，", "驚時感事俱無奈，不待殘陽下楚台。"]'),
('yuding-35','寄貫休','吳融','唐','御定全唐诗','yuding','','[]','休公何處在，知我宦情無。已似馮唐老，方知武子愚。',48,'御定全唐詩/json/684.json','["休公何處在，知我宦情無。已似馮唐老，方知武子愚。", "一身仍更病，雙闕又須趨。若得重相見，冥心學半銖。"]'),
('yuding-36','秋日渚宮即事','吳融','唐','御定全唐诗','yuding','','[]','漠漠澹雲煙，秋歸澤國天。風高還促燕，雨細未妨蟬。',48,'御定全唐詩/json/684.json','["漠漠澹雲煙，秋歸澤國天。風高還促燕，雨細未妨蟬。", "靜引荒城望，涼驚旅枕眠。更堪憔悴裏，欲泛洞庭船。"]'),
('yuding-37','荊州寓居書懷','吳融','唐','御定全唐诗','yuding','','[]','一室四無鄰，荒郊接古津。幽閒消俗態，搖落露家貧。',48,'御定全唐詩/json/684.json','["一室四無鄰，荒郊接古津。幽閒消俗態，搖落露家貧。", "絕跡思浮海，修書懶寄秦。東西不復問，翻笑泣岐人。"]'),
('yuding-38','和嚴諫議蕭山廟十韻','吳融','唐','御定全唐诗','yuding','','[]','澤國瞻遺廟，雲韶仰舊名。一隅連障影，千仞落泉聲。',120,'御定全唐詩/json/684.json','["澤國瞻遺廟，雲韶仰舊名。一隅連障影，千仞落泉聲。", "老狖尋危棟，秋蛇束畫楹。路長資稅駕，歲儉絕豐盛。", "默默雖難測，昭昭本至平。豈知遷去客，自有複來兵。", "美舜歌徒作，欺堯犬正獰。近兼聞順動，敢複怨徂征。", "日出天須霽，風休海自清。肺腸無處說，一為啟聰明。"]'),
('yuding-39','松江晚泊','吳融','唐','御定全唐诗','yuding','','[]','樹遠天疑盡，江奔地欲隨。孤帆落何處，殘日更新離。',48,'御定全唐詩/json/684.json','["樹遠天疑盡，江奔地欲隨。孤帆落何處，殘日更新離。", "客是淒涼本，情為系滯枝。寸腸無計免，應只楚猿知。"]'),
('yuding-40','湖州溪樓書獻鄭員外','吳融','唐','御定全唐诗','yuding','','[]','危檻等飛檣，閑追晚際涼。青林上雨色，白鳥破溪光。',48,'御定全唐詩/json/684.json','["危檻等飛檣，閑追晚際涼。青林上雨色，白鳥破溪光。", "目以高須極，心因靜更傷。唯公舊相許，早晚侍長楊。"]'),
('yuding-41','秋興','吳融','唐','御定全唐诗','yuding','','[]','微雨過菰葦，野居生早涼。襟期漸蕭灑，精爽欲飛揚。',48,'御定全唐詩/json/684.json','["微雨過菰葦，野居生早涼。襟期漸蕭灑，精爽欲飛揚。", "魚買罾頭活，酒沽船上香。不緣人不用，始道靜勝忙。"]'),
('yuding-42','端居','吳融','唐','御定全唐诗','yuding','','[]','片雨過前汀，端居枕簟清。病魔隨暑退，詩思傍涼生。',48,'御定全唐詩/json/684.json','["片雨過前汀，端居枕簟清。病魔隨暑退，詩思傍涼生。", "別燕殷勤語，殘蟬仿佛鳴。古來悲不盡，況我本多情。"]'),
('yuding-43','途中','吳融','唐','御定全唐诗','yuding','','[]','一棹歸何處，蒼茫落照昏。無人應失路，有樹始知春。',48,'御定全唐詩/json/684.json','["一棹歸何處，蒼茫落照昏。無人應失路，有樹始知春。", "湖岸春耕廢，江城戰鼓喧。儒冠解相誤，學劍盡乘軒。"]'),
('yuding-44','西陵夜居','吳融','唐','御定全唐诗','yuding','','[]','寒潮落遠汀，暝色入柴扃。漏永沉沉靜，燈孤的的清。',48,'御定全唐詩/json/684.json','["寒潮落遠汀，暝色入柴扃。漏永沉沉靜，燈孤的的清。", "林風移宿鳥，池雨定流螢。盡夜成愁絕，啼蛩莫近庭。"]'),
('yuding-45','燕雛','吳融','唐','御定全唐诗','yuding','','[]','掠水身猶重，偎風力尚微。瓦苔難定立，簷雨忽喧歸。',48,'御定全唐詩/json/684.json','["掠水身猶重，偎風力尚微。瓦苔難定立，簷雨忽喧歸。", "未識重溟遠，先愁一葉飛。銜泥在他日，兩兩占春暉。"]'),
('yuding-46','新秋','吳融','唐','御定全唐诗','yuding','','[]','白髮又經秋，端居海上洲。無機因事發，有涕為時流。',48,'御定全唐詩/json/684.json','["白髮又經秋，端居海上洲。無機因事發，有涕為時流。", "新酒乘涼壓，殘棋隔夜收。公車無路入，同拜老閑侯。"]'),
('yuding-47','題越州法華寺','吳融','唐','御定全唐诗','yuding','','[]','寺在五峰陰，穿緣一徑尋。雲藏古殿暗，石護小房深。',48,'御定全唐詩/json/684.json','["寺在五峰陰，穿緣一徑尋。雲藏古殿暗，石護小房深。", "宿鳥連僧定，寒猿應客吟。上方應見海，月出試登臨。"]'),
('yuding-48','寒食洛陽道','吳融','唐','御定全唐诗','yuding','','[]','路岐無樂處，時節倍思家。彩索颺輕吹，黃鸝啼落花。',48,'御定全唐詩/json/684.json','["路岐無樂處，時節倍思家。彩索颺輕吹，黃鸝啼落花。", "連幹馳寶馬，曆祿鬥香車。行客勝回首，看看春日斜。"]'),
('yuding-49','憶事','吳融','唐','御定全唐诗','yuding','','[]','去年花下把金卮，曾賦楊花數句詩。',32,'御定全唐詩/json/684.json','["去年花下把金卮，曾賦楊花數句詩。", "回首朱門閉荒草，如今愁到牡丹時。"]'),
('yuding-50','金陵遇悟空上人','吳融','唐','御定全唐诗','yuding','','[]','東閣無人事渺茫，老僧持缽過丹陽。',32,'御定全唐詩/json/684.json','["東閣無人事渺茫，老僧持缽過丹陽。", "十年棲止如何報，好與南譙剩炷香。"]'),
('yuding-51','途中','吳融','唐','御定全唐诗','yuding','','[]','柳弱風長在，雲輕雨易休。不勞芳草色，更惹夕陽愁。',48,'御定全唐詩/json/684.json','["柳弱風長在，雲輕雨易休。不勞芳草色，更惹夕陽愁。", "萬里獨歸去，五陵無與遊。春心漸傷盡，何處有高樓。"]'),
('yuding-52','秋園','吳融','唐','御定全唐诗','yuding','','[]','始憐春草細霏霏，不覺秋來綠漸稀。',32,'御定全唐詩/json/684.json','["始憐春草細霏霏，不覺秋來綠漸稀。", "惆悵擷芳人散盡，滿園煙露蝶高飛。"]'),
('yuding-53','富春','吳融','唐','御定全唐诗','yuding','','[]','天下有水亦有山，富春山水非人寰。',32,'御定全唐詩/json/684.json','["天下有水亦有山，富春山水非人寰。", "長川不是春來綠，千峰倒影落其間。"]'),
('yuding-54','山居即事','吳融','唐','御定全唐诗','yuding','','[]','小亭前面接青崖，白石交加襯綠苔。',32,'御定全唐詩/json/684.json','["小亭前面接青崖，白石交加襯綠苔。", "日暮松聲滿階砌，不關風雨鶴歸來。"]'),
('yuding-55','寓言','吳融','唐','御定全唐诗','yuding','','[]','非明非暗朦朦月，不暖不寒慢慢風。',32,'御定全唐詩/json/684.json','["非明非暗朦朦月，不暖不寒慢慢風。", "獨臥空床好天氣，平生閒事到心中。"]'),
('yuding-56','華清宮二首','吳融','唐','御定全唐诗','yuding','','[]','四郊飛雪暗雲端，唯此宮中落旋幹。',64,'御定全唐詩/json/684.json','["四郊飛雪暗雲端，唯此宮中落旋幹。", "綠樹碧簷相掩映，無人知道外邊寒。", "長生秘殿倚青蒼，擬敵金庭不死鄉。", "無奈逝川東去急，秦陵松柏滿殘陽。"]'),
('yuding-57','過九成宮','吳融','唐','御定全唐诗','yuding','','[]','鳳輦東歸二百年，九成宮殿半荒阡。魏公碑字封蒼蘚，',40,'御定全唐詩/json/684.json','["鳳輦東歸二百年，九成宮殿半荒阡。魏公碑字封蒼蘚，", "升平舊事無人說，萬疊青山但一川。"]'),
('yuding-58','出潼關','吳融','唐','御定全唐诗','yuding','','[]','重門隨地險，一徑入天開。華岳眼前盡，黃河腳底來。',48,'御定全唐詩/json/684.json','["重門隨地險，一徑入天開。華岳眼前盡，黃河腳底來。", "飛軒何滿路，丹陛正求才。獨我疏慵質，飄然又此回。"]'),
('yuding-59','過丹陽','吳融','唐','御定全唐诗','yuding','','[]','雲陽縣郭半郊坰，風雨蕭條萬古情。山帶梁朝陵路斷，',40,'御定全唐詩/json/684.json','["雲陽縣郭半郊坰，風雨蕭條萬古情。山帶梁朝陵路斷，", "遺事滿懷兼滿目，不堪孤棹艤荒城。"]'),
('yuding-60','和人題武城寺','吳融','唐','御定全唐诗','yuding','','[]','神清已覺三清近，目斷仍勞萬象牽。渭水遠含秋草渡，',40,'御定全唐詩/json/684.json','["神清已覺三清近，目斷仍勞萬象牽。渭水遠含秋草渡，", "別有闌幹壓行路，看人塵土竟流年。"]'),
('yuding-61','長安裏中聞猿','吳融','唐','御定全唐诗','yuding','','[]','夾巷重門似海深，楚猿爭得此中吟。一聲紫陌才回首，',40,'御定全唐詩/json/684.json','["夾巷重門似海深，楚猿爭得此中吟。一聲紫陌才回首，", "無因永夜聞清嘯，禁路人歸月自沈。"]'),
('yuding-62','岐下聞子規','吳融','唐','御定全唐诗','yuding','','[]','劍閣西南遠鳳台，蜀魂何事此飛來。偶因隴樹相迷至，',40,'御定全唐詩/json/684.json','["劍閣西南遠鳳台，蜀魂何事此飛來。偶因隴樹相迷至，", "誰憐越客曾聞處，月落江平曉霧開。"]'),
('yuding-63','敷水有丐者雲是馬侍中諸孫，憫而有贈','吳融','唐','御定全唐诗','yuding','','[]','天地塵昏九鼎危，大貂曾出武侯師。一心忠赤山河見，',40,'御定全唐詩/json/684.json','["天地塵昏九鼎危，大貂曾出武侯師。一心忠赤山河見，", "而今不要教人識，正藉將軍死鬥時。"]'),
('yuding-64','還俗尼','吳融','唐','御定全唐诗','yuding','','[]','柳眉梅額倩妝新，笑脫袈裟得舊身。三峽卻為行雨客，',40,'御定全唐詩/json/684.json','["柳眉梅額倩妝新，笑脫袈裟得舊身。三峽卻為行雨客，", "寄語江南徐孝克，一生長短托清塵。"]'),
('yuding-65','彭門用兵後經汴路三首','吳融','唐','御定全唐诗','yuding','','[]','長亭一望一徘徊，千里關河百戰來。細柳舊營猶鎖月，',120,'御定全唐詩/json/684.json','["長亭一望一徘徊，千里關河百戰來。細柳舊營猶鎖月，", "若比江南更牢落，子山詞賦莫興哀。", "隋堤風物已淒涼，堤下仍多舊戰場。金鏃有苔人拾得，", "獨上寒城正愁絕，戍鼙驚起雁行行。", "鐵馬雲旗夢渺茫，東來無處不堪傷。風吹白草人行少，", "曾為塞北閒遊客，遼水天山未斷腸。"]'),
('yuding-66','寄殿院高侍禦','吳融','唐','御定全唐诗','yuding','','[]','黃梅雨細冪長洲，柳密花疏水慢流。釣艇正尋逋客去，',40,'御定全唐詩/json/684.json','["黃梅雨細冪長洲，柳密花疏水慢流。釣艇正尋逋客去，", "一夜自憐無羽翼，獨當何遜滴階愁。"]'),
('yuding-67','新安道中玩流水','吳融','唐','御定全唐诗','yuding','','[]','一渠春碧弄潺潺，密竹繁花掩映間。看處便須終日住，',40,'御定全唐詩/json/684.json','["一渠春碧弄潺潺，密竹繁花掩映間。看處便須終日住，", "上卻征車再回首，了然塵土不相關。"]'),
('yuding-68','憶釣舟','吳融','唐','御定全唐诗','yuding','','[]','青山小隱枕潺湲，一葉垂綸幾溯沿。後浦春風隨興去，',40,'御定全唐詩/json/684.json','["青山小隱枕潺湲，一葉垂綸幾溯沿。後浦春風隨興去，", "回首無人寄惆悵，九衢塵土困揚鞭。"]'),
('yuding-69','靈寶縣西側津','吳融','唐','御定全唐诗','yuding','','[]','碧溪瀲瀲流殘陽，晴沙兩兩眠鴛鴦。柳花無賴苦多暇，',40,'御定全唐詩/json/684.json','["碧溪瀲瀲流殘陽，晴沙兩兩眠鴛鴦。柳花無賴苦多暇，", "高歌一曲垂鞭去，盡日無人識楚狂。"]'),
('yuding-70','即席','吳融','唐','御定全唐诗','yuding','','[]','家住叢台舊，名參絳圃新。醉波疑奪燭，嬌態欲沈春。',48,'御定全唐詩/json/684.json','["家住叢台舊，名參絳圃新。醉波疑奪燭，嬌態欲沈春。", "伴雨聊過楚，歸雲定占秦。桃花正濃暖，爭不浪迷人。"]'),
('yuding-71','出遲','吳融','唐','御定全唐诗','yuding','','[]','園密花藏易，樓深月到難。酒虛留客盡，燈暗遠更殘。',48,'御定全唐詩/json/684.json','["園密花藏易，樓深月到難。酒虛留客盡，燈暗遠更殘。", "麝想眉間印，鴉知頂上盤。文王之囿小，莫惜借人看。"]'),
('yuding-72','送僧歸日本國','吳融','唐','御定全唐诗','yuding','','[]','滄溟分故國，渺渺泛杯歸。天盡終期到，人生此別稀。',48,'御定全唐詩/json/684.json','["滄溟分故國，渺渺泛杯歸。天盡終期到，人生此別稀。", "無風亦駭浪，未午已斜暉。系帛何須雁，金烏日日飛。"]'),
('yuding-73','送僧歸破山寺','吳融','唐','御定全唐诗','yuding','','[]','萬里指吳山，高秋杖錫還。別來雙闕老，歸去片雲閑。',48,'御定全唐詩/json/684.json','["萬里指吳山，高秋杖錫還。別來雙闕老，歸去片雲閑。", "師在有無外，我嬰塵土間。居然本相別，不要慘離顏。"]'),
('yuding-74','夏夜有寄','吳融','唐','御定全唐诗','yuding','','[]','月上簟如水，軒高簾在鉤。竹聲寒不夏，蛩思靜先秋。',48,'御定全唐詩/json/684.json','["月上簟如水，軒高簾在鉤。竹聲寒不夏，蛩思靜先秋。", "偶得清宵興，方知白日愁。所思何處遠，斜漢欲低流。"]'),
('yuding-75','春詞','吳融','唐','御定全唐诗','yuding','','[]','鸞鏡長侵夜，鴛衾不識寒。羞多轉面語，妒極定睛看。',48,'御定全唐詩/json/684.json','["鸞鏡長侵夜，鴛衾不識寒。羞多轉面語，妒極定睛看。", "金市舊居近，鈿車新造寬。春期莫相誤，一日百花殘。"]'),
('yuding-76','汴上晚泊','吳融','唐','御定全唐诗','yuding','','[]','亭上風猶急，橋邊月已斜。柳寒難吐絮，浪濁不成花。',48,'御定全唐詩/json/684.json','["亭上風猶急，橋邊月已斜。柳寒難吐絮，浪濁不成花。", "岐路春三月，園林海一涯。蕭然正無寐，夜櫓莫咿啞。"]'),
('yuding-77','送僧南游','吳融','唐','御定全唐诗','yuding','','[]','戰鼙鳴未已，瓶屨抵何鄉。偶別塵中易，貪歸物外忙。',48,'御定全唐詩/json/684.json','["戰鼙鳴未已，瓶屨抵何鄉。偶別塵中易，貪歸物外忙。", "後蟬拋鄠杜，先雁下瀟湘。不得從師去，殷勤謝草堂。"]'),
('yuding-78','戲','吳融','唐','御定全唐诗','yuding','','[]','恨極同填海，情長抵導江。丁香從小結，蓮子徹枝雙。',48,'御定全唐詩/json/684.json','["恨極同填海，情長抵導江。丁香從小結，蓮子徹枝雙。", "整髻花當檻，吹燈月在窗。秦台非久計，早晚降霓幢。"]'),
('yuding-79','雪中寄盧延讓秀才','吳融','唐','御定全唐诗','yuding','','[]','苦貧皆共雪，吾子豈同悲。永日應無食，經宵必有詩。',48,'御定全唐詩/json/684.json','["苦貧皆共雪，吾子豈同悲。永日應無食，經宵必有詩。", "渚宮寒過節，華省試臨期。努力圖西去，休將凍餒辭。"]'),
('yuding-0','花村六韻','吳融','唐','御定全唐诗','yuding','','[]','地勝非離郭，花深故號村。已憐梁雪重，仍愧楚雲繁。',72,'御定全唐詩/json/685.json','["地勝非離郭，花深故號村。已憐梁雪重，仍愧楚雲繁。", "山近當吟冷，泉高入夢喧。依稀小有洞，邂逅武陵源。", "月好頻移座，風輕莫閉門。流鶯更多思，百囀待黃昏。"]'),
('yuding-1','賦雪十韻','吳融','唐','御定全唐诗','yuding','','[]','雨凍輕輕下，風乾淅淅吹。喜勝花發處，驚似客來時。',120,'御定全唐詩/json/685.json','["雨凍輕輕下，風乾淅淅吹。喜勝花發處，驚似客來時。", "河靜膠行棹，岩空響折枝。終無鷓鴣識，先有鶺鴒知。", "馬勢晨爭急，雕聲晚更饑。替霜嚴柏署，藏月上龍墀。", "百尺樓堪倚，千錢酒要追。朝歸紫閣早，漏出建章遲。", "臘候何曾爽，春工是所資。遙知故溪柳，排比萬條絲。"]'),
('yuding-2','溪邊','吳融','唐','御定全唐诗','yuding','','[]','溪邊花滿枝，百鳥帶香飛。下有一白鷺，日斜翹石磯。',24,'御定全唐詩/json/685.json','["溪邊花滿枝，百鳥帶香飛。下有一白鷺，日斜翹石磯。"]'),
('yuding-3','長安逢故人','吳融','唐','御定全唐诗','yuding','','[]','歲暮長安客，相逢酒一杯。眼前閒事靜，心裏故山來。',48,'御定全唐詩/json/685.json','["歲暮長安客，相逢酒一杯。眼前閒事靜，心裏故山來。", "池影含新草，林芳動早梅。如何不歸去，霜鬢共風埃。"]'),
('yuding-4','雨夜','吳融','唐','御定全唐诗','yuding','','[]','旅夕那禁雨，梅天已思秋。未明孤枕倦，相吊一燈愁。',48,'御定全唐詩/json/685.json','["旅夕那禁雨，梅天已思秋。未明孤枕倦，相吊一燈愁。", "有戀慚滄海，無機奈白頭。何人得濃睡，溪上釣魚舟。"]'),
('yuding-5','旅中送遷客','吳融','唐','御定全唐诗','yuding','','[]','天南不可去，君去吊靈均。落日青山路，秋風白髮人。',48,'御定全唐詩/json/685.json','["天南不可去，君去吊靈均。落日青山路，秋風白髮人。", "言危無繼者，道在有明神。滿目盡胡越，平生何處陳。"]'),
('yuding-6','寄尚顏師','吳融','唐','御定全唐诗','yuding','','[]','僧中難得靜，靜得是吾師。到闕不求紫，歸山只愛詩。',48,'御定全唐詩/json/685.json','["僧中難得靜，靜得是吾師。到闕不求紫，歸山只愛詩。", "臨風翹雪足，向日剃霜髭。自歎眠漳久，雙林動所思。"]'),
('yuding-7','微雨','吳融','唐','御定全唐诗','yuding','','[]','天青織未遍，風急舞難成。粉重低飛蝶，黃沈不語鶯。',48,'御定全唐詩/json/685.json','["天青織未遍，風急舞難成。粉重低飛蝶，黃沈不語鶯。", "自隨春靄亂，還放夕陽明。惆悵池塘上，荷珠點點傾。"]'),
('yuding-8','送廣利大師東歸','吳融','唐','御定全唐诗','yuding','','[]','紫殿久沾恩，東歸過海門。浮榮知是夢，輕別肯銷魂。',48,'御定全唐詩/json/685.json','["紫殿久沾恩，東歸過海門。浮榮知是夢，輕別肯銷魂。", "明發先晨鳥，寒棲入暝猿。蕺山如重到，應老舊雲根。"]'),
('yuding-9','關東獻兵部劉員外','吳融','唐','御定全唐诗','yuding','','[]','昨夜星辰動，仙郎近漢關。玳筵吟雪罷，錦帳押春還。',48,'御定全唐詩/json/685.json','["昨夜星辰動，仙郎近漢關。玳筵吟雪罷，錦帳押春還。", "已到青雲上，應棲絳圃間。臨邛有詞賦，一為奏天顏。"]'),
('yuding-10','途次淮口','吳融','唐','御定全唐诗','yuding','','[]','寒流萬派碧，南渡見煙光。人向隋宮近，山盤楚塞長。',48,'御定全唐詩/json/685.json','["寒流萬派碧，南渡見煙光。人向隋宮近，山盤楚塞長。", "有村皆綠暗，無徑不紅芳。已帶傷春病，如何更異鄉。"]'),
('yuding-11','詠柳','吳融','唐','御定全唐诗','yuding','','[]','自與鶯為地，不教花作媒。細應和雨斷，輕只愛風裁。',48,'御定全唐詩/json/685.json','["自與鶯為地，不教花作媒。細應和雨斷，輕只愛風裁。", "好拂錦步障，莫遮銅雀台。灞陵千萬樹，日暮別離回。"]'),
('yuding-12','武牢關遇雨','吳融','唐','御定全唐诗','yuding','','[]','澤春關路迥，暮雨細霏霏。帶霧昏河浪，和塵重客衣。',48,'御定全唐詩/json/685.json','["澤春關路迥，暮雨細霏霏。帶霧昏河浪，和塵重客衣。", "望中迷去騎，愁裏亂斜暉。惆悵家山遠，溟蒙濕翠微。"]'),
('yuding-13','春寒','吳融','唐','御定全唐诗','yuding','','[]','固教梅忍落，體與杏藏嬌。已過冬疑剩，將來暖未饒。',48,'御定全唐詩/json/685.json','["固教梅忍落，體與杏藏嬌。已過冬疑剩，將來暖未饒。", "玉階殘雪在，羅薦暗魂銷。莫問王孫事，煙蕪正寂寥。"]'),
('yuding-14','早發潼關','吳融','唐','御定全唐诗','yuding','','[]','天邊月初落，馬上夢猶殘。關樹蒼蒼曉，玉階澹澹寒。',48,'御定全唐詩/json/685.json','["天邊月初落，馬上夢猶殘。關樹蒼蒼曉，玉階澹澹寒。", "宦遊終自苦，身世靜堪觀。爭似山中隱，和雲枕碧湍。"]'),
('yuding-15','送策上人','吳融','唐','御定全唐诗','yuding','','[]','昨來非有意，今去亦無心。闕下拋新院，江南指舊林。',48,'御定全唐詩/json/685.json','["昨來非有意，今去亦無心。闕下拋新院，江南指舊林。", "瓶添新澗綠，笠卸晚峰陰。八字如相許，終辭尺組尋。"]'),
('yuding-16','和諸學士秋夕禁直偶雪','吳融','唐','御定全唐诗','yuding','','[]','大華積秋雪，禁闈生夜寒。硯冰憂詔急，燈燼惜更殘。',48,'御定全唐詩/json/685.json','["大華積秋雪，禁闈生夜寒。硯冰憂詔急，燈燼惜更殘。", "正遂攀稽願，翻追訪戴歡。更為三日約，高興未將闌。"]'),
('yuding-17','禦溝十六韻','吳融','唐','御定全唐诗','yuding','','[]','一水終南下，何年派作溝。穿城初北注，過苑卻東流。',192,'御定全唐詩/json/685.json','["一水終南下，何年派作溝。穿城初北注，過苑卻東流。", "繞岸清波溢，連宮瑞氣浮。去應涵鳳沼，來必滲龍湫。", "激石珠爭碎，縈堤練不收。照花長樂曙，泛葉建章秋。", "影炫金莖表，光搖綺陌頭。旁沾畫眉府，斜入教簫樓。", "有雨難澄鏡，無萍易擲鉤。鼓宜堯女瑟，蕩必蔡姬舟。", "皋著通鳴鶴，津應接鬥牛。回風還瀲瀲，和月更悠悠。", "淺憶觴堪泛，深思杖可投。只懷涇合慮，不帶隴分愁。", "自有朝宗樂，曾無潰穴憂。不勞誇大漢，清渭貫神州。"]'),
('yuding-18','赴闕次留獻荊南成相公三十韻','吳融','唐','御定全唐诗','yuding','','[]','分閫兼文德，持衡有武功。荊南知獨去，海內更誰同。',360,'御定全唐詩/json/685.json','["分閫兼文德，持衡有武功。荊南知獨去，海內更誰同。", "拔地孤峰秀，當天一鶚雄。雲生五色筆，月吐六鈞弓。", "骨格淩秋聳，心源見底空。神清餐沆瀣，氣逸飲洪蒙。", "臨事成奇策，全身仗至忠。解鞍欺李廣，煮弩笑臧洪。", "往昔逢多難，來茲故統戎。卓旗雲夢澤，撲火細腰宮。", "鏟土樓臺構，連江雉堞籠。似平鋪掌上，疑湧出壺中。", "豈是勞人力，寧因役鬼工。本遺三戶在，今匝萬家通。", "畫舸橫青雀，危檣列彩虹。席飛巫峽雨，袖拂宋亭風。", "場廣盤球子，池閑引釣筒。禮賢金璧賤，煦物雪霜融。", "酒滿梁塵動，棋殘漏滴終。儉常資澹靜，貴絕恃穹崇。", "唯要臣誠顯，那求帝渥隆。甘棠名異奭，大樹姓非馮。", "自念為遷客，方諧謁上公。痛知遭止棘，頻歎委飄蓬。", "借宅誅茅綠，分囷指粟紅。只慚燕館盛，甯覺阮途窮。", "渙汗沾明主，滄浪別釣翁。去曾憂塞馬，歸欲逐邊鴻。", "積感深於海，銜恩重極嵩。行行柳門路，回首下離東。"]'),
('yuding-19','三峰府內矮柏十韻','吳融','唐','御定全唐诗','yuding','','[]','擢秀依黃閣，移根自碧岑。周圍雖合抱，直上豈盈尋。',120,'御定全唐詩/json/685.json','["擢秀依黃閣，移根自碧岑。周圍雖合抱，直上豈盈尋。", "遠砌行窺頂，當庭坐庇陰。短堪驚眾木，高已讓他林。", "日轉無長影，風回有細音。不容蘿蔦附，只耐雪霜侵。", "玉帳籠應匝，牙旗倚更禁。葉低宜拂席，枝褭易抽簪。", "綠澗支離久，朱門掩映深。何須一千丈，方有歲寒心。"]'),
('yuding-20','雪十韻','吳融','唐','御定全唐诗','yuding','','[]','灑密蔽璿穹，霏霏杳莫窮。遲於雨到地，疾甚絮隨風。',120,'御定全唐詩/json/685.json','["灑密蔽璿穹，霏霏杳莫窮。遲於雨到地，疾甚絮隨風。", "四野蒼茫際，千家晃朗中。夜迷三繞鵲，晝斷一行鴻。", "結片飛瓊樹，栽花點蕊宮。壅應邊盡北，填合海無東。", "高愛危峰積，低愁暖氣融。月交都浩渺，日射更玲瓏。", "送臘辭寒律，迎春入舊叢。自憐曾末至，聊複賦玄功。"]'),
('yuding-21','和睦州盧中丞題茅堂十韻','吳融','唐','御定全唐诗','yuding','','[]','有士當今重，忘情自古稀。獨開青嶂路，閑掩白雲扉。',120,'御定全唐詩/json/685.json','["有士當今重，忘情自古稀。獨開青嶂路，閑掩白雲扉。", "石累千層險，泉分一帶微。棟危猿競下，簷回鳥爭歸。", "煙冷茶鐺靜，波香蘭舸飛。好移鐘阜蓼，莫種首陽薇。", "樹密含輕霧，川空漾薄暉。芝泥看只捧，蕙帶且休圍。", "東郭鄰穿履，西林近衲衣。瓊瑤一百字，千古見清機。"]'),
('yuding-22','奉和禦制六韻','吳融','唐','御定全唐诗','yuding','','[]','天曉密雲開，亭亭翠葆來。芰荷籠水殿，楊柳蔽風台。',72,'御定全唐詩/json/685.json','["天曉密雲開，亭亭翠葆來。芰荷籠水殿，楊柳蔽風台。", "恩洽三時雨，歡騰萬歲雷。日華偏照禦，星彩迥分台。", "葦岸縈仙棹，蓮峰倒玉杯。獨慚歌聖德，不是侍臣才。"]'),
('yuding-23','敗簾六韻','吳融','唐','御定全唐诗','yuding','','[]','有客編來久，彌年斷不收。不堪風作候，豈複燕為讎。',72,'御定全唐詩/json/685.json','["有客編來久，彌年斷不收。不堪風作候，豈複燕為讎。", "盡見三重閣，難迷百尺樓。伴燈微掩夢，兼扇劣遮羞。", "零落亡珠綴，殷勤謝玉鉤。涼宵何必卷，月自入軒流。"]'),
('yuding-24','玉堂種竹六韻','吳融','唐','御定全唐诗','yuding','','[]','當砌植檀欒，濃陰五月寒。引風穿玉牖，搖露滴金盤。',72,'御定全唐詩/json/685.json','["當砌植檀欒，濃陰五月寒。引風穿玉牖，搖露滴金盤。", "有韻和宮漏，無香雜畹蘭。地疑雲鎖易，日近雪封難。", "靜稱圍棋會，閑宜閣筆看。他年終結實，不羨樹棲鸞。"]'),
('yuding-25','和韓致光侍郎無題三首十四韻','吳融','唐','御定全唐诗','yuding','','[]','珠佩元消暑，犀簪自辟塵。掩燈容燕宿，開鏡待雞晨。',504,'御定全唐詩/json/685.json','["珠佩元消暑，犀簪自辟塵。掩燈容燕宿，開鏡待雞晨。", "去懶都忘舊，來多未厭新。每逢憂是夢，長憶故延真。", "杏小雙圓壓，山濃兩點嚬。瘦難勝寶帶，輕欲馭飆輪。", "篦鳳金雕翼，釵魚玉鏤鱗。月明無睡夜，花落斷腸春。", "解舞何須楚，能箏可在秦。怯探同海底，稀遇極天津。", "綠柰攀宮豔，青梅弄嶺珍。管纖銀字咽，梭密錦書勻。", "厭勝還隨俗，無疑不避人。可憐三五夕，嫵媚善為鄰。", "舞轉輕輕雪，歌霏漠漠塵。漫遊多蔔夜，慵起不知晨。", "玉箸和妝裛，金蓮逐步新。鳳笙追北裏，鶴馭訪南真。", "有恨都無語，非愁亦有嚬。戲應過蚌浦，飛合入蟾輪。", "杯樣成言鳥，梳文解臥鱗。逢迎大堤晚，離別洞庭春。", "似玉曾誇趙，如雲不讓秦。錦收花上露，珠引月中津。", "木為連枝貴，禽因比翼珍。萬峰酥點薄，五色繡妝勻。", "獺髓求魚客，鮫綃托海人。寸腸誰與達，洞府四無鄰。", "綺閣臨初日，銅台拂暗塵。鷾鴯偏報曉，烏鶂慣驚晨。", "魚網裁書數，鶤弦上曲新。病多疑厄重，語切見心真。", "子母錢征笑，西南月借嚬。擣衣嫌獨杵，分袂怨雙輪。", "貝葉教丹觜，金刀寄赤鱗。捲簾吟塞雪，飛楫渡江春。", "解織宜名蕙，能歌合姓秦。眼穿回雁嶺，魂斷飲牛津。", "藥自偷來絕，香從竊去珍。茗煎雲沫聚，藥種玉苗勻。", "草密應迷客，花繁好避人。長幹足風雨，遙夜與誰鄰。"]'),
('yuding-26','倒次元韻','吳融','唐','御定全唐诗','yuding','','[]','南陌來尋伴，東城去卜鄰。生憎無賴客，死憶有情人。',168,'御定全唐詩/json/685.json','["南陌來尋伴，東城去卜鄰。生憎無賴客，死憶有情人。", "似束腰支細，如描發彩勻。黃鸝裁帽貴，紫燕刻釵珍。", "身近從淄右，家元接觀津。雨台誰屬楚，花洞不知秦。", "淚滴空床冷，妝濃滿鏡春。枕涼欹琥珀，簟潔展麒麟。", "茂苑廊千步，昭陽扇九輪。陽城迷處笑，京兆畫時嚬。", "魚子封箋短，蠅頭學字真。易判期已遠，難諱事還新。", "艇子愁沖夜，驪駒怕拂晨。如何斷岐路，免得見行塵。"]'),
('yuding-27','個人三十韻','吳融','唐','御定全唐诗','yuding','','[]','嫋嫋複盈盈，何年墜玉京。見人還道姓，羞客不稱名。',360,'御定全唐詩/json/685.json','["嫋嫋複盈盈，何年墜玉京。見人還道姓，羞客不稱名。", "故事諳金穀，新居近石城。臉橫秋水溢，眉拂遠山晴。", "粉薄塗雲母，簪寒篸水晶。催來兩槳送，怕起五絲縈。", "髻學盤桓綰，床依宛轉成。博山凝霧重，油壁隱車輕。", "額點梅花樣，心通棘刺情。搔頭邀顧遇，約指到平生。", "魚網徐徐襞，螺卮淺淺傾。芙蓉褥已展，豆蔻水休更。", "趙女憐膠膩，丁娘愛燭明。炷香龍薦腦，辟魘虎輸精。", "管咽參差韻，弦嘈倰僜聲。花殘春寂寂，月落漏丁丁。", "柳絮聯章敏，椒花屬思清。剪羅成彩字，銷蠟脫珠纓。", "邂逅當投佩，艱難莫拊楹。熨來身熱定，舐得面痕平。", "匣鏡金螭怒，簾旌繡獸獰。頸長堪鶴並，腰細任蜂爭。", "滴淚泉饒竭，論心石未貞。必雙成鳳去，豈獨化蟬鳴。", "書遠腸空斷，樓高膽易驚。數錢紅帶結，鬥草蒨裙盛。", "袂柳闌幹小，侵波略彴橫。夜愁遙寄雁，曉夢半和鶯。", "翼只思鶼比，根長羨藕並。可憐衣帶緩，休賦重行行。"]'),
('yuding-28','即席十韻','吳融','唐','御定全唐诗','yuding','','[]','住處方窺宋，平生未嫁盧。暖金輕鑄骨，寒玉細凝膚。',120,'御定全唐詩/json/685.json','["住處方窺宋，平生未嫁盧。暖金輕鑄骨，寒玉細凝膚。", "妒蝶長成伴，傷鸞耐得孤。城堪迷下蔡，台合上姑蘇。", "弄眼難降柳，含茸欲鬥蒲。生涼雲母扇，直夜博山爐。", "翡翠交妝鏡，鴛鴦入畫圖。無心同石轉，有淚約泉枯。", "猿渴應須見，鷹饑只待呼。銀河正清淺，霓節過來無。"]'),
('yuding-29','追詠棠梨花十韻','吳融','唐','御定全唐诗','yuding','','[]','蜀地從來勝，棠梨第一花。更應無軟弱，別自有妍華。',120,'御定全唐詩/json/685.json','["蜀地從來勝，棠梨第一花。更應無軟弱，別自有妍華。", "不貴綃為霧，難降綺作霞。移須歸紫府，駐合餌丹砂。", "密映彈琴宅，深藏賣酒家。夜宜紅蠟照，春稱錦筵遮。", "連廟魂棲望，飄江字繞巴。未饒酥點薄，兼妒雪飛斜。", "舊賞三年斷，新期萬里賒。長安如種得，誰定牡丹誇。"]'),
('yuding-30','綿竹山四十韻','吳融','唐','御定全唐诗','yuding','','[]','綿竹東西隅，千峰勢相屬。崚嶒壓東巴，連延羅古蜀。',480,'御定全唐詩/json/685.json','["綿竹東西隅，千峰勢相屬。崚嶒壓東巴，連延羅古蜀。", "方者露圭角，尖者鑽箭簇。引者蛾眉彎，斂者鳶肩縮。", "尾蟉青蛇盤，頸低玄兔伏。橫來突若奔，直上森如束。", "歲在作噩年，銅梁搖蠆毒。相國京兆公，九命來作牧。", "戎提虎僕毛，專奉狼頭纛。行府寄精廬，開窗對林麓。", "是時重陽後，天氣曠清肅。茲山昏曉開，一一在人目。", "霜空正泬寥，濃翠霏撲撲。披海出珊瑚，貼天堆碧玉。", "俄然陰霾作，城郭才霢霂。絕頂已凝雪，晃朗開紅旭。", "初疑昆侖下，夭矯龍銜燭。亦似蓬萊巔，金銀台疊蹙。", "紫霞或旁映，綺段鋪繁褥。晚照忽斜籠，赤城差斷續。", "又如煮吳鹽，萬萬盆初熟。又如濯楚練，千千匹未軸。", "又如水晶宮，蛟螭結川瀆。又如鐘乳洞，電雷開岩穀。", "丹青畫不成，造化供難足。合有羽衣人，飄颻曳煙躅。", "合有五色禽，叫嘯含仙曲。根雖限劍門，穴必通林屋。", "方諸滄海隔，欲去憂淪覆。群玉縹緲間，未可量往復。", "何如當此境，終朝曠遐矚。往往草檄餘，吟哦思幽獨。", "早晚掃欃槍，笳鼓迎暢轂。休飛霹靂車，罷系蝦蟆木。", "勒銘燕然山，萬代垂芬鬱。然後恣逍遙，獨往群麋鹿。", "不管安與危，不問榮與辱。但樂濠梁魚，豈怨鐘山鵠。", "紉蘭以圍腰，采芝將實腹。石床須臥平，一任閑雲觸。"]'),
('yuding-31','祝風三十二韻','吳融','唐','御定全唐诗','yuding','','[]','我有二頃田，長洲東百里。環塗為之區，積葑相連纚。',384,'御定全唐詩/json/685.json','["我有二頃田，長洲東百里。環塗為之區，積葑相連纚。", "松江流其旁，春夏多苦水。堤防苟不時，氾濫即無已。", "粵餘病眠久，而複家無峙。田峻不勝荒，農功皆廢弛。", "他稼已如雲，我田方欲蒔。四際上通波，兼之葭與葦。", "是時立秋後，煙露浩淒矣。雖然遣畢功，萎約都無幾。", "如何海上風，連日從空起。似欲驅滄溟，來沃具區裏。", "噫嘻爾風師，吳中多豪士。囷倉過九年，一粒惜如死。", "糴賤兼糶貴，凶年翻大喜。只是疲羸苦，才饑須易子。", "餘仍轗軻者，進趨年二紀。秋不安一食，春不閑一晷。", "腸回為多別，骨瘦因積毀。咳唾莫逢人，揶揄空睹鬼。", "中又值干戈，遑遑常轉徙。故隱茅山西，今來笠澤涘。", "荒者不復尋，葺者還有以。將正陶令巾，又蓋薑肱被。", "不敢務有餘，有餘必驕鄙。所期免假匄，假匄多慚恥。", "驕鄙既不生，慚恥更能弭。自可致逍遙，無妨閱經史。", "籲余將四十，滿望只如此。幹澤尚多難，學稼茲複爾。", "窮達雖系命，禍福生所履。天不饑死餘，飄風當自止。"]'),
('yuding-32','金陵懷古','吳融','唐','御定全唐诗','yuding','','[]','玉樹聲沉戰艦收，萬家冠蓋入中州。',32,'御定全唐詩/json/685.json','["玉樹聲沉戰艦收，萬家冠蓋入中州。", "只應江令偏惆悵，頭白歸來是客遊。"]'),
('yuding-33','涼思','吳融','唐','御定全唐诗','yuding','','[]','松間小檻接波平，月淡煙沉暑氣清。',32,'御定全唐詩/json/685.json','["松間小檻接波平，月淡煙沉暑氣清。", "半夜水禽棲不定，綠荷風動露珠傾。"]'),
('yuding-34','鮫綃','吳融','唐','御定全唐诗','yuding','','[]','雲供片段月供光，貧女寒機枉自忙。',32,'御定全唐詩/json/685.json','["雲供片段月供光，貧女寒機枉自忙。", "莫道不蠶能致此，海邊何事有扶桑。"]'),
('yuding-35','潮','吳融','唐','御定全唐诗','yuding','','[]','暮去朝來無定期，桑田長被此聲移。',32,'御定全唐詩/json/685.json','["暮去朝來無定期，桑田長被此聲移。", "蓬萊若探人間事，一日還應兩度知。"]'),
('yuding-36','忘憂花','吳融','唐','御定全唐诗','yuding','','[]','繁紅落盡始淒涼，直道忘憂也未忘。',32,'御定全唐詩/json/685.json','["繁紅落盡始淒涼，直道忘憂也未忘。", "數朵殷紅似春在，春愁特此系人腸。"]'),
('yuding-37','憶街西所居','吳融','唐','御定全唐诗','yuding','','[]','衡門一別夢難稀，人欲歸時不得歸。',32,'御定全唐詩/json/685.json','["衡門一別夢難稀，人欲歸時不得歸。", "長憶去年寒食夜，杏花零落雨霏霏。"]'),
('yuding-38','雲','吳融','唐','御定全唐诗','yuding','','[]','南北東西似客身，遠峰高鳥自為鄰。',32,'御定全唐詩/json/685.json','["南北東西似客身，遠峰高鳥自為鄰。", "清歌一曲猶能住，莫道無心勝得人。"]'),
('yuding-39','華清宮四首','吳融','唐','御定全唐诗','yuding','','[]','中原無鹿海無波，鳳輦鸞旗出幸多。',128,'御定全唐詩/json/685.json','["中原無鹿海無波，鳳輦鸞旗出幸多。", "今日故宮歸寂寞，太平功業在山河。", "漁陽烽火照函關，玉輦匆匆下此山。", "一曲羽衣聽不盡，至今遺恨水潺潺。", "上皇鑾輅重巡遊，雨淚無言獨倚樓。", "惆悵眼前多少事，落花明月滿宮秋。", "別殿和雲鎖翠微，太真遺像夢依依。", "玉皇掩淚頻惆悵，應歎僧繇彩筆飛。"]'),
('yuding-40','陳琳墓','吳融','唐','御定全唐诗','yuding','','[]','冀州飛檄傲英雄，卻把文辭事鄴宮。',32,'御定全唐詩/json/685.json','["冀州飛檄傲英雄，卻把文辭事鄴宮。", "縱道筆端由我得，九泉何面見袁公。"]'),
('yuding-41','湖州朝陽樓','吳融','唐','御定全唐诗','yuding','','[]','十二亭亭占曉光，隋家浪說有迷藏。',32,'御定全唐詩/json/685.json','["十二亭亭占曉光，隋家浪說有迷藏。", "仲宣題盡平生恨，別處應難看屋樑。"]'),
('yuding-42','賣花翁','吳融','唐','御定全唐诗','yuding','','[]','和煙和露一叢花，擔入宮城許史家。',32,'御定全唐詩/json/685.json','["和煙和露一叢花，擔入宮城許史家。", "惆悵東風無處說，不教閑地著春華。"]'),
('yuding-43','自諷','吳融','唐','御定全唐诗','yuding','','[]','世路升沉合自安，故人何必苦相幹。',32,'御定全唐詩/json/685.json','["世路升沉合自安，故人何必苦相幹。", "塗窮始解東歸去，莫過嚴光七裏灘。"]'),
('yuding-44','送杜鵑花','吳融','唐','御定全唐诗','yuding','','[]','春紅始謝又秋紅，息國亡來入楚宮。',32,'御定全唐詩/json/685.json','["春紅始謝又秋紅，息國亡來入楚宮。", "應是蜀冤啼不盡，更憑顏色訴西風。"]'),
('yuding-45','西京道中聞蛙','吳融','唐','御定全唐诗','yuding','','[]','雨餘林外夕煙沉，忽有蛙聲伴客吟。',32,'御定全唐詩/json/685.json','["雨餘林外夕煙沉，忽有蛙聲伴客吟。", "莫怪聞時倍惆悵，稚圭蓬蓽在山陰。"]'),
('yuding-46','情','吳融','唐','御定全唐诗','yuding','','[]','依依脈脈兩如何，細似輕絲渺似波。',32,'御定全唐詩/json/685.json','["依依脈脈兩如何，細似輕絲渺似波。", "月不長圓花易落，一生惆悵為伊多。"]'),
('yuding-47','送荊南從事之岳州','吳融','唐','御定全唐诗','yuding','','[]','秋拂湖光一鏡開，庾郎蘭棹好徘徊。',32,'御定全唐詩/json/685.json','["秋拂湖光一鏡開，庾郎蘭棹好徘徊。", "遙知月落酒醒處，五十弦從波上來。"]'),
('yuding-48','渡淮作','吳融','唐','御定全唐诗','yuding','','[]','紅杏花時辭漢苑，黃梅雨裏上淮船。',32,'御定全唐詩/json/685.json','["紅杏花時辭漢苑，黃梅雨裏上淮船。", "雨迎花送長如此，辜負東風十四年。"]'),
('yuding-49','薛舍人見征恩賜香並二十八字同寄','吳融','唐','御定全唐诗','yuding','','[]','往歲知君侍武皇，今來何用紫羅囊。',32,'御定全唐詩/json/685.json','["往歲知君侍武皇，今來何用紫羅囊。", "都緣有意重熏裛，更灑江毫上玉堂。"]'),
('yuding-50','王母廟','吳融','唐','御定全唐诗','yuding','','[]','鸞龍一夜降昆丘，遺廟千年枕碧流。',32,'御定全唐詩/json/685.json','["鸞龍一夜降昆丘，遺廟千年枕碧流。", "賺得武皇心力盡，忍看煙草茂陵秋。"]'),
('yuding-51','途中阻風','吳融','唐','御定全唐诗','yuding','','[]','洛陽寒食苦多風，掃蕩春華一半空。',32,'御定全唐詩/json/685.json','["洛陽寒食苦多風，掃蕩春華一半空。", "莫道芳蹊盡成實，野花猶有未開叢。"]'),
('yuding-52','楚事','吳融','唐','御定全唐诗','yuding','','[]','悲秋應亦抵傷春，屈宋當年並楚臣。',32,'御定全唐詩/json/685.json','["悲秋應亦抵傷春，屈宋當年並楚臣。", "何事從來好時節，只將惆悵付詞人。"]'),
('yuding-53','和僧詠牡丹','吳融','唐','御定全唐诗','yuding','','[]','萬緣銷盡本無心，何事看花恨卻深。',32,'御定全唐詩/json/685.json','["萬緣銷盡本無心，何事看花恨卻深。", "都是支郎足情調，墜香殘蕊亦成吟。"]'),
('yuding-54','豫讓','吳融','唐','御定全唐诗','yuding','','[]','韓魏同謀反復深，晉陽三板免成沉。',32,'御定全唐詩/json/685.json','["韓魏同謀反復深，晉陽三板免成沉。", "趙衰當面何須恨，不把幹將訪負心。"]'),
('yuding-55','和寄座主尚書','吳融','唐','御定全唐诗','yuding','','[]','偶逢戎旅戰爭日，豈是明時放逐臣。',32,'御定全唐詩/json/685.json','["偶逢戎旅戰爭日，豈是明時放逐臣。", "不用裁詩苦惆悵，風雷看起臥龍身。"]');
